RAII guarantees cleanup by tying resource lifetime to object scope. When an exception is thrown, stack unwinding destroys local objects in reverse order — every resource wrapped in an RAII guard is released automatically.

```cpp
#include <fstream>
#include <memory>
#include <mutex>
#include <vector>
#include <stdexcept>

std::mutex g_mutex;

void process_data(const std::string& path) {
    // 1. File: ifstream destructor closes the file
    std::ifstream file(path);
    if (!file.is_open())
        throw std::runtime_error("Cannot open " + path);

    // 2. Mutex: lock_guard destructor unlocks
    std::lock_guard<std::mutex> lock(g_mutex);

    // 3. Memory: unique_ptr destructor frees the buffer
    auto buffer = std::make_unique<char[]>(4096);

    // If this throws, cleanup happens in reverse:
    //   buffer freed -> mutex unlocked -> file closed
    file.read(buffer.get(), 4096);
    if (file.bad())
        throw std::runtime_error("Read failed");
}
```

Without RAII, you'd need nested try/catch blocks for each resource, and adding a fourth resource means restructuring all the cleanup logic. With RAII, you just declare another guard — cleanup order is always correct and exception-safe by construction.

The three exception safety guarantees:
- **Basic**: No leaks, invariants preserved (RAII gives you this for free)
- **Strong**: Operation succeeds or state is unchanged (use copy-and-swap)
- **No-throw**: Operation never throws (mark `noexcept`, use only non-throwing ops)

```cpp
#include <utility>
#include <functional>
#include <iostream>

class scope_guard {
    std::function<void()> cleanup_;
    bool active_;

public:
    template <typename F>
    explicit scope_guard(F&& f)
        : cleanup_(std::forward<F>(f)), active_(true) {}

    ~scope_guard() {
        if (active_) cleanup_();
    }

    // Movable
    scope_guard(scope_guard&& other) noexcept
        : cleanup_(std::move(other.cleanup_)), active_(other.active_) {
        other.active_ = false;
    }

    scope_guard& operator=(scope_guard&& other) noexcept {
        if (this != &other) {
            if (active_) cleanup_();
            cleanup_ = std::move(other.cleanup_);
            active_ = other.active_;
            other.active_ = false;
        }
        return *this;
    }

    // Not copyable
    scope_guard(const scope_guard&) = delete;
    scope_guard& operator=(const scope_guard&) = delete;

    void dismiss() noexcept { active_ = false; }
};

// Usage
void transactional_write(int fd, const void* data, size_t len) {
    write_header(fd);
    scope_guard rollback([&] {
        truncate_to_previous(fd);  // undo header on failure
    });

    write_body(fd, data, len);     // might throw
    rollback.dismiss();            // success — don't roll back
}
```

`dismiss()` is the key pattern: you arm the guard at construction, do the risky work, then disarm only on success. If an exception is thrown between construction and `dismiss()`, the destructor runs the rollback. This is how Go's `defer` works, except type-safe and tied to scope lifetime.

```cpp
#include <memory>
#include <stdexcept>
#include <cerrno>
#include <cstring>
#include <fcntl.h>
#include <unistd.h>

struct fd_closer {
    void operator()(int* fd) const noexcept {
        if (fd && *fd >= 0) {
            ::close(*fd);
        }
        delete fd;
    }
};

class unique_fd {
    std::unique_ptr<int, fd_closer> fd_;

public:
    unique_fd() = default;

    explicit unique_fd(const char* path, int flags, mode_t mode = 0644)
        : fd_(new int(::open(path, flags, mode))) {
        if (*fd_ < 0) {
            int err = errno;
            fd_.reset();  // clean up the int allocation
            throw std::system_error(err, std::generic_category(),
                                    std::string("open failed: ") + path);
        }
    }

    int get() const noexcept { return fd_ ? *fd_ : -1; }
    explicit operator bool() const noexcept { return fd_ && *fd_ >= 0; }

    int release() noexcept {
        int result = get();
        if (fd_) *fd_ = -1;  // prevent close on destruction
        fd_.reset();
        return result;
    }
};
```

Alternatively, a simpler approach without heap-allocating the int:

```cpp
class unique_fd {
    int fd_ = -1;

public:
    unique_fd() = default;
    explicit unique_fd(int fd) noexcept : fd_(fd) {}

    explicit unique_fd(const char* path, int flags, mode_t mode = 0644)
        : fd_(::open(path, flags, mode)) {
        if (fd_ < 0)
            throw std::system_error(errno, std::generic_category(), path);
    }

    ~unique_fd() { if (fd_ >= 0) ::close(fd_); }

    unique_fd(unique_fd&& o) noexcept : fd_(std::exchange(o.fd_, -1)) {}
    unique_fd& operator=(unique_fd&& o) noexcept {
        if (this != &o) {
            if (fd_ >= 0) ::close(fd_);
            fd_ = std::exchange(o.fd_, -1);
        }
        return *this;
    }

    unique_fd(const unique_fd&) = delete;
    unique_fd& operator=(const unique_fd&) = delete;

    int get() const noexcept { return fd_; }
    explicit operator bool() const noexcept { return fd_ >= 0; }
    int release() noexcept { return std::exchange(fd_, -1); }
};
```

The second version is preferred — it follows Rule of Five directly, avoids heap allocation, and `std::exchange` is the canonical pattern for move operations on scalar resources.

The Rule of Five states: if you define any of destructor, copy constructor, copy assignment, move constructor, or move assignment, you should define all five — because defining one means you're managing a resource manually.

```cpp
#include <algorithm>
#include <cstddef>
#include <utility>

class DynamicArray {
    int* data_;
    std::size_t size_;

public:
    explicit DynamicArray(std::size_t n)
        : data_(new int[n]{}), size_(n) {}

    // 1. Destructor
    ~DynamicArray() { delete[] data_; }

    // 2. Copy constructor (deep copy)
    DynamicArray(const DynamicArray& other)
        : data_(new int[other.size_]), size_(other.size_) {
        std::copy(other.data_, other.data_ + size_, data_);
    }

    // 3. Copy assignment (copy-and-swap idiom)
    DynamicArray& operator=(DynamicArray other) {  // by value = copy
        swap(*this, other);
        return *this;
    }

    // 4. Move constructor
    DynamicArray(DynamicArray&& other) noexcept
        : data_(std::exchange(other.data_, nullptr)),
          size_(std::exchange(other.size_, 0)) {}

    // 5. Move assignment (handled by copy-assign taking by value)
    // When passed an rvalue, the by-value parameter is move-constructed,
    // then swapped. No separate move-assignment needed.

    friend void swap(DynamicArray& a, DynamicArray& b) noexcept {
        using std::swap;
        swap(a.data_, b.data_);
        swap(a.size_, b.size_);
    }

    int& operator[](std::size_t i) { return data_[i]; }
    std::size_t size() const { return size_; }
};
```

**Rule of Zero**: If your class only holds members that manage themselves (unique_ptr, shared_ptr, string, vector), you don't need ANY of the five — the compiler generates correct versions automatically:

```cpp
class Document {
    std::string title_;
    std::vector<std::string> pages_;
    std::unique_ptr<Metadata> meta_;
    // No destructor, no copy/move — compiler handles everything.
    // unique_ptr makes this move-only automatically.
};
```

**Use Rule of Five** when you directly manage a raw resource (raw pointer, file descriptor, handle). **Use Rule of Zero** for everything else — which should be the vast majority of classes.

Circular references with `shared_ptr` prevent the reference count from ever reaching zero, so destructors never run and memory leaks.

**The problem:**
```cpp
#include <memory>
#include <iostream>

struct Node {
    std::string name;
    std::shared_ptr<Node> partner;  // strong reference

    Node(std::string n) : name(std::move(n)) {
        std::cout << name << " created\n";
    }
    ~Node() {
        std::cout << name << " destroyed\n";
    }
};

int main() {
    auto a = std::make_shared<Node>("Alice");
    auto b = std::make_shared<Node>("Bob");
    a->partner = b;   // Alice -> Bob (refcount Bob = 2)
    b->partner = a;   // Bob -> Alice (refcount Alice = 2)
    // When a and b go out of scope:
    //   Alice refcount: 2 -> 1 (Bob still holds a shared_ptr to Alice)
    //   Bob refcount:   2 -> 1 (Alice still holds a shared_ptr to Bob)
    //   Neither reaches 0. LEAK.
}
// Output: "Alice created", "Bob created" — no destructors run!
```

**The fix — use `weak_ptr` for the back-reference:**
```cpp
struct Node {
    std::string name;
    std::weak_ptr<Node> partner;  // weak reference — doesn't affect refcount

    Node(std::string n) : name(std::move(n)) {
        std::cout << name << " created\n";
    }
    ~Node() {
        std::cout << name << " destroyed\n";
    }

    void greet() {
        if (auto p = partner.lock()) {  // promote to shared_ptr (may fail)
            std::cout << name << "'s partner is " << p->name << "\n";
        } else {
            std::cout << name << " has no partner (expired)\n";
        }
    }
};

int main() {
    auto a = std::make_shared<Node>("Alice");
    auto b = std::make_shared<Node>("Bob");
    a->partner = b;
    b->partner = a;
    a->greet();  // "Alice's partner is Bob"
}
// Output: Alice created, Bob created, Alice's partner is Bob,
//         Bob destroyed, Alice destroyed  ← both cleaned up!
```

`weak_ptr` observes without owning. Call `.lock()` to get a temporary `shared_ptr` — if the object was already destroyed, `lock()` returns nullptr. The rule: the object that **owns** uses `shared_ptr`, the object that **observes** uses `weak_ptr`.

```cpp
#include <memory>
#include <mutex>
#include <vector>
#include <functional>
#include <stdexcept>
#include <condition_variable>

template <typename T>
class ResourcePool {
    std::vector<std::unique_ptr<T>> available_;
    std::mutex mutex_;
    std::condition_variable cv_;

public:
    using Handle = std::unique_ptr<T, std::function<void(T*)>>;

    template <typename... Args>
    void add(Args&&... args) {
        std::lock_guard<std::mutex> lock(mutex_);
        available_.push_back(std::make_unique<T>(std::forward<Args>(args)...));
        cv_.notify_one();
    }

    Handle acquire() {
        std::unique_lock<std::mutex> lock(mutex_);
        cv_.wait(lock, [this] { return !available_.empty(); });

        auto resource = std::move(available_.back());
        available_.pop_back();

        T* raw = resource.release();
        // Custom deleter returns the resource to the pool
        return Handle(raw, [this](T* ptr) {
            std::lock_guard<std::mutex> lock(mutex_);
            available_.push_back(std::unique_ptr<T>(ptr));
            cv_.notify_one();
        });
    }

    std::size_t available() const {
        std::lock_guard<std::mutex> lock(mutex_);
        return available_.size();
    }
};

// Usage: database connection pool
struct DbConnection {
    int id;
    DbConnection(int i) : id(i) {}
    void query(const std::string& sql) { /* ... */ }
};

int main() {
    ResourcePool<DbConnection> pool;
    pool.add(1);
    pool.add(2);
    pool.add(3);

    {
        auto conn = pool.acquire();  // takes one from pool
        conn->query("SELECT 1");
        // conn goes out of scope here -> returned to pool automatically
    }
    // pool.available() == 3 again
}
```

The key pattern is the custom deleter on `unique_ptr`: instead of calling `delete`, it returns the resource to the pool. This makes the handle a zero-cost RAII guard — the caller can never forget to return the resource, even if an exception is thrown.

`enable_shared_from_this` lets an object that's already managed by `shared_ptr` safely create additional `shared_ptr` instances to itself. Without it, constructing a new `shared_ptr` from `this` creates a second control block, leading to double-free.

**The problem:**
```cpp
struct Bad {
    std::shared_ptr<Bad> get_self() {
        return std::shared_ptr<Bad>(this);  // BUG: new control block!
    }
};

auto p = std::make_shared<Bad>();
auto q = p->get_self();  // Two control blocks, two refcounts
// Both reach 0 independently -> double delete -> undefined behavior
```

**The fix:**
```cpp
#include <memory>
#include <iostream>
#include <vector>

class AsyncTask : public std::enable_shared_from_this<AsyncTask> {
    std::string name_;

public:
    explicit AsyncTask(std::string name) : name_(std::move(name)) {}
    ~AsyncTask() { std::cout << name_ << " destroyed\n"; }

    void start(std::vector<std::function<void()>>& queue) {
        // Capture shared_ptr to self — keeps object alive until callback runs
        auto self = shared_from_this();
        queue.push_back([self]() {
            std::cout << "Running " << self->name_ << "\n";
        });
    }
};

int main() {
    std::vector<std::function<void()>> work_queue;

    {
        auto task = std::make_shared<AsyncTask>("download");
        task->start(work_queue);
        // task goes out of scope, but the lambda in work_queue
        // holds a shared_ptr, so the object survives
    }

    for (auto& fn : work_queue) fn();  // "Running download"
    work_queue.clear();                // "download destroyed"
}
```

Common use cases:
- **Async callbacks**: Object must outlive the scope that launched the async work
- **Observer patterns**: Object registers itself with an event system
- **Boost.Asio**: Every async handler captures `shared_from_this()` to extend object lifetime

Rule: never call `shared_from_this()` unless the object is already managed by a `shared_ptr`. Calling it on a stack object or raw-new object is undefined behavior.

The strong exception guarantee means: if an operation throws, the program state is exactly as it was before the call — no partial modifications, no leaks.

Copy-and-swap achieves this by doing all the throwing work on a temporary copy, then committing via a non-throwing swap:

```cpp
#include <algorithm>
#include <cstddef>
#include <utility>

class Matrix {
    double* data_;
    std::size_t rows_, cols_;

public:
    Matrix(std::size_t r, std::size_t c)
        : data_(new double[r * c]{}), rows_(r), cols_(c) {}

    ~Matrix() { delete[] data_; }

    // Copy constructor — does the potentially-throwing allocation
    Matrix(const Matrix& other)
        : data_(new double[other.rows_ * other.cols_]),
          rows_(other.rows_), cols_(other.cols_) {
        std::copy(other.data_, other.data_ + rows_ * cols_, data_);
    }

    // Move constructor — noexcept, just steals guts
    Matrix(Matrix&& other) noexcept
        : data_(std::exchange(other.data_, nullptr)),
          rows_(std::exchange(other.rows_, 0)),
          cols_(std::exchange(other.cols_, 0)) {}

    // Unified assignment via copy-and-swap
    Matrix& operator=(Matrix other) noexcept {  // by VALUE
        swap(*this, other);
        return *this;
    }

    friend void swap(Matrix& a, Matrix& b) noexcept {
        using std::swap;
        swap(a.data_, b.data_);
        swap(a.rows_, b.rows_);
        swap(a.cols_, b.cols_);
    }

    double& operator()(std::size_t r, std::size_t c) {
        return data_[r * cols_ + c];
    }
};
```

Why this is strongly exception-safe:

1. `operator=` takes its parameter **by value**, so the copy happens in the caller's argument evaluation
2. If `new double[]` throws during the copy, `other` was never constructed — `*this` is untouched
3. If the copy succeeds, `swap` is `noexcept` — it cannot fail
4. The old data is destroyed when `other` (now holding our old guts) goes out of scope

The beauty: one function handles both copy-assignment (lvalue argument triggers copy constructor) and move-assignment (rvalue argument triggers move constructor). Zero code duplication.

`std::move` does NOT move anything. It's a cast — it converts an lvalue to an rvalue reference (`T&&`), which makes it *eligible* for moving. The actual move happens in the move constructor or move assignment operator that receives the rvalue.

```cpp
#include <utility>
#include <string>
#include <iostream>

std::string a = "hello";
std::string b = std::move(a);  // std::move casts a to string&&
                                // string's move constructor steals a's buffer
// a is now in a valid-but-unspecified state (likely empty)
```

**What `std::move` actually is:**
```cpp
// Simplified — it's just a static_cast
template <typename T>
constexpr std::remove_reference_t<T>&& move(T&& t) noexcept {
    return static_cast<std::remove_reference_t<T>&&>(t);
}
```

**Common mistakes:**

1. **Using an object after `std::move`:**
```cpp
std::vector<int> v = {1, 2, 3};
process(std::move(v));
v.push_back(4);  // Legal but unreliable — v is in unspecified state
// Only safe operations on moved-from objects: destruction, assignment
```

2. **Moving a `const` object (silently copies):**
```cpp
const std::string s = "data";
std::string t = std::move(s);  // Calls COPY constructor, not move!
// std::move(s) yields const string&& — no match for string(string&&)
// Falls back to string(const string&) — the copy constructor
```

3. **Moving a return value (prevents RVO):**
```cpp
std::string make() {
    std::string result = "hello";
    return std::move(result);  // BAD — prevents Named RVO
    return result;              // GOOD — compiler elides the copy entirely
}
```

4. **Forgetting `noexcept` on move constructor:**
```cpp
class Widget {
public:
    Widget(Widget&&);            // NOT noexcept — vector won't use it!
    Widget(Widget&&) noexcept;   // noexcept — vector uses move on realloc
};
// std::vector falls back to copying on reallocation if move isn't noexcept
```

5. **Moving member-by-member in move constructor without `std::move`:**
```cpp
Foo(Foo&& other)
    : name_(other.name_)  // COPIES! other.name_ is an lvalue
    : name_(std::move(other.name_))  // Correct — explicitly cast each member
```

**`std::move`**: Unconditionally casts to rvalue reference. Use when you know you want to transfer ownership.

**`std::forward`**: Conditionally casts — preserves the original value category (lvalue stays lvalue, rvalue stays rvalue). Use in templates with forwarding references (`T&&`).

```cpp
#include <utility>
#include <string>
#include <iostream>

void process(const std::string& s) { std::cout << "lvalue\n"; }
void process(std::string&& s)      { std::cout << "rvalue\n"; }

// Perfect forwarding function
template <typename T>
void wrapper(T&& arg) {
    // arg is always an lvalue inside this function (it has a name)
    process(std::forward<T>(arg));  // preserves original category
}

int main() {
    std::string s = "hello";
    wrapper(s);              // T = string&,  forward yields string& -> "lvalue"
    wrapper(std::move(s));   // T = string,   forward yields string&& -> "rvalue"
    wrapper("literal");      // T = string,   forward yields string&& -> "rvalue"
}
```

**How `std::forward` works:**
```cpp
// When T = string& (lvalue passed):
//   forward<string&>(arg) -> static_cast<string& &&>(arg) -> string&
// When T = string (rvalue passed):
//   forward<string>(arg) -> static_cast<string&&>(arg) -> string&&
```

Reference collapsing rules make this work:
- `T& &`  -> `T&`
- `T& &&` -> `T&`
- `T&& &` -> `T&`
- `T&& &&` -> `T&&`

**When to use which:**
- `std::move`: You own the value and want to transfer it. "I'm done with this, take it."
- `std::forward`: You're a middleman passing someone else's argument. "I don't know if this was an lvalue or rvalue, pass it through unchanged."

**Critical mistake — using `std::move` where `std::forward` is needed:**
```cpp
template <typename T>
void bad_wrapper(T&& arg) {
    process(std::move(arg));  // Always rvalue — breaks lvalue callers!
    // Caller passes an lvalue expecting it to be untouched,
    // but we moved from it
}
```

```cpp
#include <iostream>
#include <vector>
#include <string>
#include <utility>

class Tracked {
    std::string data_;

public:
    explicit Tracked(std::string s) : data_(std::move(s)) {
        std::cout << "  construct: " << data_ << "\n";
    }

    Tracked(const Tracked& other) : data_(other.data_) {
        std::cout << "  COPY: " << data_ << "\n";
    }

    Tracked(Tracked&& other) noexcept : data_(std::move(other.data_)) {
        std::cout << "  move: " << data_ << "\n";
    }

    Tracked& operator=(const Tracked&) = default;
    Tracked& operator=(Tracked&&) noexcept = default;
};

int main() {
    std::cout << "--- push_back with copy ---\n";
    std::vector<Tracked> v;
    Tracked t("alpha");
    v.push_back(t);             // copy into vector

    std::cout << "\n--- push_back with move ---\n";
    v.push_back(std::move(t));  // move into vector (reallocation may copy existing)

    std::cout << "\n--- emplace_back (construct in-place) ---\n";
    v.emplace_back("beta");     // constructs directly in vector storage

    std::cout << "\n--- reserve then push ---\n";
    std::vector<Tracked> v2;
    v2.reserve(4);              // pre-allocate — no reallocation
    v2.emplace_back("one");
    v2.emplace_back("two");
    v2.emplace_back("three");   // no copies or moves of existing elements
}
```

Output:
```
--- push_back with copy ---
  construct: alpha
  COPY: alpha

--- push_back with move ---
  move: alpha          <- the new element is moved in
  COPY: alpha          <- reallocation copies existing element (capacity grew)

--- emplace_back (construct in-place) ---
  construct: beta
  move: alpha          <- reallocation moves existing (noexcept move!)
  move: alpha

--- reserve then push ---
  construct: one
  construct: two
  construct: three     <- zero copies, zero moves of existing elements
```

Key takeaways:
1. `push_back(std::move(x))` avoids copying the new element
2. `emplace_back(args...)` constructs directly — avoids even the move of the new element
3. **noexcept on move constructor is critical**: `vector` only uses move during reallocation if the move constructor is `noexcept`. Without it, vector falls back to copying for strong exception safety.
4. `reserve()` eliminates reallocation entirely — best performance when you know the size

RVO is a compiler optimization that constructs the return value directly in the caller's memory, eliminating the copy or move entirely. Since C++17, RVO for unnamed temporaries is **mandatory** (not optional).

**Guaranteed RVO (C++17) — unnamed temporaries:**
```cpp
std::string make_greeting() {
    return std::string("hello");  // Constructed directly in caller's variable
}

std::string s = make_greeting();  // Zero copies, zero moves — guaranteed
```

**Named RVO (NRVO) — named local variables:**
```cpp
std::string make_greeting(const std::string& name) {
    std::string result = "Hello, " + name + "!";
    return result;  // NRVO: compiler MAY construct result directly in caller
}
// NRVO is permitted but NOT guaranteed — compiler dependent
```

**When NRVO fails (compiler can't elide):**

```cpp
// 1. Multiple return paths with different named variables
std::string pick(bool flag) {
    std::string a = "alpha";
    std::string b = "beta";
    if (flag) return a;  // Which variable gets caller's slot?
    return b;            // Can't pre-assign both. NRVO likely fails.
}

// 2. Returning a parameter
std::string identity(std::string s) {
    return s;  // Parameters have fixed slots — can't be elided into caller
}

// 3. Returning std::move(local) — KILLS NRVO!
std::string bad() {
    std::string result = "data";
    return std::move(result);  // Forces move, prevents NRVO
    //     return result;      // Better — allows NRVO, falls back to move
}
```

**The rule:** Always `return local_variable;` without `std::move`. The compiler will:
1. Try NRVO (zero cost)
2. If NRVO fails, automatically treat it as `std::move(local_variable)` (implicit move)
3. `std::move` on return **prevents** step 1 and gains nothing over step 2

**Verification:**
```cpp
struct Heavy {
    Heavy() { std::cout << "construct\n"; }
    Heavy(const Heavy&) { std::cout << "COPY\n"; }
    Heavy(Heavy&&) noexcept { std::cout << "move\n"; }
};

Heavy make() {
    Heavy h;
    return h;  // With NRVO: just "construct". Without: "construct" + "move"
}

int main() {
    Heavy x = make();  // Typically prints only "construct" — NRVO applied
}
```

`std::vector` (and other containers) require `noexcept` on move constructors to maintain the strong exception safety guarantee during reallocation.

The problem: when a `vector` grows, it allocates new memory and transfers elements from old to new. If it uses move and a move throws halfway through, some elements are in the new buffer, some are in the old — both in moved-from states. The data is **irrecoverably corrupted**.

```cpp
#include <vector>
#include <iostream>

struct Risky {
    int id;
    Risky(int i) : id(i) {}
    Risky(Risky&& other) {  // NOT noexcept!
        id = other.id;
        if (id == 3) throw std::runtime_error("oops");
    }
    Risky(const Risky& other) : id(other.id) {
        std::cout << "copy " << id << "\n";
    }
};

struct Safe {
    int id;
    Safe(int i) : id(i) {}
    Safe(Safe&& other) noexcept : id(other.id) {}  // noexcept!
    Safe(const Safe& other) : id(other.id) {
        std::cout << "copy " << id << "\n";
    }
};

int main() {
    // Risky: vector falls back to COPYING during reallocation
    std::vector<Risky> v1;
    v1.reserve(2);
    v1.emplace_back(1);
    v1.emplace_back(2);
    v1.emplace_back(3);  // reallocation — copies all elements!
    // Output: copy 1, copy 2

    // Safe: vector uses MOVE during reallocation
    std::vector<Safe> v2;
    v2.reserve(2);
    v2.emplace_back(1);
    v2.emplace_back(2);
    v2.emplace_back(3);  // reallocation — moves all elements (silent)
    // Output: (nothing — moves are noexcept, no fallback to copy)
}
```

How the container decides:
```cpp
// vector internally uses:
std::move_if_noexcept(element)
// If move is noexcept: returns T&& (move)
// If move is NOT noexcept: returns const T& (copy)
```

This applies to: `vector::push_back`, `vector::resize`, `vector::reserve` growth, `deque`, `vector::insert`, and any operation that might relocate elements.

**Rule: always mark move constructors and move assignment operators `noexcept`.** If your move truly can't throw (it shouldn't — you're just swapping pointers and scalars), declare it. The performance difference between copy and move on reallocation can be enormous for large objects.

After `std::move`, the object is in a **valid but unspecified** state. The C++ standard guarantees only that:
1. The object can be **destroyed** (destructor is safe)
2. The object can be **assigned to** (given a new value)
3. Operations with **no preconditions** are safe (like `vector::empty()`, `string::size()`)

```cpp
#include <string>
#include <vector>
#include <iostream>
#include <cassert>

int main() {
    // String: moved-from string is valid, typically empty
    std::string a = "hello world";
    std::string b = std::move(a);
    // a is valid but unspecified — don't read its content
    std::cout << a.size() << "\n";  // Safe — size() has no preconditions
    a = "reused";                    // Safe — assignment resets state
    std::cout << a << "\n";          // "reused" — fully usable again

    // Vector: moved-from vector is valid, typically empty
    std::vector<int> v1 = {1, 2, 3};
    std::vector<int> v2 = std::move(v1);
    // v1 is valid but unspecified
    std::cout << v1.empty() << "\n";  // Safe, but value not guaranteed
    v1.clear();                        // Safe — puts it in known state
    v1.push_back(42);                  // Safe after clear

    // unique_ptr: moved-from unique_ptr is guaranteed null
    auto p1 = std::make_unique<int>(10);
    auto p2 = std::move(p1);
    assert(p1 == nullptr);  // unique_ptr is special — guaranteed null
}
```

**What is NOT safe after move:**
```cpp
std::string s = "data";
std::string t = std::move(s);

// UNSAFE — dereferencing unspecified content:
char c = s[0];         // UB if s is empty after move
std::cout << s << "\n"; // Safe to call, but output is unspecified

// UNSAFE — assuming invariants:
if (s == "data") { }   // Unreliable — s is unspecified
```

**Best practice: treat moved-from objects as "empty":**
```cpp
void transfer(std::vector<Widget>& src, std::vector<Widget>& dst) {
    dst = std::move(src);
    src.clear();  // Explicit reset — now in a known state
    // Better than relying on implementation-defined moved-from state
}
```

Design your own classes to leave moved-from objects in a safe, destructible state:
```cpp
class Connection {
    int fd_ = -1;
public:
    Connection(Connection&& other) noexcept
        : fd_(std::exchange(other.fd_, -1)) {}  // -1 = safe sentinel
    ~Connection() { if (fd_ >= 0) ::close(fd_); }
};
```

```cpp
#include <memory>
#include <utility>
#include <string>
#include <iostream>

// Generic factory: perfect-forwards all args to T's constructor
template <typename T, typename... Args>
std::unique_ptr<T> make(Args&&... args) {
    return std::make_unique<T>(std::forward<Args>(args)...);
}

// With explicit allocator support
template <typename T, typename Alloc, typename... Args>
auto allocate_make(const Alloc& alloc, Args&&... args) {
    return std::allocate_shared<T>(alloc, std::forward<Args>(args)...);
}

struct Widget {
    std::string name;
    int value;

    Widget(std::string n, int v) : name(std::move(n)), value(v) {
        std::cout << "Widget(" << name << ", " << value << ")\n";
    }
};

struct Logger {
    std::string prefix;
    explicit Logger(const std::string& p) : prefix(p) {}
    explicit Logger(std::string&& p) : prefix(std::move(p)) {}
};

int main() {
    // Forwards ("sensor", 42) to Widget(string, int)
    auto w = make<Widget>("sensor", 42);

    // lvalue forwarded as const string&
    std::string prefix = "[INFO]";
    auto log1 = make<Logger>(prefix);          // calls Logger(const string&)

    // rvalue forwarded as string&&
    auto log2 = make<Logger>(std::move(prefix)); // calls Logger(string&&)

    // Works with any number of args
    auto vec = make<std::vector<int>>(10, -1);  // vector(10, -1)
}
```

How it works:
- `Args&&...` is a parameter pack of forwarding references
- Each `arg` could be lvalue or rvalue
- `std::forward<Args>(args)...` expands to forward each argument individually with its original value category preserved
- Template argument deduction + reference collapsing ensures lvalues stay lvalues and rvalues stay rvalues

This is exactly how `std::make_unique`, `std::make_shared`, and `emplace_back` work internally. The pattern is:
```cpp
template <typename... Args>
void emplace(Args&&... args) {
    new (storage) T(std::forward<Args>(args)...);
}
```

Const correctness is a compile-time contract: it tells the compiler (and humans) what can and can't be modified.

**1. Const member functions — promise not to modify `*this`:**
```cpp
class Sensor {
    double value_;
    mutable int read_count_ = 0;  // see below

public:
    // const member function — can be called on const objects
    double read() const {
        ++read_count_;  // OK because mutable
        // value_ = 0;  // ERROR: can't modify non-mutable members
        return value_;
    }

    void calibrate(double offset) {  // non-const — modifies state
        value_ += offset;
    }
};

void print_value(const Sensor& s) {
    s.read();       // OK — read() is const
    // s.calibrate(1.0);  // ERROR — calibrate() is non-const
}
```

**2. Const references — observe without modifying:**
```cpp
void process(const std::string& s) {
    std::cout << s.size();  // OK — size() is const
    // s.clear();           // ERROR — clear() is non-const
}
// Accepts both lvalues and rvalues, avoids copy
```

**3. Const pointer vs pointer-to-const:**
```cpp
int x = 10, y = 20;

const int* p1 = &x;    // pointer to const int: *p1 = 5 is ERROR, p1 = &y is OK
int* const p2 = &x;    // const pointer to int: *p2 = 5 is OK, p2 = &y is ERROR
const int* const p3 = &x;  // both const: nothing can change

// Read right-to-left: "p1 is a pointer to const int"
// "p2 is a const pointer to int"
```

**4. constexpr vs const:**
```cpp
const int a = 42;           // Compile-time or runtime, value can't change
constexpr int b = 42;       // MUST be known at compile time
constexpr int square(int n) { return n * n; }  // Evaluated at compile time if possible

static_assert(square(5) == 25);  // Compile-time computation
```

**5. mutable — opt out of const for implementation details:**
```cpp
class Cache {
    mutable std::unordered_map<int, int> cache_;  // logical constness
    mutable std::mutex mutex_;                     // thread-safe const

public:
    int compute(int key) const {  // const interface
        std::lock_guard<std::mutex> lock(mutex_);  // OK: mutable
        if (auto it = cache_.find(key); it != cache_.end())
            return it->second;
        int result = expensive_computation(key);
        cache_[key] = result;  // OK: mutable
        return result;
    }
};
```

`mutable` means "this field doesn't affect the observable state" — use it for caches, mutexes, counters, and lazy-init members.

```cpp
#include <cstddef>
#include <stdexcept>
#include <vector>

class Grid {
    std::vector<double> data_;
    std::size_t cols_;

    // Private helper with bounds check
    void check(std::size_t r, std::size_t c) const {
        if (r * cols_ + c >= data_.size())
            throw std::out_of_range("Grid index out of range");
    }

public:
    Grid(std::size_t rows, std::size_t cols)
        : data_(rows * cols), cols_(cols) {}

    // Non-const version: returns mutable reference
    double& operator()(std::size_t r, std::size_t c) {
        check(r, c);
        return data_[r * cols_ + c];
    }

    // Const version: returns const reference
    const double& operator()(std::size_t r, std::size_t c) const {
        check(r, c);
        return data_[r * cols_ + c];
    }
};
```

The two overloads are identical except for const qualification. For complex logic, use the **const_cast trick** to avoid duplication:

```cpp
class Matrix {
    std::vector<double> data_;
    std::size_t cols_;

public:
    // Implement logic in the const version
    const double& at(std::size_t r, std::size_t c) const {
        if (r * cols_ + c >= data_.size())
            throw std::out_of_range("out of range");
        return data_[r * cols_ + c];
    }

    // Non-const delegates to const, then casts away const
    double& at(std::size_t r, std::size_t c) {
        return const_cast<double&>(
            static_cast<const Matrix&>(*this).at(r, c)
        );
    }
};
```

This is safe because:
1. The non-const version is only callable on a non-const object
2. A non-const object's data is mutable, so casting away const on its data is well-defined
3. The const version does the real work — the non-const version just adapts the return type

**C++23 deducing-this eliminates the need entirely:**
```cpp
class Matrix {
    std::vector<double> data_;
    std::size_t cols_;

public:
    // Single function handles both const and non-const
    template <typename Self>
    auto&& at(this Self&& self, std::size_t r, std::size_t c) {
        if (r * self.cols_ + c >= self.data_.size())
            throw std::out_of_range("out of range");
        return std::forward<Self>(self).data_[r * self.cols_ + c];
    }
};
```

Moving from a const object silently falls back to **copying** — no error, no warning. This is because `std::move(const T)` yields `const T&&`, which doesn't match the move constructor's `T&&` parameter.

```cpp
#include <iostream>
#include <string>
#include <utility>

struct Widget {
    std::string data;

    Widget(const Widget& other) : data(other.data) {
        std::cout << "COPY constructor\n";
    }
    Widget(Widget&& other) noexcept : data(std::move(other.data)) {
        std::cout << "move constructor\n";
    }
    Widget(std::string s) : data(std::move(s)) {}
};

int main() {
    const Widget a("hello");
    Widget b = std::move(a);  // Prints "COPY constructor"!
}
```

**Overload resolution breakdown:**

`std::move(a)` where `a` is `const Widget` yields `const Widget&&`.

Candidate constructors:
```
Widget(const Widget&)     — binds const Widget&& to const Widget&?  YES (const lvalue ref binds to anything)
Widget(Widget&&) noexcept — binds const Widget&& to Widget&&?       NO  (can't drop const)
```

Only the copy constructor matches, so it's selected. The move constructor requires a **non-const** rvalue reference.

**The full binding rules:**
```
Argument type     | T&& match | const T&& match | const T& match
------------------+-----------+-----------------+---------------
T (lvalue)        | NO        | NO              | YES
const T (lvalue)  | NO        | NO              | YES
T (rvalue)        | YES (best)| YES             | YES
const T (rvalue)  | NO        | YES (best)      | YES
```

**Real-world consequence:**
```cpp
// This function accidentally copies instead of moving
void store(const std::vector<int> data) {  // const parameter!
    buffer_ = std::move(data);  // Silent copy — const vector&& -> copy
}

// Fix: take by value (non-const)
void store(std::vector<int> data) {
    buffer_ = std::move(data);  // Now actually moves
}
```

**Why `const T&&` exists at all:**
It's rarely used directly. The main place it appears is in deleted overloads to explicitly prevent moving from const:
```cpp
template <typename T>
void ref(const T&&) = delete;  // Prevent binding temporaries to const ref
```

```cpp
#include <functional>
#include <iostream>
#include <string>
#include <type_traits>
#include <utility>
#include <vector>

// 1. const auto& — deduces type, adds const reference
void example_const_auto() {
    std::vector<std::string> v = {"hello", "world"};

    const auto& ref = v[0];   // const string&
    // ref[0] = 'H';          // ERROR: const

    auto& mut_ref = v[0];     // string&
    mut_ref[0] = 'H';         // OK

    const auto copy = v[0];   // const string (copy, but immutable)
}

// 2. auto with const member functions
class Config {
    std::map<std::string, std::string> data_;

public:
    // auto deduction in return type
    const auto& get(const std::string& key) const {
        return data_.at(key);  // returns const string&
    }

    auto& get(const std::string& key) {
        return data_.at(key);  // returns string&
    }
};

// 3. decltype(auto) preserves exact type including const and references
template <typename Container>
decltype(auto) front(Container& c) {
    return c.front();  // If c is const, returns const T&
                       // If c is non-const, returns T&
}

void example_decltype_auto() {
    std::vector<int> v = {1, 2, 3};
    const std::vector<int> cv = {4, 5, 6};

    decltype(auto) a = front(v);   // int& — can modify
    decltype(auto) b = front(cv);  // const int& — read-only
    a = 10;   // OK
    // b = 20; // ERROR: const

    // Compare with auto (drops references):
    auto c = front(v);  // int — copy, not reference!
}

// 4. std::as_const — cast to const without typing the full type
void example_as_const() {
    std::vector<int> v = {1, 2, 3};

    // Force const overload selection
    for (const auto& elem : std::as_const(v)) {
        // Uses vector::begin() const -> const_iterator
    }

    // Useful with lambdas that should only observe
    auto print = [](const auto& container) {
        for (auto& x : container) std::cout << x << " ";
    };
    print(std::as_const(v));  // Explicit intent: read-only access
}

// 5. std::cref — const reference wrapper for templates
void example_cref() {
    std::string name = "hello";

    // std::ref/cref wrap references for use in templates
    // that would otherwise copy
    auto fn = std::bind([](const std::string& s) {
        std::cout << s << "\n";
    }, std::cref(name));  // holds const reference, not copy

    name = "world";
    fn();  // prints "world" — cref sees the update
}

// 6. const propagation in templates
template <typename T>
void inspect(T&& arg) {
    using RawType = std::remove_cvref_t<T>;
    constexpr bool is_const = std::is_const_v<std::remove_reference_t<T>>;
    std::cout << "const: " << is_const << "\n";
}

void example_template_propagation() {
    int x = 42;
    const int cx = 42;
    inspect(x);       // T = int&, const: false
    inspect(cx);      // T = const int&, const: true
    inspect(42);      // T = int, const: false
}
```

Key rules:
- `auto` drops top-level const and references (like template deduction)
- `auto&` preserves const from the source
- `const auto&` always adds const
- `decltype(auto)` preserves **everything** — const, references, exact type
- `std::as_const(x)` returns `const X&` — use to force const overloads
- `std::cref` wraps a const reference for passing through type-erasing APIs

Copy-on-write (CoW) shares data between copies until one of them needs to modify it. At that point, the mutating copy detaches — makes its own private copy — and modifies that.

```cpp
#include <memory>
#include <cstring>
#include <iostream>
#include <algorithm>

class CowString {
    struct Buffer {
        char* data;
        std::size_t size;
        std::size_t capacity;

        Buffer(const char* s, std::size_t len)
            : data(new char[len + 1]), size(len), capacity(len + 1) {
            std::memcpy(data, s, len);
            data[len] = '\0';
        }
        ~Buffer() { delete[] data; }

        Buffer(const Buffer&) = delete;
        Buffer& operator=(const Buffer&) = delete;
    };

    std::shared_ptr<Buffer> buf_;

    // Detach: if shared, make a private copy before mutating
    void detach() {
        if (buf_.use_count() > 1) {
            buf_ = std::make_shared<Buffer>(buf_->data, buf_->size);
        }
    }

public:
    CowString(const char* s = "")
        : buf_(std::make_shared<Buffer>(s, std::strlen(s))) {}

    // Copy is O(1) — just increments refcount
    CowString(const CowString&) = default;
    CowString& operator=(const CowString&) = default;

    // Read access — no copy needed
    const char* c_str() const { return buf_->data; }
    std::size_t size() const { return buf_->size; }
    char operator[](std::size_t i) const { return buf_->data[i]; }

    // Write access — detach first
    char& operator[](std::size_t i) {
        detach();  // COW: copy buffer if shared
        return buf_->data[i];
    }

    void append(const char* s) {
        detach();
        std::size_t len = std::strlen(s);
        if (buf_->size + len + 1 > buf_->capacity) {
            std::size_t new_cap = (buf_->size + len + 1) * 2;
            char* new_data = new char[new_cap];
            std::memcpy(new_data, buf_->data, buf_->size);
            delete[] buf_->data;
            buf_->data = new_data;
            buf_->capacity = new_cap;
        }
        std::memcpy(buf_->data + buf_->size, s, len);
        buf_->size += len;
        buf_->data[buf_->size] = '\0';
    }

    long use_count() const { return buf_.use_count(); }
};

int main() {
    CowString a("hello");
    CowString b = a;  // O(1) — shared buffer, refcount = 2

    std::cout << "a: " << a.c_str() << ", refs: " << a.use_count() << "\n";
    std::cout << "b: " << b.c_str() << ", refs: " << b.use_count() << "\n";
    // a: hello, refs: 2
    // b: hello, refs: 2

    b[0] = 'H';  // Triggers detach — b gets its own buffer

    std::cout << "a: " << a.c_str() << ", refs: " << a.use_count() << "\n";
    std::cout << "b: " << b.c_str() << ", refs: " << b.use_count() << "\n";
    // a: hello, refs: 1
    // b: Hello, refs: 1
}
```

Note: `std::string` used CoW in older implementations (GCC's libstdc++ before C++11), but C++11 effectively banned it because `operator[]` on non-const strings must not invalidate references, which conflicts with CoW's detach semantics. Modern `std::string` uses Small String Optimization (SSO) instead.

```cpp
#include <memory>
#include <stdexcept>
#include <iostream>

// Simulated C API
extern "C" {
    struct db_handle;
    db_handle* db_open(const char* path);      // Returns nullptr on failure
    int        db_execute(db_handle*, const char* sql);  // Returns 0 on success
    void       db_close(db_handle*);           // Always safe to call, even on nullptr
}

// RAII wrapper — Method 1: custom deleter with unique_ptr
class Database {
    struct Deleter {
        void operator()(db_handle* h) const noexcept {
            if (h) db_close(h);
        }
    };

    std::unique_ptr<db_handle, Deleter> handle_;

public:
    explicit Database(const char* path)
        : handle_(db_open(path)) {
        if (!handle_)
            throw std::runtime_error(std::string("Failed to open: ") + path);
    }

    // Rule of Zero — unique_ptr handles everything
    // Move-only by default (unique_ptr is move-only)

    void execute(const char* sql) {
        if (db_execute(handle_.get(), sql) != 0)
            throw std::runtime_error("Execute failed");
    }

    db_handle* get() const noexcept { return handle_.get(); }
    explicit operator bool() const noexcept { return handle_ != nullptr; }
};

// Method 2: manual RAII (when you need more control)
class DatabaseManual {
    db_handle* handle_;

public:
    explicit DatabaseManual(const char* path)
        : handle_(db_open(path)) {
        if (!handle_)
            throw std::runtime_error("open failed");
    }

    ~DatabaseManual() {
        if (handle_) db_close(handle_);
    }

    // Move support
    DatabaseManual(DatabaseManual&& other) noexcept
        : handle_(std::exchange(other.handle_, nullptr)) {}

    DatabaseManual& operator=(DatabaseManual&& other) noexcept {
        if (this != &other) {
            if (handle_) db_close(handle_);
            handle_ = std::exchange(other.handle_, nullptr);
        }
        return *this;
    }

    // No copy
    DatabaseManual(const DatabaseManual&) = delete;
    DatabaseManual& operator=(const DatabaseManual&) = delete;

    void execute(const char* sql) {
        if (db_execute(handle_, sql) != 0)
            throw std::runtime_error("failed");
    }
};

// Usage
void process() {
    Database db("/tmp/test.db");  // Opens handle
    db.execute("CREATE TABLE t (id INT)");
    db.execute("INSERT INTO t VALUES (1)");
    // db_close called automatically when db goes out of scope
    // Even if execute() throws — stack unwinding destroys db
}
```

Method 1 (unique_ptr + custom deleter) is preferred:
- Rule of Zero — no destructor/copy/move needed
- Move semantics work automatically
- Impossible to forget cleanup
- Works with any C API that has a create/destroy pattern

**Three exception safety levels:**

1. **No-throw guarantee**: Operation never throws. Destructors, `swap`, move of primitives.
2. **Strong guarantee**: If it throws, state is unchanged — as if the operation never happened.
3. **Basic guarantee**: If it throws, no leaks, invariants preserved, but state may have changed.

```cpp
#include <memory>
#include <algorithm>
#include <stdexcept>
#include <utility>

template <typename T>
class StableVector {
    std::unique_ptr<T[]> data_;
    std::size_t size_ = 0;
    std::size_t cap_ = 0;

public:
    // STRONG exception safety: succeeds completely or state unchanged
    void push_back(const T& value) {
        if (size_ == cap_) {
            // Phase 1: Allocate new buffer (may throw — no state change yet)
            std::size_t new_cap = cap_ == 0 ? 4 : cap_ * 2;
            auto new_data = std::make_unique<T[]>(new_cap);

            // Phase 2: Copy existing elements (may throw)
            // If this throws, new_data is destroyed, old state untouched
            for (std::size_t i = 0; i < size_; ++i)
                new_data[i] = data_[i];

            // Phase 3: Copy new element (may throw)
            // If this throws, new_data destroyed, old state untouched
            new_data[size_] = value;

            // Phase 4: Commit — noexcept operations only from here
            data_ = std::move(new_data);   // noexcept (unique_ptr move)
            cap_ = new_cap;                // noexcept (scalar assign)
            ++size_;                       // noexcept
        } else {
            // No reallocation needed
            // This is only BASIC guarantee — if copy throws,
            // size_ hasn't incremented, but data_[size_] may be modified
            data_[size_] = value;
            ++size_;
        }
    }

    // STRONG guarantee using copy-and-swap at container level
    void insert(std::size_t pos, const T& value) {
        if (pos > size_) throw std::out_of_range("insert pos out of range");

        // Make a complete copy with the new element
        StableVector tmp;
        tmp.reserve(size_ + 1);
        for (std::size_t i = 0; i < pos; ++i)
            tmp.push_back(data_[i]);    // may throw
        tmp.push_back(value);           // may throw
        for (std::size_t i = pos; i < size_; ++i)
            tmp.push_back(data_[i]);    // may throw

        // If we get here, tmp has the complete new state
        // Commit via noexcept swap
        swap(*this, tmp);  // noexcept
    }

    void reserve(std::size_t new_cap) {
        if (new_cap <= cap_) return;
        auto new_data = std::make_unique<T[]>(new_cap);
        for (std::size_t i = 0; i < size_; ++i)
            new_data[i] = std::move(data_[i]);
        data_ = std::move(new_data);
        cap_ = new_cap;
    }

    friend void swap(StableVector& a, StableVector& b) noexcept {
        using std::swap;
        swap(a.data_, b.data_);
        swap(a.size_, b.size_);
        swap(a.cap_, b.cap_);
    }

    std::size_t size() const { return size_; }
    T& operator[](std::size_t i) { return data_[i]; }
};
```

The pattern for strong exception safety:
1. Do all the potentially-throwing work on **temporaries**
2. Once everything succeeds, **commit** using only `noexcept` operations (swap, move of primitives, pointer assignment)
3. If anything throws during step 1, temporaries are destroyed, original state untouched

`std::exchange` atomically reads a value and replaces it with a new one, returning the old value. It's the perfect tool for move operations on scalar resources.

```cpp
#include <utility>
#include <iostream>

// Without std::exchange — verbose and error-prone
class Socket_v1 {
    int fd_;
public:
    Socket_v1(int fd) : fd_(fd) {}
    ~Socket_v1() { if (fd_ >= 0) ::close(fd_); }

    Socket_v1(Socket_v1&& other) noexcept : fd_(other.fd_) {
        other.fd_ = -1;  // Must remember to reset source!
    }

    Socket_v1& operator=(Socket_v1&& other) noexcept {
        if (this != &other) {
            if (fd_ >= 0) ::close(fd_);
            fd_ = other.fd_;
            other.fd_ = -1;  // Must remember again!
        }
        return *this;
    }
};

// With std::exchange — clean, one-line, can't forget the reset
class Socket {
    int fd_;
public:
    Socket(int fd) : fd_(fd) {}
    ~Socket() { if (fd_ >= 0) ::close(fd_); }

    Socket(Socket&& other) noexcept
        : fd_(std::exchange(other.fd_, -1)) {}  // Read + reset in one step

    Socket& operator=(Socket&& other) noexcept {
        if (this != &other) {
            if (fd_ >= 0) ::close(fd_);
            fd_ = std::exchange(other.fd_, -1);  // Same pattern
        }
        return *this;
    }

    Socket(const Socket&) = delete;
    Socket& operator=(const Socket&) = delete;
};
```

**Multiple members:**
```cpp
class Connection {
    int fd_;
    bool connected_;
    std::string host_;

public:
    Connection(Connection&& other) noexcept
        : fd_(std::exchange(other.fd_, -1)),
          connected_(std::exchange(other.connected_, false)),
          host_(std::move(other.host_)) {}  // std::move for non-trivial types
};
```

**Other uses beyond move operations:**
```cpp
// Resetting a flag and checking old value
bool was_dirty = std::exchange(dirty_, false);
if (was_dirty) flush();

// Linked list node detach
Node* next = std::exchange(current->next, nullptr);

// Rotating values
int prev = std::exchange(current, next_value);

// Implementing post-increment
Iterator operator++(int) {
    return Iterator(std::exchange(pos_, pos_ + 1));
}
```

Rule of thumb:
- `std::exchange` for scalars and trivial types in move operations
- `std::move` for non-trivial types (string, vector, unique_ptr)
- Both together for classes with mixed member types

```cpp
#include <mutex>
#include <stdexcept>
#include <iostream>

// Minimal lock_guard implementation
template <typename Mutex>
class LockGuard {
    Mutex& mutex_;

public:
    // Lock on construction
    explicit LockGuard(Mutex& m) : mutex_(m) {
        mutex_.lock();
    }

    // Adopt already-locked mutex
    LockGuard(Mutex& m, std::adopt_lock_t) noexcept : mutex_(m) {
        // mutex is already locked — just take ownership
    }

    // Unlock on destruction
    ~LockGuard() {
        mutex_.unlock();
    }

    // Non-copyable, non-movable (mutex can't be "transferred")
    LockGuard(const LockGuard&) = delete;
    LockGuard& operator=(const LockGuard&) = delete;
    LockGuard(LockGuard&&) = delete;
    LockGuard& operator=(LockGuard&&) = delete;
};

// Demonstration: exception safety
std::mutex g_mutex;
int shared_counter = 0;

void safe_increment() {
    LockGuard<std::mutex> lock(g_mutex);
    // mutex is now locked

    ++shared_counter;

    if (shared_counter > 100)
        throw std::runtime_error("limit exceeded");
    // If this throws, ~LockGuard() still runs -> mutex unlocked
    // Without RAII: mutex stays locked forever -> deadlock

    // Normal exit: ~LockGuard() runs -> mutex unlocked
}

// Without RAII — what goes wrong:
void unsafe_increment() {
    g_mutex.lock();
    ++shared_counter;
    if (shared_counter > 100) {
        // BUG: forgot to unlock before throwing!
        // g_mutex.unlock();  // Easy to forget one path
        throw std::runtime_error("limit exceeded");
    }
    g_mutex.unlock();  // Only reached on normal path
}
```

**Why `lock_guard` is non-movable:** A mutex has a fixed address. If you moved the guard, the destructor of both the moved-from and moved-to objects would try to unlock — either double-unlock or use-after-move. Since mutex locks are scoped by definition, there's no reason to move them.

**When to use `unique_lock` instead:**
```cpp
void flexible_locking() {
    std::unique_lock<std::mutex> lock(g_mutex);

    // Can unlock early
    lock.unlock();
    do_unprotected_work();
    lock.lock();

    // Can transfer ownership
    auto lock2 = std::move(lock);

    // Can use with condition_variable
    // cv.wait(lock, predicate);
}
```

`lock_guard` = simple, zero-overhead, perfect for straightforward scoped locking.
`unique_lock` = flexible, movable, needed for condition variables and deferred locking.
C++17 `scoped_lock` = like `lock_guard` but locks multiple mutexes without deadlock.

```cpp
#include <memory>
#include <iostream>
#include <cstdlib>

// 1. unique_ptr with arrays
void array_example() {
    // Correct: use T[] specialization
    auto arr = std::make_unique<int[]>(100);  // 100 ints, value-initialized to 0
    arr[0] = 42;
    arr[99] = 7;
    // arr.get() returns int*
    // Destructor calls delete[], not delete

    // Can't use make_unique for non-default init, use direct construction:
    std::unique_ptr<double[]> data(new double[256]);
    // Note: not value-initialized — contains garbage

    // Both go out of scope -> delete[] called automatically
}

// 2. unique_ptr with custom deleter for C malloc/free
void malloc_example() {
    auto deleter = [](void* p) { std::free(p); };
    std::unique_ptr<int[], decltype(deleter)> buf(
        static_cast<int*>(std::malloc(1024 * sizeof(int))),
        deleter
    );

    buf[0] = 1;
    buf[1023] = 2;
    // free() called on destruction, not delete[]
}

// 3. unique_ptr with aligned allocation (C++17)
void aligned_example() {
    struct alignas(64) CacheLine {
        char data[64];
    };

    // make_unique respects alignas
    auto line = std::make_unique<CacheLine>();
    std::cout << "Aligned to: " << alignof(CacheLine)
              << ", addr: " << line.get() << "\n";
}

// 4. unique_ptr with pool/arena allocator
class Arena {
    char* pool_;
    std::size_t offset_ = 0;
    std::size_t capacity_;

public:
    explicit Arena(std::size_t cap)
        : pool_(new char[cap]), capacity_(cap) {}
    ~Arena() { delete[] pool_; }

    void* allocate(std::size_t size) {
        if (offset_ + size > capacity_)
            throw std::bad_alloc();
        void* ptr = pool_ + offset_;
        offset_ += size;
        return ptr;
    }

    // Arena frees everything at once — individual free is a no-op
    static void deallocate(void*) {}  // intentional no-op
};

void arena_example() {
    Arena arena(4096);

    // Custom deleter that calls destructor but not free
    auto deleter = [](std::string* p) {
        p->~basic_string();  // Destroy object
        // Don't free memory — arena owns it
    };

    // Construct in arena memory
    void* mem = arena.allocate(sizeof(std::string));
    auto* str = new (mem) std::string("arena-allocated");

    std::unique_ptr<std::string, decltype(deleter)> ptr(str, deleter);
    std::cout << *ptr << "\n";
    // Destructor runs on scope exit (calls ~string), memory stays in arena
}

int main() {
    array_example();
    malloc_example();
    aligned_example();
    arena_example();
}
```

Key points:
- `unique_ptr<T[]>` uses `delete[]` — always use this for arrays, never `unique_ptr<T>`
- `make_unique<T[]>(n)` value-initializes (zeros for primitives)
- Custom deleters make `unique_ptr` work with any allocation scheme: malloc/free, mmap/munmap, arena allocators, COM Release(), etc.
- The deleter is part of the type — `unique_ptr<T, Deleter>` — so it's zero-overhead (no virtual call)

Self-move-assignment happens more often than you'd expect — particularly in generic code like `std::swap`, `std::sort`, or when elements are moved within a container.

```cpp
#include <utility>
#include <iostream>
#include <cstddef>

class Buffer {
    int* data_;
    std::size_t size_;

public:
    explicit Buffer(std::size_t n) : data_(new int[n]{}), size_(n) {}
    ~Buffer() { delete[] data_; }

    Buffer(Buffer&& other) noexcept
        : data_(std::exchange(other.data_, nullptr)),
          size_(std::exchange(other.size_, 0)) {}

    // UNSAFE move assignment — breaks on self-assignment
    Buffer& bad_move_assign(Buffer&& other) noexcept {
        delete[] data_;             // Deletes our data
        data_ = other.data_;        // If this == &other, data_ is now dangling!
        size_ = other.size_;
        other.data_ = nullptr;      // Sets our own data_ to null
        other.size_ = 0;
        return *this;
    }

    // SAFE move assignment — Method 1: self-check
    Buffer& operator=(Buffer&& other) noexcept {
        if (this != &other) {
            delete[] data_;
            data_ = std::exchange(other.data_, nullptr);
            size_ = std::exchange(other.size_, 0);
        }
        return *this;
    }

    // SAFE move assignment — Method 2: swap (no branch needed)
    // Buffer& operator=(Buffer&& other) noexcept {
    //     std::swap(data_, other.data_);
    //     std::swap(size_, other.size_);
    //     return *this;  // other's destructor cleans up old data
    // }

    Buffer(const Buffer&) = delete;
    Buffer& operator=(const Buffer&) = delete;

    int* data() const { return data_; }
    std::size_t size() const { return size_; }
};

int main() {
    Buffer b(10);
    b.data()[0] = 42;

    // Self-move — happens in generic algorithms
    b = std::move(b);  // Must not crash or corrupt

    std::cout << "size: " << b.size() << "\n";  // Should still work
}
```

Why self-assignment happens:
```cpp
// In sort/partition: swap(a[i], a[j]) where i might equal j
template <typename T>
void swap(T& a, T& b) {
    T tmp = std::move(a);   // If &a == &b, a is now empty
    a = std::move(b);       // Self-move-assign of empty object
    b = std::move(tmp);
}

// With move-and-erase idioms:
vec[i] = std::move(vec[i]);  // Possible if index logic has off-by-one
```

Two safe approaches:
1. **Self-check** (`if (this != &other)`) — simple, explicit, zero cost on the hot path since branch predictor will learn it's almost never taken
2. **Swap-based** — always correct, slightly slower (destructs old data lazily via other's destructor), but no branch

```cpp
#include <memory>
#include <functional>
#include <iostream>

// Type-erased RAII handle — wraps any resource with any cleanup
class AnyResource {
    std::shared_ptr<void> handle_;  // shared_ptr<void> remembers the deleter

public:
    AnyResource() = default;

    template <typename T, typename Deleter>
    AnyResource(T* resource, Deleter deleter)
        : handle_(resource, std::move(deleter)) {}

    // Factory for common patterns
    template <typename T>
    static AnyResource from_unique(std::unique_ptr<T> ptr) {
        return AnyResource(ptr.release(), std::default_delete<T>{});
    }

    void* get() const { return handle_.get(); }
    explicit operator bool() const { return handle_ != nullptr; }
    long use_count() const { return handle_.use_count(); }

    // Type-safe accessor
    template <typename T>
    T* as() const { return static_cast<T*>(handle_.get()); }
};

// Simulated C APIs
struct CFile { const char* name; };
CFile* cfile_open(const char* n) { auto* f = new CFile{n}; std::cout << "open " << n << "\n"; return f; }
void cfile_close(CFile* f) { std::cout << "close " << f->name << "\n"; delete f; }

struct CSocket { int fd; };
CSocket* csock_connect(int fd) { auto* s = new CSocket{fd}; std::cout << "connect " << fd << "\n"; return s; }
void csock_disconnect(CSocket* s) { std::cout << "disconnect " << s->fd << "\n"; delete s; }

// Usage: uniform RAII for heterogeneous resources
int main() {
    std::vector<AnyResource> resources;

    // Wrap a C file
    resources.emplace_back(cfile_open("data.txt"), cfile_close);

    // Wrap a C socket
    resources.emplace_back(csock_connect(42), csock_disconnect);

    // Wrap a C++ object
    resources.push_back(AnyResource::from_unique(
        std::make_unique<std::string>("managed string")));

    // Use type-safe accessor
    auto* file = resources[0].as<CFile>();
    std::cout << "file: " << file->name << "\n";

    // All cleaned up in reverse order when vector is destroyed
    resources.clear();
    // Output: close data.txt, disconnect 42, (string destroyed)
}
```

The trick is `shared_ptr<void>`: even though the pointer type is `void*`, the deleter captured at construction time remembers the original type and calls the correct cleanup function. This is because `shared_ptr` stores the deleter in the control block (type-erased via virtual call), not in the pointer type.

This pattern is useful for:
- Resource managers that hold heterogeneous resources
- Plugin systems where resource types are unknown at compile time
- Cleanup stacks (execute in reverse order on scope exit)

**unique_ptr — zero overhead:**
```
Size:           sizeof(T*) = 8 bytes (no custom deleter) or sizeof(T*) + sizeof(Deleter)
Allocation:     make_unique does one allocation (the object)
Dereference:    Same as raw pointer (direct access)
Copy:           Impossible (compile error)
Move:           Pointer swap — O(1), no atomic ops
Destruction:    Calls delete (or custom deleter) — no overhead
Thread safety:  None needed (single owner)
```

**shared_ptr — reference counting overhead:**
```
Size:           2 pointers = 16 bytes (object ptr + control block ptr)
Allocation:     make_shared does one allocation (object + control block together)
                shared_ptr(new T) does TWO allocations (object + control block separately)
Dereference:    Same as raw pointer (direct access to object)
Copy:           Atomic increment of reference count — ~10-30ns per copy
Move:           Pointer swap — O(1), no atomic ops (like unique_ptr)
Destruction:    Atomic decrement + conditional delete — ~10-30ns
Thread safety:  Ref count is atomic. Object access is NOT thread-safe.
```

**Performance comparison:**
```cpp
#include <memory>
#include <vector>
#include <chrono>

void benchmark() {
    const int N = 1'000'000;

    // unique_ptr: ~2ms (just allocate + deallocate)
    {
        std::vector<std::unique_ptr<int>> v;
        v.reserve(N);
        for (int i = 0; i < N; ++i)
            v.push_back(std::make_unique<int>(i));
    }

    // shared_ptr: ~8ms (allocate + control block + atomic refcount)
    {
        std::vector<std::shared_ptr<int>> v;
        v.reserve(N);
        for (int i = 0; i < N; ++i)
            v.push_back(std::make_shared<int>(i));
    }

    // shared_ptr copies: ~30ms (N atomic increments + decrements)
    {
        auto src = std::make_shared<int>(42);
        std::vector<std::shared_ptr<int>> v;
        v.reserve(N);
        for (int i = 0; i < N; ++i)
            v.push_back(src);  // atomic increment each time
    }
}
```

**Decision guide:**

Use `unique_ptr` (default choice):
- Single ownership, clear lifetime
- Containers of polymorphic objects (`vector<unique_ptr<Base>>`)
- Factory functions returning new objects
- RAII wrappers for C handles
- Performance-critical code

Use `shared_ptr`:
- Genuinely shared ownership (multiple owners, last one cleans up)
- Observer pattern with `weak_ptr` for cycle-breaking
- Async callbacks that must extend object lifetime (`shared_from_this`)
- Caches (shared_ptr in cache + weak_ptr in clients)

Use `weak_ptr`:
- Breaking cycles in shared_ptr graphs
- Cache entries that auto-expire
- Observing without preventing destruction

**Rule**: Start with `unique_ptr`. Switch to `shared_ptr` only when you genuinely need shared ownership, not just because "multiple things use it" (that's what references and raw pointers are for).

```cpp
// Method 1: Explicit delete (preferred — clear intent)
class Singleton {
public:
    static Singleton& instance() {
        static Singleton s;
        return s;
    }

    Singleton(const Singleton&) = delete;
    Singleton& operator=(const Singleton&) = delete;
    Singleton(Singleton&&) = delete;
    Singleton& operator=(Singleton&&) = delete;

    void do_work() { /* ... */ }

private:
    Singleton() = default;
    ~Singleton() = default;
};

// Method 2: Base class mixin (reusable)
class NonCopyable {
protected:
    NonCopyable() = default;
    ~NonCopyable() = default;

public:
    NonCopyable(const NonCopyable&) = delete;
    NonCopyable& operator=(const NonCopyable&) = delete;
    NonCopyable(NonCopyable&&) = delete;
    NonCopyable& operator=(NonCopyable&&) = delete;
};

class DatabasePool : private NonCopyable {
    // Automatically non-copyable and non-movable
};

// Method 3: Just delete copy — move is auto-disabled
class Logger {
public:
    Logger(const Logger&) = delete;
    Logger& operator=(const Logger&) = delete;
    // Move operations are implicitly NOT declared because
    // we declared copy operations. But being explicit is better.
};
```

**When to make a class non-copyable AND non-movable:**

1. **Singletons and global managers** — only one instance should exist
```cpp
class ThreadPool : NonCopyable {
    std::vector<std::thread> workers_;
    // Moving a thread pool would invalidate thread references
};
```

2. **Mutex and synchronization primitives** — identity matters
```cpp
class SpinLock : NonCopyable {
    std::atomic_flag flag_ = ATOMIC_FLAG_INIT;
    // Threads are waiting on THIS specific memory address
    // Moving it would leave waiters spinning on old address
};
```

3. **Objects with registered callbacks or observers**
```cpp
class EventEmitter : NonCopyable {
    std::vector<std::function<void()>> listeners_;
    // Listeners hold pointers/references to this object
    // Moving it would invalidate all those references
};
```

4. **RAII guards that shouldn't transfer** (like `lock_guard`)
```cpp
template <typename Mutex>
class LockGuard : NonCopyable {
    Mutex& mutex_;  // Reference to specific mutex
    // Moving would require tracking whether we still own the lock
};
```

**When to be non-copyable but movable:** File handles, sockets, unique_ptr — single ownership that can be transferred.

**When to be fully copyable and movable:** Value types — strings, vectors, data structures.

```cpp
#include <utility>
#include <cstddef>
#include <type_traits>

template <typename T, typename Deleter = std::default_delete<T>>
class UniquePtr {
    T* ptr_;
    [[no_unique_address]] Deleter deleter_;  // Zero-size for stateless deleters

public:
    // Constructors
    constexpr UniquePtr() noexcept : ptr_(nullptr), deleter_() {}
    constexpr UniquePtr(std::nullptr_t) noexcept : ptr_(nullptr), deleter_() {}
    explicit UniquePtr(T* p) noexcept : ptr_(p), deleter_() {}
    UniquePtr(T* p, const Deleter& d) noexcept : ptr_(p), deleter_(d) {}
    UniquePtr(T* p, Deleter&& d) noexcept : ptr_(p), deleter_(std::move(d)) {}

    // Destructor
    ~UniquePtr() {
        if (ptr_) deleter_(ptr_);
    }

    // Move constructor
    UniquePtr(UniquePtr&& other) noexcept
        : ptr_(std::exchange(other.ptr_, nullptr)),
          deleter_(std::move(other.deleter_)) {}

    // Move assignment
    UniquePtr& operator=(UniquePtr&& other) noexcept {
        if (this != &other) {
            reset();
            ptr_ = std::exchange(other.ptr_, nullptr);
            deleter_ = std::move(other.deleter_);
        }
        return *this;
    }

    UniquePtr& operator=(std::nullptr_t) noexcept {
        reset();
        return *this;
    }

    // No copy
    UniquePtr(const UniquePtr&) = delete;
    UniquePtr& operator=(const UniquePtr&) = delete;

    // Observers
    T* get() const noexcept { return ptr_; }
    T& operator*() const noexcept { return *ptr_; }
    T* operator->() const noexcept { return ptr_; }
    explicit operator bool() const noexcept { return ptr_ != nullptr; }
    Deleter& get_deleter() noexcept { return deleter_; }
    const Deleter& get_deleter() const noexcept { return deleter_; }

    // Modifiers
    T* release() noexcept {
        return std::exchange(ptr_, nullptr);
    }

    void reset(T* p = nullptr) noexcept {
        T* old = std::exchange(ptr_, p);
        if (old) deleter_(old);
    }

    void swap(UniquePtr& other) noexcept {
        using std::swap;
        swap(ptr_, other.ptr_);
        swap(deleter_, other.deleter_);
    }
};

// make_unique equivalent
template <typename T, typename... Args>
UniquePtr<T> makeUnique(Args&&... args) {
    return UniquePtr<T>(new T(std::forward<Args>(args)...));
}

// Comparison operators
template <typename T, typename D>
bool operator==(const UniquePtr<T, D>& p, std::nullptr_t) { return !p; }

template <typename T, typename D>
bool operator==(std::nullptr_t, const UniquePtr<T, D>& p) { return !p; }

// Usage
#include <iostream>

struct Widget {
    int value;
    Widget(int v) : value(v) { std::cout << "Widget(" << v << ")\n"; }
    ~Widget() { std::cout << "~Widget(" << value << ")\n"; }
};

struct LogDeleter {
    void operator()(Widget* w) const {
        std::cout << "Custom delete: " << w->value << "\n";
        delete w;
    }
};

int main() {
    auto w1 = makeUnique<Widget>(42);
    std::cout << w1->value << "\n";

    UniquePtr<Widget, LogDeleter> w2(new Widget(99));
    auto w3 = std::move(w2);  // Transfer ownership
    // w2 is now null, w3 owns the widget
}
```

Key design points:
- `[[no_unique_address]]` on the deleter enables Empty Base Optimization — `sizeof(UniquePtr<T>)` equals `sizeof(T*)` when Deleter is stateless (like `default_delete`)
- `std::exchange` in move operations guarantees source is null after move
- `reset()` handles self-assignment (if reset with same pointer, the old pointer is saved before overwriting)
- The deleter is a template parameter, not a `std::function` — zero overhead, fully inlined

```cpp
#include <memory>
#include <stdexcept>
#include <iostream>
#include <string>

// Simulated database API
class Connection {
public:
    void begin()    { std::cout << "BEGIN TRANSACTION\n"; }
    void commit()   { std::cout << "COMMIT\n"; }
    void rollback() { std::cout << "ROLLBACK\n"; }
    void execute(const std::string& sql) {
        std::cout << "  EXEC: " << sql << "\n";
        if (sql.find("FAIL") != std::string::npos)
            throw std::runtime_error("Query failed: " + sql);
    }
};

// RAII transaction guard
class Transaction {
    Connection& conn_;
    bool committed_ = false;

public:
    explicit Transaction(Connection& conn) : conn_(conn) {
        conn_.begin();
    }

    ~Transaction() {
        if (!committed_) {
            try {
                conn_.rollback();  // Safe: rollback on scope exit
            } catch (...) {
                // Swallow exceptions in destructor — never throw from dtor
            }
        }
    }

    void commit() {
        conn_.commit();
        committed_ = true;
    }

    // Non-copyable, non-movable
    Transaction(const Transaction&) = delete;
    Transaction& operator=(const Transaction&) = delete;
};

// Usage: impossible to forget rollback
void transfer(Connection& db, int from, int to, double amount) {
    Transaction txn(db);  // BEGIN

    db.execute("UPDATE accounts SET balance = balance - " +
               std::to_string(amount) + " WHERE id = " + std::to_string(from));

    db.execute("UPDATE accounts SET balance = balance + " +
               std::to_string(amount) + " WHERE id = " + std::to_string(to));

    // Only commit if BOTH updates succeeded
    txn.commit();  // COMMIT

    // If any execute() throws, ~Transaction runs -> ROLLBACK
    // If commit() throws, committed_ is still false -> ROLLBACK
}

// Example with nested operations
void batch_process(Connection& db) {
    Transaction txn(db);

    db.execute("INSERT INTO log VALUES ('batch start')");

    for (int i = 0; i < 5; ++i) {
        db.execute("INSERT INTO results VALUES (" + std::to_string(i) + ")");
        // If iteration 3 throws, ALL 3 prior inserts are rolled back
    }

    db.execute("INSERT INTO log VALUES ('batch complete')");
    txn.commit();  // All-or-nothing
}

int main() {
    Connection db;

    std::cout << "=== Successful transfer ===\n";
    transfer(db, 1, 2, 100.0);

    std::cout << "\n=== Failed transfer ===\n";
    try {
        Transaction txn(db);
        db.execute("UPDATE accounts SET balance = balance - 50 WHERE id = 1");
        db.execute("FAIL: connection lost");  // Throws!
        txn.commit();                         // Never reached
    } catch (const std::exception& e) {
        std::cout << "Caught: " << e.what() << "\n";
        // Transaction already rolled back by ~Transaction
    }
}
```

Output:
```
=== Successful transfer ===
BEGIN TRANSACTION
  EXEC: UPDATE accounts SET balance = balance - 100 WHERE id = 1
  EXEC: UPDATE accounts SET balance = balance + 100 WHERE id = 2
COMMIT

=== Failed transfer ===
BEGIN TRANSACTION
  EXEC: UPDATE accounts SET balance = balance - 50 WHERE id = 1
  EXEC: FAIL: connection lost
ROLLBACK
Caught: Query failed: FAIL: connection lost
```

The pattern: constructor starts the transaction, destructor rolls back unless `commit()` was called. This makes it impossible to leak a transaction — even through exceptions, early returns, or forgotten cleanup.

When multiple RAII objects are in scope and an exception is thrown, they are destroyed in **reverse order of construction**. This is the C++ guarantee that makes multi-resource acquisition safe.

```cpp
#include <iostream>
#include <memory>
#include <fstream>
#include <mutex>
#include <stdexcept>

std::mutex g_mutex;

// Helper to visualize destruction order
struct Tracer {
    std::string name;
    Tracer(std::string n) : name(std::move(n)) {
        std::cout << "  acquired: " << name << "\n";
    }
    ~Tracer() {
        std::cout << "  released: " << name << "\n";
    }
};

void process(const std::string& path) {
    // Resource 1: Open file
    std::ifstream file(path);
    if (!file) throw std::runtime_error("cannot open " + path);
    Tracer t1("file: " + path);

    // Resource 2: Lock mutex
    std::lock_guard<std::mutex> lock(g_mutex);
    Tracer t2("mutex");

    // Resource 3: Allocate buffer
    auto buffer = std::make_unique<char[]>(1024);
    Tracer t3("buffer");

    // Resource 4: Network connection (FAILS HERE)
    // Simulating failure:
    throw std::runtime_error("network timeout");

    // Resources 5, 6, ... would go here but are never reached
}

int main() {
    try {
        process("test.txt");
    } catch (const std::exception& e) {
        std::cout << "\nCaught: " << e.what() << "\n";
    }
}
```

Output (assuming test.txt exists):
```
  acquired: file: test.txt
  acquired: mutex
  acquired: buffer
  released: buffer    <- reverse order!
  released: mutex
  released: file: test.txt

Caught: network timeout
```

**Without RAII — the disaster:**
```cpp
void process_unsafe(const std::string& path) {
    FILE* file = fopen(path.c_str(), "r");
    if (!file) throw std::runtime_error("open failed");

    g_mutex.lock();

    char* buffer = new char[1024];

    // If this throws:
    //   buffer leaked (no delete[])
    //   mutex locked forever (no unlock)
    //   file leaked (no fclose)
    connect_to_server();  // throws!

    delete[] buffer;
    g_mutex.unlock();
    fclose(file);
}
```

Every new resource in the unsafe version adds another cleanup path to get wrong. With RAII, you just declare the next guard and the compiler handles every possible failure path.

**Key guarantee**: Only fully-constructed objects are destroyed. If a constructor throws on resource 4, resources 1-3 are destroyed (they were fully constructed). Resource 4's destructor does NOT run (it was never fully constructed). This is why constructors should either succeed completely or throw without leaking.

```cpp
#include <memory>
#include <iostream>
#include <string>
#include <vector>

struct Widget {
    std::string name;
    Widget(std::string n) : name(std::move(n)) {
        std::cout << "Widget(" << name << ") created\n";
    }
    ~Widget() { std::cout << "Widget(" << name << ") destroyed\n"; }
};

// PATTERN 1: Factory — function creates and returns ownership
std::unique_ptr<Widget> create_widget(const std::string& name) {
    return std::make_unique<Widget>(name);  // RVO, no move needed
}

// PATTERN 2: Sink — function takes ownership permanently
void archive(std::unique_ptr<Widget> w) {
    std::cout << "Archived: " << w->name << "\n";
    // w destroyed when function returns
}

// PATTERN 3: Pass-through — function modifies and returns ownership
std::unique_ptr<Widget> upgrade(std::unique_ptr<Widget> w) {
    w->name += " (v2)";
    return w;  // Implicit move on return
}

// PATTERN 4: Store — function stores in a container
class WidgetRegistry {
    std::vector<std::unique_ptr<Widget>> widgets_;

public:
    void add(std::unique_ptr<Widget> w) {
        widgets_.push_back(std::move(w));  // Must move into container
    }

    // Transfer out of container
    std::unique_ptr<Widget> take(std::size_t index) {
        auto w = std::move(widgets_[index]);
        widgets_.erase(widgets_.begin() + index);
        return w;
    }
};

// PATTERN 5: Borrow — function uses but doesn't take ownership
void inspect(const Widget& w) {
    std::cout << "Inspecting: " << w.name << "\n";
    // Does NOT take ownership — caller keeps the unique_ptr
}

int main() {
    // Factory: caller receives ownership
    auto w1 = create_widget("Alpha");

    // Borrow: pass by reference, keep ownership
    inspect(*w1);

    // Pass-through: transfer out and back
    w1 = upgrade(std::move(w1));
    std::cout << "After upgrade: " << w1->name << "\n";

    // Store: transfer into container
    WidgetRegistry reg;
    reg.add(std::move(w1));       // w1 is null after this
    reg.add(create_widget("Beta"));  // Factory -> store directly

    // Take: transfer out of container
    auto w2 = reg.take(0);
    std::cout << "Took: " << w2->name << "\n";

    // Sink: permanent transfer
    archive(std::move(w2));       // w2 is null after this
}
```

The rules:
- **Return `unique_ptr`**: Factory pattern. Caller receives ownership.
- **Parameter `unique_ptr` by value**: Sink/store pattern. Caller must `std::move()` — makes transfer explicit at call site.
- **Parameter `const T&` or `T*`**: Borrow pattern. No ownership transfer.
- **Never** pass `unique_ptr` by const reference unless you need to inspect the pointer itself (null check). Pass the object by reference instead: `*ptr` or `ptr.get()`.

```cpp
#include <string>
#include <utility>
#include <iostream>
#include <vector>

class Base {
protected:
    std::string name_;
    std::vector<int> data_;

public:
    Base(std::string name, std::vector<int> data)
        : name_(std::move(name)), data_(std::move(data)) {}

    // Must explicitly declare move operations — compiler won't if you
    // declare a virtual destructor
    Base(Base&& other) noexcept
        : name_(std::move(other.name_)), data_(std::move(other.data_)) {
        std::cout << "Base move ctor\n";
    }

    Base& operator=(Base&& other) noexcept {
        name_ = std::move(other.name_);
        data_ = std::move(other.data_);
        std::cout << "Base move assign\n";
        return *this;
    }

    Base(const Base&) = default;
    Base& operator=(const Base&) = default;
    virtual ~Base() = default;
};

class Derived : public Base {
    double extra_;

public:
    Derived(std::string name, std::vector<int> data, double extra)
        : Base(std::move(name), std::move(data)), extra_(extra) {}

    // KEY: must explicitly move the base class
    Derived(Derived&& other) noexcept
        : Base(std::move(other)),     // Calls Base move ctor
          extra_(other.extra_) {
        std::cout << "Derived move ctor\n";
    }

    Derived& operator=(Derived&& other) noexcept {
        Base::operator=(std::move(other));  // Calls Base move assign
        extra_ = other.extra_;
        std::cout << "Derived move assign\n";
        return *this;
    }

    Derived(const Derived&) = default;
    Derived& operator=(const Derived&) = default;
};

int main() {
    Derived d1("widget", {1, 2, 3}, 3.14);

    std::cout << "--- move construct ---\n";
    Derived d2 = std::move(d1);
    // Output: Base move ctor, Derived move ctor

    std::cout << "--- move assign ---\n";
    Derived d3("other", {}, 0.0);
    d3 = std::move(d2);
    // Output: Base move assign, Derived move assign
}
```

**Critical mistake — forgetting to move the base:**
```cpp
// BUG: Base is COPIED, not moved!
Derived(Derived&& other) noexcept
    : Base(other),         // other is an lvalue! Calls Base COPY ctor
      extra_(other.extra_) {}

// FIX:
Derived(Derived&& other) noexcept
    : Base(std::move(other)),  // Explicitly cast to rvalue
      extra_(other.extra_) {}
```

**Why the compiler doesn't auto-generate moves with virtual destructor:**

Declaring `virtual ~Base() = default;` counts as a user-declared destructor. The C++ rules say: if any of the Big Five is user-declared, the compiler does NOT implicitly generate move operations. You must declare them yourself (or `= default` them).

**Best practice for polymorphic hierarchies:**
```cpp
class Base {
public:
    virtual ~Base() = default;
    Base(Base&&) = default;             // Explicitly defaulted
    Base& operator=(Base&&) = default;
    Base(const Base&) = default;
    Base& operator=(const Base&) = default;
};
// Derived classes can then rely on implicit generation
```

This is the "Rule of Five as defaults" pattern — declare all five as `= default` when you need a virtual destructor but don't manage raw resources.

C++20 allows `constexpr` destructors and dynamic allocation in constant expressions (memory must be freed before the constant expression ends). This enables RAII at compile time.

```cpp
#include <memory>
#include <array>
#include <cstddef>
#include <algorithm>

// constexpr RAII buffer
class ConstexprBuffer {
    int* data_;
    std::size_t size_;

public:
    constexpr ConstexprBuffer(std::size_t n)
        : data_(new int[n]{}), size_(n) {}

    constexpr ~ConstexprBuffer() { delete[] data_; }

    constexpr ConstexprBuffer(ConstexprBuffer&& other) noexcept
        : data_(std::exchange(other.data_, nullptr)),
          size_(std::exchange(other.size_, 0)) {}

    constexpr ConstexprBuffer& operator=(ConstexprBuffer&& other) noexcept {
        if (this != &other) {
            delete[] data_;
            data_ = std::exchange(other.data_, nullptr);
            size_ = std::exchange(other.size_, 0);
        }
        return *this;
    }

    ConstexprBuffer(const ConstexprBuffer&) = delete;
    ConstexprBuffer& operator=(const ConstexprBuffer&) = delete;

    constexpr int& operator[](std::size_t i) { return data_[i]; }
    constexpr const int& operator[](std::size_t i) const { return data_[i]; }
    constexpr std::size_t size() const { return size_; }
};

// Compile-time computation using RAII
constexpr int compute_sum(int n) {
    ConstexprBuffer buf(n);  // RAII: allocates at compile time
    for (int i = 0; i < n; ++i)
        buf[i] = i * i;

    int sum = 0;
    for (int i = 0; i < n; ++i)
        sum += buf[i];

    return sum;
    // buf destroyed here — memory freed before constexpr ends
}

// constexpr scope_guard
template <typename F>
class ConstexprScopeGuard {
    F fn_;
    bool active_;

public:
    constexpr explicit ConstexprScopeGuard(F f)
        : fn_(std::move(f)), active_(true) {}

    constexpr ~ConstexprScopeGuard() {
        if (active_) fn_();
    }

    constexpr void dismiss() { active_ = false; }

    ConstexprScopeGuard(const ConstexprScopeGuard&) = delete;
    ConstexprScopeGuard& operator=(const ConstexprScopeGuard&) = delete;
};

constexpr int safe_compute() {
    int* p = new int(42);
    ConstexprScopeGuard guard([&] { delete p; });

    int result = *p * 2;
    // guard ensures delete even if we add early returns later
    return result;
}

// Verify at compile time
static_assert(compute_sum(5) == 0 + 1 + 4 + 9 + 16);  // 30
static_assert(safe_compute() == 84);

int main() {
    constexpr int result = compute_sum(10);
    // result is computed entirely at compile time
    // All memory allocated and freed during compilation
}
```

C++20 constexpr allocation rules:
- `new`/`delete` allowed in constexpr contexts
- All memory must be deallocated before the constant expression completes ("transient allocation")
- Memory that escapes = compilation error (compiler catches leaks!)
- RAII destructors work exactly like runtime — but the compiler verifies correctness

```cpp
#include <string>
#include <vector>
#include <stdexcept>
#include <optional>

class UserProfile {
    std::string name_;
    std::string email_;
    std::vector<std::string> tags_;
    std::optional<std::string> bio_;

public:
    UserProfile(std::string name, std::string email)
        : name_(std::move(name)), email_(std::move(email)) {}

    // SAFE: return const reference — caller can read but not modify
    const std::string& name() const { return name_; }
    const std::string& email() const { return email_; }
    const std::vector<std::string>& tags() const { return tags_; }

    // SAFE: return optional by value (small + move-friendly)
    std::optional<std::string> bio() const { return bio_; }

    // Mutators — return reference for chaining
    UserProfile& set_name(std::string name) {
        name_ = std::move(name);
        return *this;
    }

    UserProfile& add_tag(std::string tag) {
        tags_.push_back(std::move(tag));
        return *this;
    }

    // When you need both const and non-const access:
    const std::string& tag_at(std::size_t i) const {
        if (i >= tags_.size()) throw std::out_of_range("tag index");
        return tags_[i];
    }

    std::string& tag_at(std::size_t i) {
        if (i >= tags_.size()) throw std::out_of_range("tag index");
        return tags_[i];
    }
};

// DANGEROUS patterns to avoid:
class Bad {
    std::string temp_;

public:
    // BUG: returning reference to temporary
    const std::string& get_full_name() const {
        // return first_ + " " + last_;  // DANGLING REFERENCE to temporary!
        temp_ = "cached";  // Workaround: store in member (ugly)
        return temp_;
    }

    // BUG: returning non-const reference from const method
    // std::string& name() const { return name_; }  // Won't compile

    // BUG: returning internal pointer that may be invalidated
    const std::string* first_tag() const {
        if (tags_.empty()) return nullptr;
        return &tags_[0];  // Invalidated by push_back!
    }
};

// Guidelines:
void usage() {
    UserProfile user("Alice", "alice@example.com");
    user.add_tag("admin").add_tag("dev");

    // Read via const reference — zero copy
    const std::string& name = user.name();  // Efficient
    std::string name_copy = user.name();     // Copy if you need to store

    // const object only allows const getters
    const UserProfile& cref = user;
    // cref.tag_at(0) = "hacker";  // ERROR: returns const string&
}
```

Rules for returning references from getters:
1. **Return `const T&`** from const member functions — safe, zero-copy read access
2. **Never return reference to a local/temporary** — instant dangling reference
3. **Return by value** for computed results, optionals, and small types
4. **Return `T&` (non-const)** only from non-const overloads when mutation is intended
5. **Beware invalidation** — references to vector elements are invalidated by push_back/insert
6. **Prefer returning `std::string_view`** for read-only string access (C++17) when the caller doesn't need ownership

PIMPL (Pointer to Implementation) hides implementation details behind an opaque pointer. This isolates clients from internal changes, reduces compile dependencies, and preserves ABI stability.

**widget.h — Public header:**
```cpp
#pragma once
#include <memory>
#include <string>

class Widget {
public:
    Widget(std::string name, int value);
    ~Widget();  // MUST be declared (even = default) in header

    // Move operations — declared in header, defined in .cpp
    Widget(Widget&& other) noexcept;
    Widget& operator=(Widget&& other) noexcept;

    // No copy (or declare and define in .cpp)
    Widget(const Widget&) = delete;
    Widget& operator=(const Widget&) = delete;

    // Public API
    const std::string& name() const;
    int value() const;
    void update(int new_value);

private:
    struct Impl;                    // Forward declaration only
    std::unique_ptr<Impl> pimpl_;   // Opaque pointer
};
```

**widget.cpp — Implementation:**
```cpp
#include "widget.h"
#include <iostream>
#include <vector>
#include <algorithm>
// Heavy headers only included here — clients don't see them

struct Widget::Impl {
    std::string name;
    int value;
    std::vector<int> history;  // Hidden from clients

    Impl(std::string n, int v) : name(std::move(n)), value(v) {
        history.push_back(v);
    }
};

// Constructor: creates impl
Widget::Widget(std::string name, int value)
    : pimpl_(std::make_unique<Impl>(std::move(name), value)) {}

// Destructor: MUST be in .cpp where Impl is complete
Widget::~Widget() = default;

// Move operations: also in .cpp
Widget::Widget(Widget&& other) noexcept = default;
Widget& Widget::operator=(Widget&& other) noexcept = default;

// API forwarding
const std::string& Widget::name() const { return pimpl_->name; }
int Widget::value() const { return pimpl_->value; }

void Widget::update(int new_value) {
    pimpl_->value = new_value;
    pimpl_->history.push_back(new_value);
}
```

**Why the destructor and move ops MUST be in the .cpp:**

`unique_ptr<Impl>` needs `Impl` to be a complete type when it calls `delete`. If the destructor is in the header (even `= default`), the compiler instantiates `unique_ptr::~unique_ptr()` in every translation unit that includes the header — but `Impl` is only forward-declared there. Result: compilation error.

Putting `~Widget() = default;` in the .cpp means the compiler instantiates the unique_ptr destructor in widget.cpp, where `Impl` is fully defined.

**Benefits:**
- Changing `Impl` members doesn't recompile clients
- Heavy includes (`<vector>`, `<algorithm>`) stay out of the header
- ABI stable: `sizeof(Widget)` is always `sizeof(unique_ptr)` = 8 bytes
- Private members truly private (not visible in header)

```cpp
#include <algorithm>
#include <cstring>
#include <utility>

class String {
    char* data_;
    std::size_t len_;

public:
    String(const char* s = "")
        : len_(std::strlen(s)), data_(new char[len_ + 1]) {
        std::memcpy(data_, s, len_ + 1);
    }

    ~String() { delete[] data_; }

    String(const String& other)
        : len_(other.len_), data_(new char[len_ + 1]) {
        std::memcpy(data_, other.data_, len_ + 1);
    }

    String(String&& other) noexcept
        : data_(std::exchange(other.data_, nullptr)),
          len_(std::exchange(other.len_, 0)) {}

    // BAD: Naive copy assignment — broken on self-assignment
    String& bad_assign(const String& other) {
        delete[] data_;                    // Destroys our data
        len_ = other.len_;                 // If this == &other, other.len_ is garbage!
        data_ = new char[len_ + 1];        // Allocates with garbage length
        std::memcpy(data_, other.data_, len_ + 1);  // Reads freed memory!
        return *this;
    }

    // OK: Self-check guard — correct but not exception-safe
    String& check_assign(const String& other) {
        if (this == &other) return *this;  // Self-assignment check
        delete[] data_;
        len_ = other.len_;
        data_ = new char[len_ + 1];        // If new throws, *this is invalid!
        std::memcpy(data_, other.data_, len_ + 1);
        return *this;
    }

    // BEST: Copy-and-swap — self-assignment safe AND exception-safe
    String& operator=(String other) {  // By value: copy happens here
        swap(*this, other);             // Noexcept swap
        return *this;
        // Old data destroyed when 'other' goes out of scope
    }

    friend void swap(String& a, String& b) noexcept {
        using std::swap;
        swap(a.data_, b.data_);
        swap(a.len_, b.len_);
    }
};

int main() {
    String s("hello");

    // Self-assignment: s = s
    s = s;  // With copy-and-swap:
            // 1. Copy of s is made (parameter 'other')
            // 2. *this and copy are swapped
            // 3. Copy (holding old data) is destroyed
            // Result: s unchanged, no crash

    // Aliased self-assignment through reference:
    String& ref = s;
    s = ref;  // Same object — still safe
}
```

Why copy-and-swap is superior:

| Approach | Self-safe | Exception-safe | Performance |
|----------|-----------|----------------|-------------|
| Naive | No (UB) | No | Fastest (broken) |
| Self-check | Yes | No (leak on throw) | Fast |
| Copy-and-swap | Yes | Strong guarantee | Slightly slower (extra copy on same-size assign) |

The "extra copy" cost is negligible compared to the safety guarantees. For performance-critical code where you know sizes match frequently, you can optimize:

```cpp
String& operator=(const String& other) {
    if (this != &other) {
        if (len_ == other.len_) {
            // Same size: reuse buffer, no allocation
            std::memcpy(data_, other.data_, len_ + 1);
        } else {
            // Different size: copy-and-swap
            String tmp(other);
            swap(*this, tmp);
        }
    }
    return *this;
}
```

```cpp
#include <queue>
#include <mutex>
#include <condition_variable>
#include <thread>
#include <optional>
#include <iostream>
#include <chrono>
#include <vector>

template <typename T>
class BlockingQueue {
    std::queue<T> queue_;
    mutable std::mutex mutex_;
    std::condition_variable not_empty_;
    bool shutdown_ = false;

public:
    void push(T item) {
        {
            std::lock_guard<std::mutex> lock(mutex_);  // RAII lock
            if (shutdown_) return;
            queue_.push(std::move(item));
        }  // lock released before notify (optimization: avoids wake-then-block)
        not_empty_.notify_one();
    }

    // Returns nullopt when queue is shut down and empty
    std::optional<T> pop() {
        std::unique_lock<std::mutex> lock(mutex_);  // RAII lock
        not_empty_.wait(lock, [this] {
            return !queue_.empty() || shutdown_;
        });

        if (queue_.empty()) return std::nullopt;  // Shutdown signal

        T item = std::move(queue_.front());
        queue_.pop();
        return item;
    }

    void shutdown() {
        {
            std::lock_guard<std::mutex> lock(mutex_);
            shutdown_ = true;
        }
        not_empty_.notify_all();  // Wake all waiting consumers
    }

    bool empty() const {
        std::lock_guard<std::mutex> lock(mutex_);
        return queue_.empty();
    }
};

// RAII thread joiner — ensures threads are joined on scope exit
class ThreadGroup {
    std::vector<std::thread> threads_;

public:
    template <typename F>
    void spawn(F&& fn) {
        threads_.emplace_back(std::forward<F>(fn));
    }

    ~ThreadGroup() {
        for (auto& t : threads_) {
            if (t.joinable()) t.join();
        }
    }

    ThreadGroup() = default;
    ThreadGroup(const ThreadGroup&) = delete;
    ThreadGroup& operator=(const ThreadGroup&) = delete;
};

int main() {
    BlockingQueue<int> queue;
    ThreadGroup threads;

    // 3 consumers
    for (int id = 0; id < 3; ++id) {
        threads.spawn([&queue, id] {
            while (auto item = queue.pop()) {
                std::cout << "Consumer " << id
                          << " processed: " << *item << "\n";
            }
            std::cout << "Consumer " << id << " shutting down\n";
        });
    }

    // Producer
    for (int i = 0; i < 10; ++i) {
        queue.push(i);
    }

    queue.shutdown();  // Signal consumers to exit after draining

    // ~ThreadGroup joins all threads automatically
    // Even if an exception is thrown, threads are joined (RAII)
}
```

RAII guarantees in this code:
1. **`lock_guard`**: Mutex always unlocked, even if push/pop throw
2. **`unique_lock`**: Required for condition_variable.wait (must be unlockable), still RAII-managed
3. **`ThreadGroup`**: All threads joined on destruction — no zombie threads, no crashes from joinable thread destruction
4. **`optional<T>`**: Return type signals "no more items" without exceptions or sentinel values

Shutdown protocol:
- `shutdown()` sets flag + wakes all waiters
- Consumers see `shutdown_ == true`, drain remaining items, then get `nullopt`
- No data lost: items pushed before `shutdown()` are all consumed

```cpp
#include <iostream>
#include <functional>

class Widget {
    int value_ = 42;

public:
    // Non-const member function
    void set(int v) { value_ = v; }

    // Const member function
    int get() const { return value_; }

    // Overloaded on const
    int& access() { return value_; }
    const int& access() const { return value_; }
};

int main() {
    // Pointer to NON-CONST member function
    void (Widget::*setter)(int) = &Widget::set;
    // Type: void (Widget::*)(int)
    // Can only be called on non-const Widget

    // Pointer to CONST member function
    int (Widget::*getter)() const = &Widget::get;
    // Type: int (Widget::*) () const
    // Can be called on both const and non-const Widget

    Widget w;
    const Widget cw;

    // Calling through pointer-to-member
    (w.*setter)(100);          // OK: w is non-const
    // (cw.*setter)(100);      // ERROR: cw is const, setter is non-const

    int v1 = (w.*getter)();    // OK: const member fn on non-const object
    int v2 = (cw.*getter)();   // OK: const member fn on const object

    // Selecting const vs non-const overload
    int& (Widget::*nc_access)() = &Widget::access;            // non-const
    const int& (Widget::*c_access)() const = &Widget::access; // const

    (w.*nc_access)() = 99;     // OK: returns int&
    // (cw.*nc_access)() = 99; // ERROR: can't call non-const on const object
    int val = (cw.*c_access)();// OK: returns const int&

    // With std::invoke (cleaner syntax)
    std::invoke(setter, w, 50);
    int result = std::invoke(getter, cw);
    std::cout << result << "\n";  // 42 (cw was never modified)

    // Using auto to avoid writing the type
    auto fn = &Widget::get;  // auto deduces int (Widget::*)() const

    // In templates — using std::mem_fn
    auto bound = std::mem_fn(&Widget::get);
    std::cout << bound(w) << "\n";   // 50
    std::cout << bound(cw) << "\n";  // 42
}
```

Full type syntax reference:
```
Return (Class::*name)(Params)                // non-const
Return (Class::*name)(Params) const          // const
Return (Class::*name)(Params) volatile       // volatile (rare)
Return (Class::*name)(Params) const volatile // both (rare)
Return (Class::*name)(Params) noexcept       // noexcept (C++17)
Return (Class::*name)(Params) const noexcept // const + noexcept
Return (Class::*name)(Params) &              // lvalue-qualified
Return (Class::*name)(Params) const &        // const + lvalue
Return (Class::*name)(Params) &&             // rvalue-qualified
```

The const in a pointer-to-member-function type is not about the pointer — it's about what kind of object you can call it on. A `const` member function pointer can be called on const or non-const objects. A non-const pointer can only be called on non-const objects.

```cpp
#include <mutex>
#include <thread>
#include <iostream>
#include <string>
#include <vector>

class BankAccount {
    mutable std::mutex mutex_;  // mutable: lockable in const methods
    std::string name_;
    double balance_;

public:
    BankAccount(std::string name, double balance)
        : name_(std::move(name)), balance_(balance) {}

    // Expose mutex for external locking (for multi-object operations)
    std::mutex& mutex() const { return mutex_; }
    const std::string& name() const { return name_; }
    double balance() const { return balance_; }
    void deposit(double amount) { balance_ += amount; }
    void withdraw(double amount) { balance_ -= amount; }
};

// DEADLOCK-PRONE approach (DON'T DO THIS):
void bad_transfer(BankAccount& from, BankAccount& to, double amount) {
    std::lock_guard<std::mutex> lock1(from.mutex());  // Lock A first
    std::lock_guard<std::mutex> lock2(to.mutex());    // Lock B second
    // Thread 1: transfer(a, b) — locks a, waits for b
    // Thread 2: transfer(b, a) — locks b, waits for a
    // DEADLOCK!
    from.withdraw(amount);
    to.deposit(amount);
}

// SAFE: scoped_lock locks all mutexes atomically (C++17)
void transfer(BankAccount& from, BankAccount& to, double amount) {
    // Locks both mutexes using deadlock-avoidance algorithm
    // (internally uses std::lock which tries all orderings)
    std::scoped_lock lock(from.mutex(), to.mutex());

    if (from.balance() < amount)
        throw std::runtime_error("Insufficient funds");

    from.withdraw(amount);
    to.deposit(amount);

    std::cout << from.name() << " -> " << to.name()
              << ": $" << amount << "\n";
    // Both mutexes unlocked when lock goes out of scope (RAII)
}

// Pre-C++17 equivalent using std::lock + adopt_lock:
void transfer_cpp14(BankAccount& from, BankAccount& to, double amount) {
    std::lock(from.mutex(), to.mutex());  // Lock both, no deadlock
    std::lock_guard<std::mutex> lk1(from.mutex(), std::adopt_lock);
    std::lock_guard<std::mutex> lk2(to.mutex(), std::adopt_lock);
    // adopt_lock: take ownership of already-locked mutex
    from.withdraw(amount);
    to.deposit(amount);
}

int main() {
    BankAccount alice("Alice", 1000);
    BankAccount bob("Bob", 500);

    std::vector<std::thread> threads;
    for (int i = 0; i < 100; ++i) {
        threads.emplace_back([&] { transfer(alice, bob, 1.0); });
        threads.emplace_back([&] { transfer(bob, alice, 1.0); });
    }

    for (auto& t : threads) t.join();

    std::cout << alice.name() << ": $" << alice.balance() << "\n";
    std::cout << bob.name() << ": $" << bob.balance() << "\n";
    // Totals preserved: $1500
}
```

`std::scoped_lock`:
- RAII: locks on construction, unlocks on destruction
- Deadlock-free: uses try-and-back-off algorithm internally
- Variadic: handles any number of mutexes
- Zero overhead for single mutex (equivalent to `lock_guard`)
- Preferred over `lock_guard` in all C++17 code

```cpp
#include <memory>
#include <iostream>
#include <string>

struct Config {
    std::string host;
    int port;
    Config(std::string h, int p) : host(std::move(h)), port(p) {}
};

// SHALLOW COPY: shared_ptr — multiple owners of same object
class ShallowClient {
    std::shared_ptr<Config> config_;  // Shared ownership

public:
    ShallowClient(std::shared_ptr<Config> cfg) : config_(std::move(cfg)) {}

    // Default copy: copies the shared_ptr (refcount++), not the Config
    // Both copies point to the SAME Config object

    void set_port(int p) { config_->port = p; }
    int port() const { return config_->port; }
    long refs() const { return config_.use_count(); }
};

// DEEP COPY: unique_ptr — each instance owns its own copy
class DeepClient {
    std::unique_ptr<Config> config_;  // Exclusive ownership

public:
    DeepClient(std::unique_ptr<Config> cfg) : config_(std::move(cfg)) {}

    // Manual deep copy — unique_ptr has no copy constructor
    DeepClient(const DeepClient& other)
        : config_(std::make_unique<Config>(*other.config_)) {
        // *other.config_ copies the Config value
    }

    DeepClient& operator=(const DeepClient& other) {
        if (this != &other)
            config_ = std::make_unique<Config>(*other.config_);
        return *this;
    }

    DeepClient(DeepClient&&) = default;
    DeepClient& operator=(DeepClient&&) = default;

    void set_port(int p) { config_->port = p; }
    int port() const { return config_->port; }
};

int main() {
    // SHALLOW: modifying one affects the other
    auto shared_cfg = std::make_shared<Config>("localhost", 8080);
    ShallowClient a(shared_cfg);
    ShallowClient b = a;  // Copies shared_ptr, not Config

    std::cout << "=== Shallow (shared_ptr) ===\n";
    std::cout << "a.port: " << a.port() << ", refs: " << a.refs() << "\n";
    // a.port: 8080, refs: 3 (shared_cfg + a + b)

    b.set_port(9090);  // Modifies THE SAME Config
    std::cout << "After b.set_port(9090):\n";
    std::cout << "a.port: " << a.port() << "\n";  // 9090! Changed!
    std::cout << "b.port: " << b.port() << "\n";  // 9090

    // DEEP: each has independent copy
    DeepClient c(std::make_unique<Config>("localhost", 8080));
    DeepClient d = c;  // Deep copies the Config

    std::cout << "\n=== Deep (unique_ptr + clone) ===\n";
    std::cout << "c.port: " << c.port() << "\n";  // 8080

    d.set_port(9090);  // Only modifies d's copy
    std::cout << "After d.set_port(9090):\n";
    std::cout << "c.port: " << c.port() << "\n";  // 8080 — unchanged
    std::cout << "d.port: " << d.port() << "\n";  // 9090
}
```

**Polymorphic deep copy with clone:**
```cpp
class Shape {
public:
    virtual ~Shape() = default;
    virtual std::unique_ptr<Shape> clone() const = 0;
    virtual void draw() const = 0;
};

class Circle : public Shape {
    double radius_;
public:
    Circle(double r) : radius_(r) {}
    std::unique_ptr<Shape> clone() const override {
        return std::make_unique<Circle>(*this);  // Copy construct
    }
    void draw() const override {
        std::cout << "Circle(r=" << radius_ << ")\n";
    }
};

class Canvas {
    std::vector<std::unique_ptr<Shape>> shapes_;
public:
    // Deep copy: clone each shape
    Canvas(const Canvas& other) {
        shapes_.reserve(other.shapes_.size());
        for (const auto& s : other.shapes_)
            shapes_.push_back(s->clone());
    }
    void add(std::unique_ptr<Shape> s) {
        shapes_.push_back(std::move(s));
    }
};
```

Decision guide:
- **shared_ptr (shallow)**: Intentional sharing, observer pattern, caches
- **unique_ptr + deep copy**: Independent copies, value semantics for owned objects
- **unique_ptr + clone()**: Deep copy of polymorphic hierarchies

```cpp
#include <utility>
#include <algorithm>
#include <iostream>
#include <string>
#include <vector>

class HeavyObject {
    std::string name_;
    std::vector<double> data_;  // Potentially huge

public:
    HeavyObject(std::string name, std::size_t size)
        : name_(std::move(name)), data_(size, 1.0) {}

    // Move-aware friend swap — found via ADL
    friend void swap(HeavyObject& a, HeavyObject& b) noexcept {
        using std::swap;          // Enable fallback to std::swap
        swap(a.name_, b.name_);   // Calls std::string's swap (O(1))
        swap(a.data_, b.data_);   // Calls std::vector's swap (O(1))
    }

    // Move constructor and assignment (use swap)
    HeavyObject(HeavyObject&& other) noexcept
        : HeavyObject("", 0) {   // Default construct
        swap(*this, other);       // Swap in the data
    }

    HeavyObject& operator=(HeavyObject other) noexcept {  // By value
        swap(*this, other);
        return *this;
    }

    HeavyObject(const HeavyObject&) = default;

    const std::string& name() const { return name_; }
    std::size_t size() const { return data_.size(); }
};

// WITHOUT custom swap — std::swap does 3 moves:
// tmp = move(a); a = move(b); b = move(tmp);
// With custom swap — member-by-member swap, no temporaries

// Why it matters for algorithms:
void demo() {
    std::vector<HeavyObject> objects;
    objects.emplace_back("charlie", 1'000'000);
    objects.emplace_back("alice", 2'000'000);
    objects.emplace_back("bob", 500'000);

    // std::sort calls swap — uses ADL to find our friend swap
    std::sort(objects.begin(), objects.end(),
              [](const HeavyObject& a, const HeavyObject& b) {
                  return a.name() < b.name();
              });

    for (const auto& obj : objects)
        std::cout << obj.name() << " (" << obj.size() << ")\n";
}
```

**How ADL (Argument-Dependent Lookup) finds custom swap:**
```cpp
template <typename T>
void generic_sort_step(T& a, T& b) {
    using std::swap;  // Make std::swap available as fallback
    swap(a, b);       // Unqualified call — ADL checks T's namespace first
    // If T has a friend swap() -> calls that (optimized)
    // If T has no custom swap -> falls back to std::swap (3 moves)
}

// WRONG: std::swap(a, b); — bypasses ADL, always 3 moves
```

**Performance difference:**
```
Operation                  | Custom swap | std::swap (3 moves)
---------------------------+-------------+--------------------
swap two HeavyObjects      | swap 2 ptrs | construct temp, 
  (1M doubles each)        | O(1)        | move 3x, destroy temp
                           | ~10 ns      | ~30 ns (but still O(1))

swap two non-movable types | swap members| 3 copies (!!)
  (legacy class)           | O(1)        | O(n) — catastrophic
```

**Rules:**
1. Always write `friend void swap(T&, T&) noexcept` for types with resources
2. Always use the two-step: `using std::swap; swap(a, b);` in generic code
3. Never write `std::swap(a, b);` in templates — it bypasses ADL
4. Mark swap `noexcept` — move_if_noexcept depends on it

Strong typedefs prevent accidental mixing of types that share the same underlying representation. Unlike raw `int`, `UserId` and `ProductId` won't implicitly convert to each other.

```cpp
#include <utility>
#include <string>
#include <iostream>
#include <functional>

// Generic strong typedef wrapper
template <typename T, typename Tag>
class StrongType {
    T value_;

public:
    // Constructors: forward to underlying type
    constexpr StrongType() : value_{} {}

    constexpr explicit StrongType(const T& v) : value_(v) {}
    constexpr explicit StrongType(T&& v) noexcept(std::is_nothrow_move_constructible_v<T>)
        : value_(std::move(v)) {}

    // Move and copy — delegate to T
    StrongType(const StrongType&) = default;
    StrongType& operator=(const StrongType&) = default;
    StrongType(StrongType&&) noexcept(std::is_nothrow_move_constructible_v<T>) = default;
    StrongType& operator=(StrongType&&) noexcept(std::is_nothrow_move_assignable_v<T>) = default;

    // Access
    constexpr T& get() & { return value_; }
    constexpr const T& get() const& { return value_; }
    constexpr T&& get() && { return std::move(value_); }

    // Comparison
    constexpr auto operator<=>(const StrongType&) const = default;
};

// Usage: define domain types
using UserId = StrongType<int, struct UserIdTag>;
using ProductId = StrongType<int, struct ProductIdTag>;
using Email = StrongType<std::string, struct EmailTag>;
using Name = StrongType<std::string, struct NameTag>;

// Hash support for use in unordered containers
template <typename T, typename Tag>
struct std::hash<StrongType<T, Tag>> {
    std::size_t operator()(const StrongType<T, Tag>& v) const {
        return std::hash<T>{}(v.get());
    }
};

// Functions that accept only the correct type
void send_email(Email to, Name from) {
    std::cout << "From: " << from.get() << " To: " << to.get() << "\n";
}

struct User {
    UserId id;
    Name name;
    Email email;
};

User find_user(UserId id);
// User find_user(ProductId id);  // Different function, different type!

int main() {
    UserId uid(42);
    ProductId pid(42);

    // uid == pid;           // COMPILE ERROR: different types!
    // find_user(pid);       // COMPILE ERROR: expects UserId, got ProductId
    // find_user(42);        // COMPILE ERROR: no implicit conversion
    // find_user(UserId(42)); // OK: explicit construction

    // Move semantics work for string-based types
    Email email(std::string("alice@example.com"));
    Name name(std::string("Alice"));

    // Move the strings into the function (no copy)
    send_email(std::move(email), std::move(name));
    // email.get() and name.get() are now in moved-from state

    // Comparison works
    UserId a(1), b(2);
    if (a < b) std::cout << "a < b\n";
}
```

Benefits:
- Zero runtime cost (same layout as underlying type)
- Compile-time prevention of type confusion bugs
- Move semantics propagated to underlying type automatically
- `noexcept` propagation via `is_nothrow_move_*` traits
- Works with any underlying type: int, string, vector, custom types

```cpp
#include <memory>
#include <vector>
#include <mutex>
#include <algorithm>
#include <functional>
#include <iostream>
#include <string>

// Observer interface
class Observer : public std::enable_shared_from_this<Observer> {
public:
    virtual ~Observer() = default;
    virtual void on_event(const std::string& event) = 0;
};

// Thread-safe event emitter using weak_ptr observers
class EventEmitter {
    mutable std::mutex mutex_;
    std::vector<std::weak_ptr<Observer>> observers_;

public:
    void subscribe(std::shared_ptr<Observer> observer) {
        std::lock_guard<std::mutex> lock(mutex_);
        observers_.push_back(observer);  // Store as weak_ptr
    }

    void emit(const std::string& event) {
        // Collect live observers under lock, then notify without lock
        std::vector<std::shared_ptr<Observer>> alive;
        {
            std::lock_guard<std::mutex> lock(mutex_);
            // Promote weak_ptr to shared_ptr, remove expired ones
            auto it = std::remove_if(observers_.begin(), observers_.end(),
                [&alive](std::weak_ptr<Observer>& wp) {
                    if (auto sp = wp.lock()) {
                        alive.push_back(sp);
                        return false;  // Keep
                    }
                    return true;  // Remove expired
                });
            observers_.erase(it, observers_.end());
        }

        // Notify outside the lock — observers can safely unsubscribe
        for (auto& obs : alive) {
            obs->on_event(event);
        }
        // alive goes out of scope — temporary shared_ptrs released
    }

    std::size_t observer_count() const {
        std::lock_guard<std::mutex> lock(mutex_);
        return observers_.size();
    }
};

// Concrete observer
class Logger : public Observer {
    std::string prefix_;

public:
    explicit Logger(std::string prefix) : prefix_(std::move(prefix)) {
        std::cout << prefix_ << " created\n";
    }
    ~Logger() override {
        std::cout << prefix_ << " destroyed\n";
    }

    void on_event(const std::string& event) override {
        std::cout << prefix_ << ": " << event << "\n";
    }
};

int main() {
    EventEmitter emitter;

    auto log1 = std::make_shared<Logger>("[INFO]");
    auto log2 = std::make_shared<Logger>("[DEBUG]");

    emitter.subscribe(log1);
    emitter.subscribe(log2);

    emitter.emit("system started");
    // [INFO]: system started
    // [DEBUG]: system started

    std::cout << "Observers: " << emitter.observer_count() << "\n";  // 2

    log2.reset();  // Destroy the DEBUG logger
    std::cout << "After reset:\n";

    emitter.emit("user connected");
    // [INFO]: user connected
    // (DEBUG is gone — weak_ptr expired, auto-removed)

    std::cout << "Observers: " << emitter.observer_count() << "\n";  // 1
}
```

Why `weak_ptr` is essential here:
- **No prevent-destruction**: Observers can be destroyed independently. The emitter doesn't keep them alive.
- **No dangling pointers**: `weak_ptr::lock()` returns nullptr if the observer is gone — safe check.
- **Auto-cleanup**: Expired weak_ptrs are removed on each `emit()` — no manual unsubscribe needed.
- **Thread-safe**: The lock-then-collect-then-notify pattern avoids calling user code under lock (prevents deadlock if observer modifies the emitter).

RAII works in coroutines, but with a twist: when a coroutine suspends, its frame (including local variables) is preserved on the heap. RAII objects in the frame are destroyed when the coroutine completes or is destroyed.

```cpp
#include <coroutine>
#include <iostream>
#include <memory>
#include <string>

// Simple task coroutine type
struct Task {
    struct promise_type {
        Task get_return_object() {
            return Task{std::coroutine_handle<promise_type>::from_promise(*this)};
        }
        std::suspend_never initial_suspend() { return {}; }
        std::suspend_always final_suspend() noexcept { return {}; }
        void return_void() {}
        void unhandled_exception() { std::terminate(); }
    };

    std::coroutine_handle<promise_type> handle;

    ~Task() {
        if (handle) handle.destroy();
        // Destroying the handle destroys the coroutine frame,
        // which calls destructors of all local RAII objects
    }

    Task(Task&& other) noexcept : handle(std::exchange(other.handle, nullptr)) {}
    Task& operator=(Task&&) = delete;
    Task(const Task&) = delete;

    explicit Task(std::coroutine_handle<promise_type> h) : handle(h) {}

    bool resume() {
        if (handle && !handle.done()) {
            handle.resume();
            return !handle.done();
        }
        return false;
    }
};

// RAII tracer to show destruction
struct Guard {
    std::string name;
    Guard(std::string n) : name(std::move(n)) {
        std::cout << "  + " << name << " acquired\n";
    }
    ~Guard() {
        std::cout << "  - " << name << " released\n";
    }
};

struct Suspend {
    bool await_ready() { return false; }
    void await_suspend(std::coroutine_handle<>) {}
    void await_resume() {}
};

// Coroutine with RAII guards
Task example_coroutine() {
    Guard g1("mutex_lock");
    auto buffer = std::make_unique<char[]>(1024);
    std::cout << "  (buffer allocated)\n";

    co_await Suspend{};  // Suspend point 1
    // g1 and buffer survive across suspension — stored in coroutine frame

    Guard g2("file_handle");

    co_await Suspend{};  // Suspend point 2
    // Both g1, g2, and buffer survive

    std::cout << "  (coroutine completing)\n";
    // Normal completion: g2 destroyed, then buffer, then g1 (reverse order)
}

int main() {
    std::cout << "=== Normal completion ===\n";
    {
        Task t = example_coroutine();
        // + mutex_lock acquired, (buffer allocated)
        t.resume();  // Resume at suspend 1
        // + file_handle acquired
        t.resume();  // Resume at suspend 2
        // (coroutine completing)
        // - file_handle released
        // - mutex_lock released
    }

    std::cout << "\n=== Early destruction (coroutine abandoned) ===\n";
    {
        Task t = example_coroutine();
        // + mutex_lock acquired, (buffer allocated)
        t.resume();  // Resume at suspend 1
        // + file_handle acquired
        // DON'T resume again — just let Task go out of scope
    }
    // ~Task destroys coroutine frame:
    // - file_handle released
    // - mutex_lock released
    // (buffer freed by unique_ptr)
}
```

Key rules for RAII in coroutines:
1. **Local RAII objects are stored in the coroutine frame** (heap-allocated). They survive across `co_await` suspension points.
2. **Destroying the coroutine handle destroys the frame**, which runs destructors of all live locals in reverse order — same as stack unwinding.
3. **Never let a coroutine handle leak** — wrap it in an RAII type (like our `Task`) that calls `handle.destroy()` in its destructor.
4. **Coroutine parameters are copied into the frame** at the start. If you pass a `unique_ptr` parameter, it's moved into the frame.
5. **Don't hold raw locks across suspension** — another coroutine might resume on a different thread. Use `co_await` friendly async locks instead.

```cpp
#include <map>
#include <unordered_map>
#include <string>
#include <iostream>
#include <utility>

struct HeavyValue {
    std::string data;
    HeavyValue(std::string d) : data(std::move(d)) {}
    HeavyValue(const HeavyValue& o) : data(o.data) {
        std::cout << "  COPY: " << data << "\n";
    }
    HeavyValue(HeavyValue&& o) noexcept : data(std::move(o.data)) {
        std::cout << "  move: " << data << "\n";
    }
};

int main() {
    std::map<int, HeavyValue> map;

    // 1. insert with move
    std::cout << "--- insert (copy) ---\n";
    HeavyValue v1("alpha");
    map.insert({1, v1});              // Copies v1 into the map

    std::cout << "--- insert (move) ---\n";
    map.insert({2, std::move(v1)});   // Moves v1 into the map

    // 2. emplace — constructs in-place, no copy or move of value
    std::cout << "--- emplace ---\n";
    map.emplace(3, "beta");           // Constructs HeavyValue("beta") in-place

    // 3. try_emplace (C++17) — doesn't move argument if key exists
    std::cout << "--- try_emplace (new key) ---\n";
    HeavyValue v2("gamma");
    map.try_emplace(4, std::move(v2));  // Key 4 new: v2 is moved

    std::cout << "--- try_emplace (existing key) ---\n";
    HeavyValue v3("delta");
    map.try_emplace(4, std::move(v3));  // Key 4 exists: v3 is NOT moved!
    std::cout << "v3 still has: " << v3.data << "\n";  // "delta" — preserved

    // 4. extract — removes node without destroying the value
    std::cout << "--- extract ---\n";
    auto node = map.extract(3);  // Removes key 3, value stays alive in node
    if (node) {
        std::cout << "  Extracted key " << node.key()
                  << ": " << node.mapped().data << "\n";
        // Modify key without copy/move of value!
        node.key() = 30;
        map.insert(std::move(node));  // Re-insert with new key
    }

    // 5. merge — transfer nodes between maps without copying
    std::cout << "--- merge ---\n";
    std::map<int, HeavyValue> other;
    other.emplace(5, "epsilon");
    other.emplace(1, "conflict");  // Key 1 already in map

    map.merge(other);
    // Key 5: moved to map (no copy, just re-links the tree node)
    // Key 1: stays in other (conflict)
    std::cout << "other size after merge: " << other.size() << "\n";  // 1

    std::cout << "\n--- Final map ---\n";
    for (const auto& [k, v] : map) {
        std::cout << "  " << k << ": " << v.data << "\n";
    }
}
```

Performance guide:
| Operation | Copies | Moves | Notes |
|-----------|--------|-------|-------|
| `insert({k, v})` | 1 | 0 | Copies v |
| `insert({k, move(v)})` | 0 | 1 | Moves v |
| `emplace(k, args...)` | 0 | 0 | Constructs in-place |
| `try_emplace(k, move(v))` | 0 | 0-1 | Moves only if inserted |
| `extract(k)` | 0 | 0 | Detaches tree node |
| `merge(other_map)` | 0 | 0 | Re-links nodes (no element copy/move) |

`try_emplace` is strictly better than `emplace` when you have movable arguments — it won't consume them on collision. `extract` + `insert` is the only way to change a key without copying the value.

```cpp
#include <memory>
#include <string>
#include <iostream>
#include <functional>
#include <vector>

int main() {
    // 1. Move capture with mutable lambda
    auto ptr = std::make_unique<std::string>("hello");

    // Move ptr INTO the lambda's capture
    // Lambda must be mutable because calling methods on captured ptr
    // modifies the lambda's internal state
    auto fn = [p = std::move(ptr)]() mutable {
        *p += " world";
        std::cout << *p << "\n";
    };
    // ptr is now null — ownership transferred to lambda

    fn();  // "hello world"
    fn();  // "hello world world" (lambda state persists between calls)

    // 2. Move capture for move-only types
    std::vector<std::unique_ptr<int>> items;
    items.push_back(std::make_unique<int>(1));
    items.push_back(std::make_unique<int>(2));

    // Can't copy vector<unique_ptr>, must move
    auto process = [v = std::move(items)]() {
        for (const auto& item : v)
            std::cout << *item << " ";
        std::cout << "\n";
    };
    // items is now empty
    process();  // "1 2"

    // 3. Why mutable is needed
    int counter = 0;
    auto inc = [counter]() mutable {  // Copy capture + mutable
        return ++counter;  // Modifies lambda's own copy
    };
    std::cout << inc() << "\n";  // 1
    std::cout << inc() << "\n";  // 2
    std::cout << counter << "\n"; // 0 — original unchanged

    // Without mutable:
    // auto bad = [counter]() { return ++counter; };  // ERROR: can't modify

    // 4. Move capture with init expression (C++14)
    std::string name = "Alice";
    auto greet = [n = std::move(name)]() {
        std::cout << "Hello, " << n << "\n";
    };
    // name is now in moved-from state
    greet();  // "Hello, Alice"

    // 5. Storing move-only lambdas
    // std::function requires copyable callables — WON'T WORK:
    // std::function<void()> f = std::move(fn);  // ERROR

    // Solutions:
    // a) Use auto (preferred)
    auto stored = std::move(fn);

    // b) Use std::move_only_function (C++23)
    // std::move_only_function<void()> mof = std::move(fn);

    // c) Use template parameter
    auto invoke = [](auto&& callable) { callable(); };
    // invoke(std::move(stored));

    // 6. Forwarding capture (perfect capture)
    auto factory = [](auto&& value) {
        return [v = std::forward<decltype(value)>(value)]() mutable {
            return std::move(v);
        };
    };

    std::string data = "moved";
    auto getter = factory(std::move(data));  // Moves data into lambda
    std::string result = getter();           // Moves out of lambda
    std::cout << result << "\n";             // "moved"
}
```

Key rules:
- **`mutable`**: Required when the lambda body modifies captured-by-value variables. Without it, the lambda's `operator()` is `const`.
- **Move capture** (`[x = std::move(y)]`): Transfers ownership into the lambda. Essential for `unique_ptr` and other move-only types.
- **Move-only lambdas** (those with move-captured unique_ptr, etc.) can't be stored in `std::function` — use `auto`, templates, or C++23 `std::move_only_function`.
- **`mutable` + move capture** is the pattern for lambdas that consume resources: read once, transfer ownership out, etc.

```cpp
#include <cstddef>
#include <stdexcept>
#include <string>
#include <string_view>
#include <utility>

#ifdef _WIN32
#include <windows.h>
#else
#include <fcntl.h>
#include <sys/mman.h>
#include <sys/stat.h>
#include <unistd.h>
#endif

class MemoryMappedFile {
    void* data_ = nullptr;
    std::size_t size_ = 0;

#ifdef _WIN32
    HANDLE file_ = INVALID_HANDLE_VALUE;
    HANDLE mapping_ = nullptr;
#else
    int fd_ = -1;
#endif

public:
    explicit MemoryMappedFile(const char* path) {
#ifdef _WIN32
        file_ = CreateFileA(path, GENERIC_READ, FILE_SHARE_READ,
                           nullptr, OPEN_EXISTING, FILE_ATTRIBUTE_NORMAL, nullptr);
        if (file_ == INVALID_HANDLE_VALUE)
            throw std::runtime_error(std::string("Cannot open: ") + path);

        LARGE_INTEGER file_size;
        if (!GetFileSizeEx(file_, &file_size)) {
            CloseHandle(file_);
            throw std::runtime_error("Cannot get file size");
        }
        size_ = static_cast<std::size_t>(file_size.QuadPart);

        mapping_ = CreateFileMappingA(file_, nullptr, PAGE_READONLY, 0, 0, nullptr);
        if (!mapping_) {
            CloseHandle(file_);
            throw std::runtime_error("Cannot create file mapping");
        }

        data_ = MapViewOfFile(mapping_, FILE_MAP_READ, 0, 0, 0);
        if (!data_) {
            CloseHandle(mapping_);
            CloseHandle(file_);
            throw std::runtime_error("Cannot map file");
        }
#else
        fd_ = ::open(path, O_RDONLY);
        if (fd_ < 0)
            throw std::runtime_error(std::string("Cannot open: ") + path);

        struct stat st;
        if (fstat(fd_, &st) < 0) {
            ::close(fd_);
            throw std::runtime_error("Cannot stat file");
        }
        size_ = static_cast<std::size_t>(st.st_size);

        data_ = ::mmap(nullptr, size_, PROT_READ, MAP_PRIVATE, fd_, 0);
        if (data_ == MAP_FAILED) {
            data_ = nullptr;
            ::close(fd_);
            throw std::runtime_error("Cannot mmap file");
        }
#endif
    }

    ~MemoryMappedFile() {
#ifdef _WIN32
        if (data_) UnmapViewOfFile(data_);
        if (mapping_) CloseHandle(mapping_);
        if (file_ != INVALID_HANDLE_VALUE) CloseHandle(file_);
#else
        if (data_) ::munmap(data_, size_);
        if (fd_ >= 0) ::close(fd_);
#endif
    }

    // Move support
    MemoryMappedFile(MemoryMappedFile&& other) noexcept
        : data_(std::exchange(other.data_, nullptr)),
          size_(std::exchange(other.size_, 0))
#ifdef _WIN32
        , file_(std::exchange(other.file_, INVALID_HANDLE_VALUE))
        , mapping_(std::exchange(other.mapping_, nullptr))
#else
        , fd_(std::exchange(other.fd_, -1))
#endif
    {}

    MemoryMappedFile& operator=(MemoryMappedFile&& other) noexcept {
        if (this != &other) {
            // Clean up current resources
            MemoryMappedFile tmp(std::move(*this));
            // Take other's resources
            data_ = std::exchange(other.data_, nullptr);
            size_ = std::exchange(other.size_, 0);
#ifdef _WIN32
            file_ = std::exchange(other.file_, INVALID_HANDLE_VALUE);
            mapping_ = std::exchange(other.mapping_, nullptr);
#else
            fd_ = std::exchange(other.fd_, -1);
#endif
        }
        return *this;
    }

    // Non-copyable
    MemoryMappedFile(const MemoryMappedFile&) = delete;
    MemoryMappedFile& operator=(const MemoryMappedFile&) = delete;

    // Accessors
    const void* data() const noexcept { return data_; }
    std::size_t size() const noexcept { return size_; }
    std::string_view as_string() const {
        return {static_cast<const char*>(data_), size_};
    }
};

// Usage
#include <iostream>

int main() {
    try {
        MemoryMappedFile file("example.txt");
        std::cout << "Size: " << file.size() << " bytes\n";
        std::cout << "Content: " << file.as_string().substr(0, 100) << "\n";
        // File unmapped + closed automatically when file goes out of scope
    } catch (const std::exception& e) {
        std::cerr << "Error: " << e.what() << "\n";
    }
}
```

RAII handles 3 resources on Windows (file handle, mapping handle, view) and 2 on Linux (fd, mmap). Cleanup in the destructor is in reverse acquisition order. The constructor cleans up partially-acquired resources if a later step fails — this is the constructor exception safety pattern: clean up what you've acquired before propagating the exception.

`const_cast` removes or adds `const` qualification. It's the only cast that can change constness, and it's only safe when the original object was actually non-const.

```cpp
#include <iostream>
#include <string>

// LEGAL: Object was originally non-const
void legal_usage() {
    int x = 42;                     // x is non-const
    const int& cref = x;            // const view of x
    int& ref = const_cast<int&>(cref);  // Remove const — LEGAL
    ref = 100;                      // OK: x was non-const originally
    std::cout << x << "\n";         // 100
}

// UNDEFINED BEHAVIOR: Object was originally const
void ub_usage() {
    const int x = 42;               // x is truly const
    int& ref = const_cast<int&>(x); // Remove const
    // ref = 100;                   // UB! Modifying a const object
    // Compiler may have optimized x to a compile-time constant
    // The write may silently do nothing, crash, or corrupt memory
}

// PRACTICAL USE: Avoiding code duplication in const/non-const overloads
class Buffer {
    char* data_;
    std::size_t size_;

public:
    // Const version: the real implementation
    const char& at(std::size_t i) const {
        if (i >= size_) throw std::out_of_range("index");
        return data_[i];
    }

    // Non-const delegates to const version
    char& at(std::size_t i) {
        // Step 1: cast *this to const to call const overload
        // Step 2: const_cast the result to remove const
        return const_cast<char&>(
            static_cast<const Buffer&>(*this).at(i)
        );
        // LEGAL: *this is non-const (this function is non-const)
        // So the underlying data_[i] is non-const
    }
};

// PRACTICAL USE: Calling legacy C APIs that aren't const-correct
extern "C" {
    // Old C function that doesn't modify str but forgot const
    int c_strlen(char* str);  // Should be const char*
}

void call_legacy(const std::string& s) {
    // We know c_strlen doesn't modify the string
    int len = c_strlen(const_cast<char*>(s.c_str()));
    // LEGAL: s.c_str() points to non-const storage internally
    // (string owns mutable buffer, const is just the API contract)
}

// NEVER DO THIS:
void dangerous() {
    const std::string s = "immutable";
    // const_cast<std::string&>(s).clear();  // UB!
    // s lives in read-only memory potentially

    // Also UB: casting away const on string literals
    // char* p = const_cast<char*>("hello");
    // p[0] = 'H';  // UB: string literals are const
}
```

**Rules for safe `const_cast`:**
1. The original object must be **non-const** (or mutable member)
2. You're just removing a const view that was added along the way
3. Never modify through a const_cast if the object was declared const
4. Never const_cast string literals or static const data
5. Prefer `mutable` keyword over const_cast for internal state (caches, mutexes)
6. The main legitimate use is the const/non-const overload delegation pattern

```cpp
#include <iostream>
#include <string>
#include <mutex>
#include <thread>
#include <vector>

// Meyers' Singleton — the modern C++ way
class Config {
public:
    static Config& instance() {
        static Config cfg;  // Thread-safe since C++11
        return cfg;
        // Guaranteed:
        // 1. Constructed exactly once, on first call
        // 2. Thread-safe initialization (compiler inserts hidden mutex)
        // 3. Destroyed at program exit in reverse construction order
    }

    // Non-copyable, non-movable
    Config(const Config&) = delete;
    Config& operator=(const Config&) = delete;
    Config(Config&&) = delete;
    Config& operator=(Config&&) = delete;

    // Thread-safe access (internal mutex for mutable state)
    std::string get(const std::string& key) const {
        std::lock_guard<std::mutex> lock(mutex_);
        auto it = data_.find(key);
        return it != data_.end() ? it->second : "";
    }

    void set(const std::string& key, const std::string& value) {
        std::lock_guard<std::mutex> lock(mutex_);
        data_[key] = value;
    }

private:
    Config() {
        std::cout << "Config initialized\n";
        data_["version"] = "1.0";
    }

    ~Config() {
        std::cout << "Config destroyed\n";
    }

    mutable std::mutex mutex_;
    std::unordered_map<std::string, std::string> data_;
};

// Why this is superior to the alternatives:

// BAD: Double-checked locking (pre-C++11 pattern)
class BadSingleton {
    static BadSingleton* instance_;
    static std::mutex mutex_;
public:
    static BadSingleton& instance() {
        if (!instance_) {  // First check (no lock)
            std::lock_guard<std::mutex> lock(mutex_);
            if (!instance_) {  // Second check (with lock)
                instance_ = new BadSingleton();  // Leak! Never deleted.
            }
        }
        return *instance_;
    }
};
// Problems: potential memory leak, undefined destruction order,
// was broken before C++11 memory model

// BETTER BUT UNNECESSARY: unique_ptr + call_once
class OverEngineered {
    static std::unique_ptr<OverEngineered> instance_;
    static std::once_flag flag_;
public:
    static OverEngineered& instance() {
        std::call_once(flag_, [] {
            instance_ = std::make_unique<OverEngineered>();
        });
        return *instance_;
    }
};
// Works, but Meyers' singleton does the same thing with less code

int main() {
    // Thread-safe concurrent access
    std::vector<std::thread> threads;
    for (int i = 0; i < 10; ++i) {
        threads.emplace_back([i] {
            Config::instance().set("key" + std::to_string(i),
                                  "val" + std::to_string(i));
        });
    }
    for (auto& t : threads) t.join();

    std::cout << Config::instance().get("key5") << "\n";
    // Config destroyed automatically at program exit
}
```

Meyers' Singleton guarantees:
- **Thread-safe construction**: C++11 standard (§6.7) guarantees that static local variable initialization is thread-safe
- **Lazy initialization**: Only constructed on first use
- **Deterministic destruction**: Destroyed at program exit, in reverse order of construction
- **No heap allocation**: Lives in static storage
- **No manual cleanup**: RAII via the compiler-generated static destructor

The only caveat: static destruction order fiasco. If singleton A's destructor uses singleton B, and B is destroyed first, you get undefined behavior. Solution: avoid using singletons in destructors of other singletons.

```cpp
#include <mutex>
#include <shared_mutex>
#include <condition_variable>
#include <iostream>
#include <thread>

std::mutex m1, m2;
std::shared_mutex sm;
std::condition_variable cv;
bool ready = false;

// 1. lock_guard — simplest, lightest, scoped lock
void use_lock_guard() {
    std::lock_guard<std::mutex> lock(m1);
    // Locked on construction, unlocked on destruction
    // Cannot: unlock early, defer locking, move, use with condition_variable
    // Use for: simple scoped locking with no special requirements
}

// 2. unique_lock — flexible, movable, works with condition_variable
void use_unique_lock() {
    // a) Normal usage
    std::unique_lock<std::mutex> lock(m1);
    // Can unlock/relock:
    lock.unlock();
    // ... do unprotected work ...
    lock.lock();

    // b) Deferred locking
    std::unique_lock<std::mutex> deferred(m1, std::defer_lock);
    // Not locked yet
    deferred.lock();  // Lock when ready

    // c) Try-lock
    std::unique_lock<std::mutex> trying(m1, std::try_to_lock);
    if (trying.owns_lock()) {
        // Got the lock
    }

    // d) Condition variable (REQUIRES unique_lock)
    std::unique_lock<std::mutex> cv_lock(m1);
    cv.wait(cv_lock, [] { return ready; });
    // cv.wait unlocks the mutex while waiting, relocks on wake
    // lock_guard can't do this because it can't unlock

    // e) Movable — transfer lock ownership
    std::unique_lock<std::mutex> lock2 = std::move(cv_lock);
    // cv_lock no longer owns the lock
}

// 3. scoped_lock — multi-mutex, deadlock-free (C++17)
void use_scoped_lock() {
    // Locks m1 AND m2 atomically, no deadlock possible
    std::scoped_lock lock(m1, m2);
    // Equivalent to: std::lock(m1, m2) + adopt both
    // Cannot: unlock early, defer, move, use with condition_variable

    // Single mutex: identical to lock_guard
    std::scoped_lock single(m1);

    // Zero mutexes: valid no-op (useful in templates)
    std::scoped_lock<> nothing;
}

// 4. shared_lock — reader lock for shared_mutex (C++17)
void use_shared_lock() {
    // Multiple readers can hold shared_lock simultaneously
    std::shared_lock<std::shared_mutex> read_lock(sm);
    // Read shared data...

    // Writer uses unique_lock or scoped_lock for exclusive access
    // std::unique_lock<std::shared_mutex> write_lock(sm);
}
```

**Decision table:**

| Need | Use |
|------|-----|
| Simple scoped lock, one mutex | `scoped_lock` (C++17) or `lock_guard` |
| Lock multiple mutexes at once | `scoped_lock(m1, m2, ...)` |
| Condition variable | `unique_lock` (required) |
| Unlock/relock mid-scope | `unique_lock` |
| Try-lock | `unique_lock` with `try_to_lock` |
| Defer locking | `unique_lock` with `defer_lock` |
| Transfer lock ownership | `unique_lock` (movable) |
| Reader/writer lock | `shared_lock` (read) + `unique_lock` (write) |

**In modern C++17 code:**
- Default to `scoped_lock` for all simple locking
- Use `unique_lock` only when you need its flexibility (condition variables, deferred/try locking)
- `lock_guard` is effectively superseded by `scoped_lock` but still valid

```cpp
#include <utility>
#include <string>
#include <vector>
#include <algorithm>

class Widget {
    std::string name_;
    std::vector<int> data_;
    int* raw_ = nullptr;  // Raw resource for demonstration

public:
    Widget(std::string name, std::vector<int> data)
        : name_(std::move(name)), data_(std::move(data)),
          raw_(new int(42)) {}

    ~Widget() { delete raw_; }

    // noexcept swap — THE foundation of exception safety
    friend void swap(Widget& a, Widget& b) noexcept {
        using std::swap;
        swap(a.name_, b.name_);   // string::swap is noexcept
        swap(a.data_, b.data_);   // vector::swap is noexcept
        swap(a.raw_, b.raw_);     // pointer swap is noexcept
    }

    // Copy-and-swap assignment (relies on noexcept swap)
    Widget(const Widget& other)
        : name_(other.name_), data_(other.data_),
          raw_(other.raw_ ? new int(*other.raw_) : nullptr) {}

    Widget(Widget&& other) noexcept
        : name_(std::move(other.name_)),
          data_(std::move(other.data_)),
          raw_(std::exchange(other.raw_, nullptr)) {}

    Widget& operator=(Widget other) noexcept {  // by value
        swap(*this, other);  // noexcept swap is critical here
        return *this;
    }
};
```

**Why `noexcept` on swap matters:**

1. **Exception safety guarantee chain:**
```
copy-and-swap assignment is strongly exception-safe
    BECAUSE swap is noexcept
    BECAUSE each member swap is noexcept

If swap could throw:
    Widget& operator=(Widget other) noexcept {  // <-- can't be noexcept!
        swap(*this, other);  // If this throws, *this is corrupted
        // Neither old nor new state — basic guarantee at best
    }
```

2. **move_if_noexcept relies on it:**
```cpp
// std::vector reallocation uses:
std::move_if_noexcept(element)

// If Widget's move (which may use swap) isn't noexcept:
//   vector copies instead of moving → O(n) vs O(1) per element
```

3. **Compiler optimizations:**
```cpp
// noexcept lets the compiler skip exception handling infrastructure:
void foo() noexcept {
    // No need for stack unwinding tables
    // No need for exception handler frames
    // Smaller binary, faster code
}

// If a noexcept function throws, std::terminate() is called immediately
// — no unwinding, no destructors. This is a feature: it's a hard contract.
```

4. **Generic code uses `noexcept` in type traits:**
```cpp
static_assert(std::is_nothrow_swappable_v<Widget>);
static_assert(std::is_nothrow_move_constructible_v<Widget>);
static_assert(std::is_nothrow_move_assignable_v<Widget>);
// These traits are checked by containers, algorithms, and other templates
// to decide between copy and move
```

**Rule: swap must ALWAYS be noexcept.** If your swap calls something that might throw, restructure your type so swap only exchanges pointers and scalars. This is always possible — store resources behind pointers (or smart pointers) and swap the pointers.

The classic exception-safe stack problem: `std::stack::pop()` returns void because combining removal + return can't be strongly exception-safe. Here's a stack that provides both safety and convenience.

```cpp
#include <vector>
#include <stdexcept>
#include <optional>
#include <utility>

template <typename T>
class SafeStack {
    std::vector<T> data_;

public:
    // push: strong guarantee
    void push(const T& value) {
        data_.push_back(value);  // If vector realloc throws:
        //   data_ is unchanged (vector provides strong guarantee)
    }

    void push(T&& value) {
        data_.push_back(std::move(value));
    }

    template <typename... Args>
    void emplace(Args&&... args) {
        data_.emplace_back(std::forward<Args>(args)...);
    }

    // Why std::stack::pop() returns void:
    // If pop returned T by value, and T's copy constructor threw,
    // the element would already be removed — data lost.
    // Separating top() and pop() avoids this.

    const T& top() const {
        if (data_.empty()) throw std::out_of_range("empty stack");
        return data_.back();
    }

    void pop() {
        if (data_.empty()) throw std::out_of_range("empty stack");
        data_.pop_back();  // noexcept (destructor + size decrement)
    }

    // Safe combined pop: returns optional, moves the value out
    std::optional<T> try_pop() {
        if (data_.empty()) return std::nullopt;
        std::optional<T> result(std::move(data_.back()));  // Move, not copy
        data_.pop_back();  // noexcept
        return result;  // RVO or move
    }

    bool empty() const noexcept { return data_.empty(); }
    std::size_t size() const noexcept { return data_.size(); }
};

int main() {
    SafeStack<std::string> stack;
    stack.push("hello");
    stack.emplace("world");

    while (auto val = stack.try_pop()) {
        std::cout << *val << "\n";
    }
}
```

`try_pop` is safe because:
1. `std::move(data_.back())` — if T's move constructor throws, data_.back() is still in the vector (in moved-from state, but the element isn't removed yet)
2. `data_.pop_back()` — noexcept, only runs after the move succeeded
3. Return — RVO typically eliminates the optional move

```cpp
#include <memory>
#include <functional>
#include <stdexcept>
#include <iostream>
#include <thread>
#include <chrono>

// Simulated connection
struct Connection {
    std::string endpoint;
    bool connected = false;

    void connect(const std::string& ep) {
        endpoint = ep;
        // Simulate intermittent failure
        static int attempt = 0;
        if (++attempt % 3 != 0)
            throw std::runtime_error("Connection refused: " + ep);
        connected = true;
        std::cout << "Connected to " << ep << "\n";
    }

    void disconnect() {
        if (connected) {
            std::cout << "Disconnected from " << endpoint << "\n";
            connected = false;
        }
    }

    void query(const std::string& q) {
        if (!connected) throw std::runtime_error("Not connected");
        std::cout << "Query: " << q << "\n";
    }
};

class ManagedConnection {
    std::unique_ptr<Connection> conn_;
    int max_retries_;

public:
    ManagedConnection(const std::string& endpoint, int retries = 3)
        : conn_(std::make_unique<Connection>()), max_retries_(retries) {
        for (int i = 1; i <= max_retries_; ++i) {
            try {
                conn_->connect(endpoint);
                return;  // Success
            } catch (const std::exception& e) {
                std::cout << "Attempt " << i << "/" << max_retries_
                          << " failed: " << e.what() << "\n";
                if (i == max_retries_) throw;  // Re-throw on final failure
                std::this_thread::sleep_for(std::chrono::milliseconds(100 * i));
            }
        }
    }

    ~ManagedConnection() {
        if (conn_) conn_->disconnect();  // RAII: always disconnect
    }

    // Move-only
    ManagedConnection(ManagedConnection&&) = default;
    ManagedConnection& operator=(ManagedConnection&&) = default;
    ManagedConnection(const ManagedConnection&) = delete;
    ManagedConnection& operator=(const ManagedConnection&) = delete;

    Connection& operator*() { return *conn_; }
    Connection* operator->() { return conn_.get(); }
};

int main() {
    try {
        ManagedConnection conn("db://localhost:5432");
        conn->query("SELECT 1");
        // Automatically disconnected when conn goes out of scope
    } catch (const std::exception& e) {
        std::cerr << "Failed after all retries: " << e.what() << "\n";
    }
}
```

Key design points:
- Constructor does all retry logic — if it succeeds, the connection is guaranteed valid
- If all retries fail, the constructor throws — no half-initialized object
- Destructor calls disconnect unconditionally (RAII cleanup)
- Move-only semantics prevent accidental connection sharing
- unique_ptr member gives us Rule-of-Zero move operations

Init-capture (C++14) lets you move or transform values into a lambda's capture. Combined with `std::forward`, it enables perfect forwarding into lambdas.

```cpp
#include <utility>
#include <memory>
#include <string>
#include <iostream>
#include <functional>
#include <tuple>

// 1. Basic init-capture: move a unique_ptr into lambda
void basic_init_capture() {
    auto ptr = std::make_unique<std::string>("owned");

    // Can't capture unique_ptr by copy — use init-capture to move
    auto fn = [p = std::move(ptr)]() {
        std::cout << *p << "\n";
    };
    // ptr is null now — ownership transferred to lambda
    fn();
}

// 2. Perfect forwarding into a lambda
template <typename F, typename... Args>
auto defer(F&& f, Args&&... args) {
    // Capture function and args by move/copy as appropriate
    return [f = std::forward<F>(f),
            ...captured = std::forward<Args>(args)]() mutable {
        return f(std::move(captured)...);
    };
}

// 3. Pre-C++20 (no pack init-capture): use tuple
template <typename F, typename... Args>
auto defer_legacy(F&& f, Args&&... args) {
    auto bound_args = std::make_tuple(std::forward<Args>(args)...);
    return [f = std::forward<F>(f),
            args = std::move(bound_args)]() mutable {
        return std::apply(f, std::move(args));
    };
}

// 4. Capturing *this by value (C++17)
class Timer {
    std::string name_;
    int duration_;

public:
    Timer(std::string name, int ms) : name_(std::move(name)), duration_(ms) {}

    auto make_callback() {
        // Captures a COPY of the entire Timer object
        return [*this]() {
            std::cout << name_ << ": " << duration_ << "ms\n";
        };
        // Safe even if the Timer is destroyed before callback runs
    }

    auto make_callback_ref() {
        // Captures pointer to this — DANGEROUS if Timer is destroyed
        return [this]() {
            std::cout << name_ << ": " << duration_ << "ms\n";
        };
    }
};

int main() {
    basic_init_capture();

    // defer: forward string literal (const char*) and int
    auto task1 = defer([](std::string s, int n) {
        std::cout << s << " x" << n << "\n";
    }, std::string("hello"), 3);
    task1();  // "hello x3"

    // Safe callback from temporary
    auto cb = Timer("render", 16).make_callback();  // Timer destroyed
    cb();  // Still works — callback has its own copy
}
```

Key patterns:
- `[x = std::move(y)]`: Move into capture (unique_ptr, large objects)
- `[x = expr]`: Compute at capture time, store result
- `[*this]`: Copy entire object (C++17) — safe for async callbacks
- `[...args = std::forward<Args>(args)]`: Pack init-capture (C++20)
- Always use `mutable` on lambdas that consume captured move-only types

`std::function` requires copyable callables, which prevents storing lambdas that capture `unique_ptr`. Here's a move-only alternative:

```cpp
#include <memory>
#include <utility>
#include <type_traits>
#include <iostream>

template <typename Signature>
class unique_function;  // Primary template (undefined)

template <typename Ret, typename... Args>
class unique_function<Ret(Args...)> {
    // Type-erased callable holder
    struct concept_t {
        virtual ~concept_t() = default;
        virtual Ret invoke(Args... args) = 0;
    };

    template <typename F>
    struct model_t final : concept_t {
        F fn;
        template <typename Fwd>
        model_t(Fwd&& f) : fn(std::forward<Fwd>(f)) {}
        Ret invoke(Args... args) override {
            return fn(std::forward<Args>(args)...);
        }
    };

    std::unique_ptr<concept_t> impl_;  // Move-only!

public:
    unique_function() = default;
    unique_function(std::nullptr_t) noexcept {}

    template <typename F,
              typename = std::enable_if_t<!std::is_same_v<std::decay_t<F>, unique_function>>>
    unique_function(F&& f)
        : impl_(std::make_unique<model_t<std::decay_t<F>>>(std::forward<F>(f))) {}

    // Move-only
    unique_function(unique_function&&) noexcept = default;
    unique_function& operator=(unique_function&&) noexcept = default;
    unique_function(const unique_function&) = delete;
    unique_function& operator=(const unique_function&) = delete;

    Ret operator()(Args... args) {
        if (!impl_) throw std::bad_function_call();
        return impl_->invoke(std::forward<Args>(args)...);
    }

    explicit operator bool() const noexcept { return impl_ != nullptr; }
};

// Usage: store move-only lambdas
int main() {
    auto ptr = std::make_unique<int>(42);

    // std::function<void()> f = [p = std::move(ptr)]() {};  // ERROR: not copyable

    unique_function<void()> f = [p = std::move(ptr)]() {
        std::cout << "Value: " << *p << "\n";
    };

    f();  // "Value: 42"

    // Can be moved into containers
    std::vector<unique_function<void()>> tasks;
    tasks.push_back(std::move(f));

    // Transfer ownership of task
    auto task = std::move(tasks.back());
    tasks.pop_back();
    task();
}
```

This is essentially what C++23's `std::move_only_function` does. The key is using `unique_ptr` for the type-erased storage — since `unique_ptr` is move-only, the entire `unique_function` becomes move-only automatically (Rule of Zero). No virtual copy needed, no `shared_ptr` overhead.

```cpp
#include <utility>
#include <variant>
#include <string>
#include <iostream>
#include <memory>
#include <optional>

// States as distinct types
struct Idle {};
struct Connecting {
    std::string endpoint;
    int timeout_ms;
};
struct Connected {
    std::unique_ptr<int> socket;  // Move-only resource
    std::string endpoint;
};
struct Error {
    std::string message;
};

using State = std::variant<Idle, Connecting, Connected, Error>;

class NetworkClient {
    State state_ = Idle{};

public:
    // Transition: Idle -> Connecting
    void connect(std::string endpoint, int timeout_ms = 5000) {
        auto prev = std::exchange(state_,
            Connecting{std::move(endpoint), timeout_ms});
        // prev holds old state — can inspect or log it
        if (!std::holds_alternative<Idle>(prev)) {
            // Revert if not in valid starting state
            state_ = std::move(prev);
            throw std::logic_error("Can only connect from Idle");
        }
        std::cout << "Connecting...\n";
    }

    // Transition: Connecting -> Connected
    void on_connected(std::unique_ptr<int> socket) {
        auto prev = std::exchange(state_, Idle{});  // Temporary
        if (auto* c = std::get_if<Connecting>(&prev)) {
            state_ = Connected{
                std::move(socket),
                std::move(c->endpoint)  // Move endpoint from old state
            };
            std::cout << "Connected!\n";
        } else {
            state_ = std::move(prev);  // Revert
            throw std::logic_error("Not connecting");
        }
    }

    // Transition: Connected -> Idle (cleanup via move)
    void disconnect() {
        auto prev = std::exchange(state_, Idle{});
        if (auto* c = std::get_if<Connected>(&prev)) {
            std::cout << "Disconnecting from " << c->endpoint << "\n";
            // c->socket destroyed here when prev goes out of scope
            // RAII: socket cleaned up automatically
        }
    }

    // Transition: Any -> Error
    void on_error(std::string msg) {
        auto prev = std::exchange(state_, Error{std::move(msg)});
        // Old state (including any owned resources) destroyed
        // when prev goes out of scope
    }

    std::string status() const {
        return std::visit([](const auto& s) -> std::string {
            using T = std::decay_t<decltype(s)>;
            if constexpr (std::is_same_v<T, Idle>) return "idle";
            if constexpr (std::is_same_v<T, Connecting>) return "connecting to " + s.endpoint;
            if constexpr (std::is_same_v<T, Connected>) return "connected to " + s.endpoint;
            if constexpr (std::is_same_v<T, Error>) return "error: " + s.message;
        }, state_);
    }
};

int main() {
    NetworkClient client;
    std::cout << client.status() << "\n";  // idle

    client.connect("api.example.com");
    std::cout << client.status() << "\n";  // connecting to api.example.com

    client.on_connected(std::make_unique<int>(42));
    std::cout << client.status() << "\n";  // connected to api.example.com

    client.disconnect();
    std::cout << client.status() << "\n";  // idle
    // Socket was automatically closed via unique_ptr destructor
}
```

`std::exchange` is the key: it atomically replaces the state and returns the old one. This means:
- Old resources (sockets, connections) are cleaned up by RAII when `prev` goes out of scope
- State transitions can be validated and reverted
- Move-only resources (unique_ptr) transfer cleanly between states

```cpp
#include <type_traits>
#include <string>
#include <iostream>
#include <vector>

// constexpr if selects code paths at compile time based on type traits
template <typename T>
class SmartBuffer {
    T data_;

public:
    explicit SmartBuffer(T data) : data_(std::move(data)) {}

    // const member function with constexpr if
    auto summary() const {
        if constexpr (std::is_arithmetic_v<T>) {
            // For numeric types: return the value directly
            return data_;
        } else if constexpr (std::is_same_v<T, std::string>) {
            // For strings: return size info
            return "string[" + std::to_string(data_.size()) + "]";
        } else {
            // For containers: return element count
            return static_cast<std::size_t>(data_.size());
        }
    }

    // const-correct access with different behavior per type
    decltype(auto) get() const {
        if constexpr (std::is_pointer_v<T>) {
            return static_cast<const std::remove_pointer_t<T>*>(data_);
            // Returns pointer-to-const for pointer types
        } else {
            return (data_);  // Returns const T& (parentheses preserve ref)
        }
    }

    // Non-const overload
    decltype(auto) get() {
        if constexpr (std::is_pointer_v<T>) {
            return data_;  // Returns raw pointer (mutable)
        } else {
            return (data_);  // Returns T&
        }
    }
};

// Using const propagation with constexpr if in free functions
template <typename Container>
void process(const Container& c) {
    if constexpr (requires { c.reserve(0); }) {
        // Has reserve — it's a vector-like container
        std::cout << "vector-like, size=" << c.size() << "\n";
    } else if constexpr (requires { c.find(typename Container::key_type{}); }) {
        // Has find — it's an associative container
        std::cout << "associative, size=" << c.size() << "\n";
    } else {
        std::cout << "unknown container\n";
    }
    // Only the matching branch is compiled — others are discarded
    // const Container& ensures we only call const member functions
}

// Combining with SFINAE replacement
template <typename T>
auto serialize(const T& value) {
    if constexpr (requires { value.to_json(); }) {
        return value.to_json();
    } else if constexpr (std::is_arithmetic_v<T>) {
        return std::to_string(value);
    } else if constexpr (std::is_convertible_v<T, std::string>) {
        return std::string(value);
    } else {
        static_assert(sizeof(T) == 0, "No serializer for this type");
    }
}

int main() {
    SmartBuffer<int> ib(42);
    SmartBuffer<std::string> sb(std::string("hello"));

    std::cout << ib.summary() << "\n";  // 42
    std::cout << sb.summary() << "\n";  // string[5]

    const SmartBuffer<int> cib(99);
    // cib.get() returns const int& (const member function)
    std::cout << cib.get() << "\n";  // 99

    process(std::vector<int>{1, 2, 3});
    process(std::map<int, int>{{1, 2}});
}
```

`constexpr if` replaced most SFINAE and tag-dispatch patterns in modern C++. The key interaction with const:
- Discarded branches aren't compiled, so you can write code that wouldn't be valid for all types
- const member functions + constexpr if let you provide different const behavior per type
- `decltype(auto)` preserves constness through the return path

```cpp
#include <memory>
#include <algorithm>
#include <utility>
#include <cstddef>
#include <iostream>

template <typename T, typename Alloc = std::allocator<T>>
class SimpleVec {
    using AllocTraits = std::allocator_traits<Alloc>;

    T* data_ = nullptr;
    std::size_t size_ = 0;
    std::size_t cap_ = 0;
    [[no_unique_address]] Alloc alloc_;

public:
    explicit SimpleVec(const Alloc& a = Alloc{}) : alloc_(a) {}

    ~SimpleVec() {
        clear();
        if (data_) AllocTraits::deallocate(alloc_, data_, cap_);
    }

    // Copy constructor: uses allocator propagation traits
    SimpleVec(const SimpleVec& other)
        : alloc_(AllocTraits::select_on_container_copy_construction(other.alloc_)) {
        reserve(other.size_);
        for (std::size_t i = 0; i < other.size_; ++i)
            AllocTraits::construct(alloc_, data_ + i, other.data_[i]);
        size_ = other.size_;
    }

    // Move constructor: steal allocator and data
    SimpleVec(SimpleVec&& other) noexcept
        : data_(std::exchange(other.data_, nullptr)),
          size_(std::exchange(other.size_, 0)),
          cap_(std::exchange(other.cap_, 0)),
          alloc_(std::move(other.alloc_)) {}

    // Move assignment: must check if allocators are compatible
    SimpleVec& operator=(SimpleVec&& other) noexcept {
        if (this == &other) return *this;

        clear();
        if (data_) AllocTraits::deallocate(alloc_, data_, cap_);

        if constexpr (AllocTraits::propagate_on_container_move_assignment::value) {
            // Take their allocator — can steal their buffer
            alloc_ = std::move(other.alloc_);
            data_ = std::exchange(other.data_, nullptr);
            size_ = std::exchange(other.size_, 0);
            cap_ = std::exchange(other.cap_, 0);
        } else if (alloc_ == other.alloc_) {
            // Same allocator instance — can steal buffer
            data_ = std::exchange(other.data_, nullptr);
            size_ = std::exchange(other.size_, 0);
            cap_ = std::exchange(other.cap_, 0);
        } else {
            // Different, non-propagating allocators — must element-wise move
            data_ = nullptr;
            cap_ = 0;
            size_ = 0;
            reserve(other.size_);
            for (std::size_t i = 0; i < other.size_; ++i)
                AllocTraits::construct(alloc_, data_ + i, std::move(other.data_[i]));
            size_ = other.size_;
        }
        return *this;
    }

    void reserve(std::size_t new_cap) {
        if (new_cap <= cap_) return;
        T* new_data = AllocTraits::allocate(alloc_, new_cap);
        for (std::size_t i = 0; i < size_; ++i) {
            AllocTraits::construct(alloc_, new_data + i, std::move(data_[i]));
            AllocTraits::destroy(alloc_, data_ + i);
        }
        if (data_) AllocTraits::deallocate(alloc_, data_, cap_);
        data_ = new_data;
        cap_ = new_cap;
    }

    template <typename... Args>
    void emplace_back(Args&&... args) {
        if (size_ == cap_) reserve(cap_ == 0 ? 4 : cap_ * 2);
        AllocTraits::construct(alloc_, data_ + size_, std::forward<Args>(args)...);
        ++size_;
    }

    void clear() {
        for (std::size_t i = 0; i < size_; ++i)
            AllocTraits::destroy(alloc_, data_ + i);
        size_ = 0;
    }

    std::size_t size() const { return size_; }
    T& operator[](std::size_t i) { return data_[i]; }
    const T& operator[](std::size_t i) const { return data_[i]; }
};
```

Key move semantics interactions with allocators:
1. **Move constructor**: Always steals the allocator and buffer (allocators must be movable)
2. **Move assignment**: Three cases based on allocator propagation traits:
   - `propagate_on_container_move_assignment = true`: Take allocator, steal buffer
   - Same allocator: Steal buffer directly
   - Different allocators: Must element-wise move (can't transfer memory between different allocators)
3. **`[[no_unique_address]]`**: Stateless allocators (like `std::allocator`) take zero space
4. **`allocator_traits::construct/destroy`**: Always use traits, never direct placement new/destructor calls — supports fancy pointers and custom construction

```cpp
#include <memory>
#include <iostream>
#include <string>

struct Widget {
    std::string name;
    Widget(std::string n) : name(std::move(n)) {}
    ~Widget() { std::cout << "~Widget(" << name << ")\n"; }
};

// 1. By value: SINK — function takes ownership
void consume(std::unique_ptr<Widget> w) {
    std::cout << "Consuming: " << w->name << "\n";
    // w destroyed at end of function
}

// 2. By non-const reference: function MAY take ownership
void maybe_take(std::unique_ptr<Widget>& w) {
    if (w->name == "steal-me") {
        auto taken = std::move(w);  // w is now null
        std::cout << "Stole: " << taken->name << "\n";
    } else {
        std::cout << "Left: " << w->name << "\n";
    }
}

// 3. By const reference: function observes the pointer (DON'T DO THIS)
void bad_observe(const std::unique_ptr<Widget>& w) {
    std::cout << "Observing: " << w->name << "\n";
    // Can't move from const ref, can only read
    // But WHY pass unique_ptr? You only need the Widget!
}

// 4. CORRECT observation: pass the object, not the smart pointer
void observe(const Widget& w) {
    std::cout << "Observing: " << w.name << "\n";
}

// 5. By rvalue reference: explicit move semantics (rare, prefer by value)
void explicit_sink(std::unique_ptr<Widget>&& w) {
    // Caller wrote std::move(w), but w is still valid here until we move it
    auto local = std::move(w);  // Actually takes ownership
    std::cout << "Explicit: " << local->name << "\n";
    // Difference from by-value: if we DON'T move, caller keeps ownership!
}

int main() {
    // Sink: caller must use std::move — clear transfer signal
    auto w1 = std::make_unique<Widget>("alpha");
    consume(std::move(w1));  // w1 is null after this
    // consume(w1);          // ERROR: unique_ptr not copyable

    // Maybe-take: unclear ownership — use sparingly
    auto w2 = std::make_unique<Widget>("steal-me");
    maybe_take(w2);
    std::cout << "w2 is " << (w2 ? "valid" : "null") << "\n";  // null

    // Observation: pass the object, not the pointer
    auto w3 = std::make_unique<Widget>("beta");
    observe(*w3);  // Dereference: pass Widget&
    // w3 still valid
}
```

**Decision table:**

| Signature | Meaning | When to use |
|-----------|---------|-------------|
| `f(unique_ptr<T> p)` | "I take ownership" | Sinks, stores, transfers |
| `f(unique_ptr<T>& p)` | "I might take ownership" | Reseat, conditional take (rare) |
| `f(const unique_ptr<T>& p)` | "I observe the pointer" | Almost never — use `f(const T&)` instead |
| `f(unique_ptr<T>&& p)` | "Move required but optional take" | Rarely needed — prefer by value |
| `f(const T&)` or `f(T*)` | "I observe the object" | Most common — decouples from ownership |

Herb Sutter's rule: "Don't pass smart pointers unless you're dealing with ownership. If the function doesn't participate in ownership, it should take `T&`, `const T&`, or `T*`."

```cpp
#include <utility>
#include <iostream>
#include <cstdio>

// RAII defer implementation
template <typename F>
class DeferGuard {
    F fn_;
    bool active_;
public:
    explicit DeferGuard(F f) noexcept : fn_(std::move(f)), active_(true) {}
    ~DeferGuard() { if (active_) fn_(); }
    DeferGuard(DeferGuard&& o) noexcept
        : fn_(std::move(o.fn_)), active_(std::exchange(o.active_, false)) {}
    DeferGuard(const DeferGuard&) = delete;
    DeferGuard& operator=(const DeferGuard&) = delete;
    DeferGuard& operator=(DeferGuard&&) = delete;
};

template <typename F>
DeferGuard<F> make_defer(F&& f) {
    return DeferGuard<F>(std::forward<F>(f));
}

// Macro for anonymous variable names
#define DEFER_CONCAT_(a, b) a##b
#define DEFER_CONCAT(a, b) DEFER_CONCAT_(a, b)
#define defer(code) auto DEFER_CONCAT(_defer_, __LINE__) = make_defer([&]() { code; })

// Usage: exactly like Go's defer
void process_file(const char* path) {
    FILE* f = fopen(path, "r");
    if (!f) return;
    defer(fclose(f));  // Guaranteed to run on scope exit

    char* buffer = (char*)malloc(4096);
    defer(free(buffer));  // Second defer: freed after fclose

    // Stack multiple defers — execute in reverse order (LIFO)
    defer(std::cout << "step 3: done\n");
    defer(std::cout << "step 2: cleanup\n");
    defer(std::cout << "step 1: finish\n");

    // Do work...
    fread(buffer, 1, 4096, f);
    std::cout << "Processing...\n";

    // On scope exit (normal or exception):
    // step 1: finish
    // step 2: cleanup
    // step 3: done
    // free(buffer)
    // fclose(f)
}

// Alternative: named defer for conditional dismiss
void transactional() {
    auto guard = make_defer([]{ std::cout << "ROLLBACK\n"; });

    // Do risky operations...
    bool success = true;

    if (success) {
        // Dismiss the rollback — we succeeded
        // (Requires dismiss() method from earlier scope_guard)
    }
}

int main() {
    process_file("/dev/null");
}
```

The `defer` macro creates a uniquely-named local variable (using `__LINE__` for uniqueness) whose destructor runs the cleanup lambda. This gives C++ the same ergonomics as Go's `defer` with additional benefits:
- Type-safe (lambda, not void pointer)
- Scope-based (not function-based like Go)
- LIFO ordering guaranteed by C++ destruction rules
- Exception-safe (destructors run during stack unwinding)
- Zero overhead (lambda inlined, no allocation)

The aliasing constructor of `shared_ptr` creates a `shared_ptr` that shares ownership (refcount) with another `shared_ptr` but points to a different object. This enables powerful patterns.

```cpp
#include <memory>
#include <iostream>
#include <string>

// Pattern 1: Point to a sub-object while keeping parent alive
struct Player {
    std::string name;
    int health;
    struct Inventory {
        int gold;
        int items;
    } inventory;
};

void use_subobject() {
    auto player = std::make_shared<Player>();
    player->name = "Hero";
    player->inventory.gold = 100;

    // Aliasing: points to inventory, but keeps entire Player alive
    std::shared_ptr<Player::Inventory> inv(player, &player->inventory);

    player.reset();  // Release our reference
    // Player is NOT destroyed — inv still holds a reference

    std::cout << "Gold: " << inv->gold << "\n";  // Safe!
    // Player destroyed when inv goes out of scope
}

// Pattern 2: Type-erased handle with custom release
class TextureHandle {
    struct GPU {
        static int alloc(const std::string& name) {
            std::cout << "GPU alloc: " << name << "\n";
            return 42;  // fake GPU handle
        }
        static void free(int handle) {
            std::cout << "GPU free: " << handle << "\n";
        }
    };

    std::shared_ptr<int> handle_;

public:
    TextureHandle(const std::string& name) {
        int* raw = new int(GPU::alloc(name));
        handle_ = std::shared_ptr<int>(raw, [](int* p) {
            GPU::free(*p);
            delete p;
        });
    }

    int id() const { return *handle_; }
    long refs() const { return handle_.use_count(); }
    // Copy = shared GPU texture (refcount++, no GPU realloc)
    // Last copy destroyed = GPU::free called
};

// Pattern 3: Shared ownership with different views
struct Matrix {
    double data[16];
    int rows, cols;
};

class MatrixView {
    std::shared_ptr<double> data_;  // Shares ownership of Matrix
    int rows_, cols_, stride_;

public:
    // View into an existing matrix — keeps matrix alive
    MatrixView(std::shared_ptr<Matrix> m, int row_start, int row_count)
        : data_(m, m->data + row_start * m->cols),  // Aliasing!
          rows_(row_count), cols_(m->cols), stride_(m->cols) {}

    double operator()(int r, int c) const {
        return data_.get()[r * stride_ + c];
    }
};

int main() {
    use_subobject();

    // Shared GPU textures
    TextureHandle t1("grass");
    TextureHandle t2 = t1;  // Shares GPU handle (refcount=2)
    std::cout << "refs: " << t1.refs() << "\n";  // 2
    t1 = TextureHandle("stone");  // Old texture: refcount 2->1
    // "grass" freed when t2 destroyed
}
```

The aliasing constructor signature:
```cpp
template <typename Y>
shared_ptr(const shared_ptr<Y>& owner, T* ptr) noexcept;
```

- `owner`: provides the reference count (keeps underlying object alive)
- `ptr`: what this shared_ptr actually points to (can be anything)
- Both share the same control block

Use cases:
- Sub-object references that keep parent alive
- Non-owning views with lifetime guarantee
- GPU/OS handles with custom release semantics
- Type-erased shared ownership

```cpp
#include <vector>
#include <iostream>
#include <algorithm>
#include <string>

class Playlist {
    std::vector<std::string> songs_;

public:
    void add(std::string song) { songs_.push_back(std::move(song)); }

    // Non-const iterators: allow modification
    auto begin() { return songs_.begin(); }   // vector<string>::iterator
    auto end() { return songs_.end(); }

    // Const iterators: read-only access
    auto begin() const { return songs_.begin(); }   // vector<string>::const_iterator
    auto end() const { return songs_.end(); }

    // Explicit const iterators (C++11)
    auto cbegin() const { return songs_.cbegin(); }
    auto cend() const { return songs_.cend(); }

    std::size_t size() const { return songs_.size(); }
};

void demo() {
    Playlist p;
    p.add("Song A");
    p.add("Song B");
    p.add("Song C");

    // Non-const object: range-for calls begin()/end() -> mutable iterators
    for (auto& song : p) {
        song += " (played)";  // OK: mutable reference
    }

    // Const reference: range-for calls begin() const/end() const -> const iterators
    const Playlist& cp = p;
    for (const auto& song : cp) {
        std::cout << song << "\n";
        // song += "x";  // ERROR: const reference
    }

    // Force const iteration on non-const object:
    // Method 1: std::as_const (C++17)
    for (const auto& song : std::as_const(p)) {
        // Uses const begin()/end()
    }

    // Method 2: explicit cbegin/cend
    for (auto it = p.cbegin(); it != p.cend(); ++it) {
        std::cout << *it << "\n";
    }

    // Method 3: const auto& in range-for
    for (const auto& song : p) {
        // song is const string& — prevents accidental modification
        // But NOTE: p.begin() still returns non-const iterator!
        // The const comes from the binding, not the iterator
    }

    // Why this matters for generic code:
    auto modify = [](auto& container) {
        for (auto& elem : container) {
            // If container is const, elem is const auto&
            // If container is non-const, elem is auto&
            // Const propagates through begin()/end() overloads
        }
    };
}

// Custom const-correct iterator implementation
template <typename T>
class CircularBuffer {
    T* data_;
    std::size_t size_;
    std::size_t head_ = 0;

public:
    template <bool IsConst>
    class Iterator {
        using ptr_type = std::conditional_t<IsConst, const T*, T*>;
        using ref_type = std::conditional_t<IsConst, const T&, T&>;

        ptr_type data_;
        std::size_t pos_, size_;

    public:
        Iterator(ptr_type data, std::size_t pos, std::size_t size)
            : data_(data), pos_(pos), size_(size) {}

        ref_type operator*() const { return data_[pos_ % size_]; }
        Iterator& operator++() { ++pos_; return *this; }
        bool operator!=(const Iterator& other) const { return pos_ != other.pos_; }

        // Allow conversion from non-const to const iterator
        operator Iterator<true>() const requires (!IsConst) {
            return Iterator<true>(data_, pos_, size_);
        }
    };

    using iterator = Iterator<false>;
    using const_iterator = Iterator<true>;

    iterator begin() { return {data_, head_, size_}; }
    iterator end() { return {data_, head_ + size_, size_}; }
    const_iterator begin() const { return {data_, head_, size_}; }
    const_iterator end() const { return {data_, head_ + size_, size_}; }
    const_iterator cbegin() const { return begin(); }
    const_iterator cend() const { return end(); }
};
```

The const-correctness chain:
1. `const` on the container object selects `begin() const` / `end() const`
2. These return `const_iterator` (read-only view)
3. `const_iterator::operator*` returns `const T&`
4. Range-based for uses `begin()`/`end()` — const propagates automatically

```cpp
#include <vector>
#include <functional>
#include <iostream>
#include <stdexcept>
#include <string>

// Generic RAII transaction: records undo actions, rolls back on exception
class Transaction {
    std::vector<std::function<void()>> undo_stack_;
    bool committed_ = false;

public:
    ~Transaction() {
        if (!committed_) rollback();
    }

    // Register an action with its undo
    template <typename DoFn, typename UndoFn>
    void execute(DoFn&& action, UndoFn&& undo) {
        action();  // Do the action (may throw)
        // If action succeeded, register undo
        undo_stack_.push_back(std::forward<UndoFn>(undo));
    }

    void commit() noexcept {
        committed_ = true;
        undo_stack_.clear();  // Discard all undo actions
    }

    void rollback() noexcept {
        // Undo in reverse order (LIFO)
        for (auto it = undo_stack_.rbegin(); it != undo_stack_.rend(); ++it) {
            try { (*it)(); } catch (...) {}  // Swallow exceptions in undo
        }
        undo_stack_.clear();
    }

    Transaction(const Transaction&) = delete;
    Transaction& operator=(const Transaction&) = delete;
};

// Simulated database
struct DB {
    std::vector<std::string> users;
    std::vector<std::string> logs;
    int balance = 1000;

    void add_user(const std::string& name) {
        users.push_back(name);
        std::cout << "  Added user: " << name << "\n";
    }
    void remove_user() {
        std::cout << "  Rolled back user: " << users.back() << "\n";
        users.pop_back();
    }
    void add_log(const std::string& msg) {
        logs.push_back(msg);
        std::cout << "  Added log: " << msg << "\n";
    }
    void remove_log() {
        std::cout << "  Rolled back log: " << logs.back() << "\n";
        logs.pop_back();
    }
    void debit(int amount) {
        if (balance < amount) throw std::runtime_error("Insufficient funds");
        balance -= amount;
        std::cout << "  Debited: " << amount << " (balance: " << balance << ")\n";
    }
    void credit(int amount) {
        balance += amount;
        std::cout << "  Credited back: " << amount << " (balance: " << balance << ")\n";
    }
};

void register_user(DB& db, const std::string& name, int fee) {
    Transaction txn;

    txn.execute(
        [&] { db.add_user(name); },
        [&] { db.remove_user(); }
    );

    txn.execute(
        [&] { db.debit(fee); },
        [&] { db.credit(fee); }
    );

    txn.execute(
        [&] { db.add_log("Registered " + name + ", fee=" + std::to_string(fee)); },
        [&] { db.remove_log(); }
    );

    // If any step throws:
    //   All prior steps are rolled back in reverse order
    //   ~Transaction calls rollback() automatically

    txn.commit();  // All steps succeeded — discard undo actions
}

int main() {
    DB db;

    std::cout << "=== Successful registration ===\n";
    register_user(db, "Alice", 100);
    std::cout << "Users: " << db.users.size()
              << ", Balance: " << db.balance << "\n";

    std::cout << "\n=== Failed registration (insufficient funds) ===\n";
    try {
        register_user(db, "Bob", 2000);  // Will fail at debit
    } catch (const std::exception& e) {
        std::cout << "Error: " << e.what() << "\n";
    }
    std::cout << "Users: " << db.users.size()
              << ", Balance: " << db.balance << "\n";
    // Bob was rolled back — users still has only Alice, balance unchanged
}
```

Output:
```
=== Successful registration ===
  Added user: Alice
  Debited: 100 (balance: 900)
  Added log: Registered Alice, fee=100
Users: 1, Balance: 900

=== Failed registration (insufficient funds) ===
  Added user: Bob
  Rolled back user: Bob
Error: Insufficient funds
Users: 1, Balance: 900
```

The pattern: each `execute()` call pairs an action with its inverse. If any action throws, the Transaction destructor (RAII) runs all accumulated undo functions in reverse order. `commit()` clears the undo stack, signaling success. This is the Command pattern + RAII = reliable all-or-nothing operations.

Structured bindings (C++17) can create dangling references when binding to temporaries or when the source container is modified.

```cpp
#include <map>
#include <string>
#include <iostream>
#include <tuple>

// DANGER 1: Binding to a temporary
std::pair<std::string, int> get_config() {
    return {"timeout", 30};
}

void dangling_from_temporary() {
    // BAD: binding references to a temporary that's immediately destroyed
    // auto& [key, value] = get_config();  // DANGLING! Temporary destroyed.
    // std::cout << key << "\n";           // Undefined behavior

    // GOOD: bind by value (copies/moves the pair)
    auto [key, value] = get_config();  // Owns the data
    std::cout << key << ": " << value << "\n";  // Safe

    // GOOD: bind const reference to extend temporary lifetime
    const auto& [k2, v2] = get_config();  // Temporary lifetime extended
    std::cout << k2 << ": " << v2 << "\n";  // Safe
}

// DANGER 2: Binding to container elements that get invalidated
void dangling_from_container() {
    std::map<int, std::string> m = {{1, "one"}, {2, "two"}};

    // BAD: storing references to map elements, then modifying map
    auto& [key, val] = *m.begin();
    // m.clear();  // Invalidates ALL iterators and references
    // std::cout << val;  // DANGLING — undefined behavior

    // ALSO BAD with vectors:
    std::vector<std::string> v = {"a", "b", "c"};
    auto& elem = v[0];   // Reference to v[0]
    v.push_back("d");     // May reallocate — elem is now dangling!
}

// DANGER 3: Structured bindings in range-for with temporary containers
void dangling_in_loop() {
    // BAD: range-for over a temporary
    // for (auto& [k, v] : get_map()) { }  // Temporary destroyed before loop body!

    // GOOD: store in a variable first
    auto map = get_map();
    for (auto& [k, v] : map) { /* safe */ }

    // GOOD: const ref extends lifetime in range-for (C++23 fixes this)
    for (auto& [k, v] : std::map<int, int>{{1, 2}, {3, 4}}) {
        // Temporary lifetime extended to cover the loop (since C++23)
    }
}

// SAFE patterns
void safe_bindings() {
    std::map<std::string, int> scores = {{"alice", 100}, {"bob", 85}};

    // Safe: iterate by const ref
    for (const auto& [name, score] : scores) {
        std::cout << name << ": " << score << "\n";
    }

    // Safe: iterate by value (copies each pair)
    for (auto [name, score] : scores) {
        name += "_copy";  // Modifies local copy, not the map
    }

    // Safe: modify map values through mutable binding
    for (auto& [name, score] : scores) {
        score += 10;  // Modifies map value directly
        // name is const — keys are always const in maps
    }

    // Safe: tuple decomposition
    auto [a, b, c] = std::make_tuple(1, 2.0, std::string("three"));
    // a, b, c are copies — no dangling possible
}
```

Rules:
1. **Never bind `auto&` to a function return** (temporary dies immediately). Use `auto` (by value) or `const auto&` (extends lifetime).
2. **Don't modify containers while holding structured binding references** to their elements.
3. **In range-for over temporaries**, the temporary may not survive the loop body (fixed in C++23).
4. **`const auto&`** is the safest default for structured bindings — prevents modification and extends temporary lifetimes.
5. **Map iteration**: keys are always `const` in structured bindings (`const auto& [key, value]` — key is inherently const).

```cpp
#include <memory>
#include <stdexcept>
#include <iostream>

struct Widget {
    std::string name;
    int value;
    Widget(std::string n, int v) : name(std::move(n)), value(v) {
        std::cout << "Widget(" << name << ")\n";
    }
    ~Widget() { std::cout << "~Widget(" << name << ")\n"; }
};

// PROBLEM 1: Memory leak with raw new
void leak_example() {
    // BAD: if process() throws, Widget leaks!
    // process(std::shared_ptr<Widget>(new Widget("leak", 1)), might_throw());

    // Pre-C++17 evaluation order:
    //   1. new Widget("leak", 1)  — allocates
    //   2. might_throw()           — throws! (order unspecified pre-C++17)
    //   3. shared_ptr constructor  — never reached
    //   Result: Widget leaked

    // SAFE: make_shared bundles allocation + construction atomically
    // process(std::make_shared<Widget>("safe", 1), might_throw());
    // Even if might_throw() is evaluated first, no Widget was allocated yet
}

// PROBLEM 2: Two allocations vs one
void allocation_efficiency() {
    // Two allocations: one for Widget, one for control block
    std::shared_ptr<Widget> p1(new Widget("two-alloc", 1));

    // ONE allocation: Widget + control block in single memory block
    auto p2 = std::make_shared<Widget>("one-alloc", 2);
    // Faster, better cache locality, less memory fragmentation
}

// When you MUST use raw new:
void raw_new_required() {
    // 1. Custom deleter (make_shared doesn't support it)
    std::shared_ptr<FILE> file(
        fopen("test.txt", "r"),
        [](FILE* f) { if (f) fclose(f); }
    );

    // 2. Weak_ptr preventing deallocation
    // With make_shared, the entire block (object + control block)
    // stays allocated while ANY weak_ptr exists, even after all
    // shared_ptrs are gone. With raw new, the object memory is freed
    // immediately when refcount hits 0.
    auto obj = std::make_shared<Widget>("big", 1);  // One block
    std::weak_ptr<Widget> weak = obj;
    obj.reset();  // Object destroyed, but memory NOT freed (weak_ptr holds control block + object block)

    // 3. Private constructor (make_shared can't access it)
    // Solution: passkey idiom or friend declaration
}

// SUMMARY: Always prefer make_unique/make_shared
void best_practice() {
    // unique_ptr: ALWAYS use make_unique
    auto u = std::make_unique<Widget>("unique", 1);

    // shared_ptr: ALWAYS use make_shared (unless custom deleter needed)
    auto s = std::make_shared<Widget>("shared", 2);

    // Array versions
    auto arr = std::make_unique<int[]>(100);  // 100 ints, zero-initialized
    // auto sarr = std::make_shared<int[]>(100);  // C++20

    // Avoid:
    // std::unique_ptr<Widget> p(new Widget("avoid", 3));  // Works but risky
    // std::shared_ptr<Widget> p(new Widget("avoid", 4));  // Works but slower
}

int main() {
    best_practice();
}
```

**Decision matrix:**

| Scenario | Use |
|----------|-----|
| Creating unique_ptr | `make_unique<T>(args...)` always |
| Creating shared_ptr | `make_shared<T>(args...)` usually |
| Custom deleter | `shared_ptr<T>(new T(...), deleter)` |
| Private constructor | `shared_ptr<T>(new T(...))` + friend |
| Long-lived weak_ptr to large object | `shared_ptr<T>(new T(...))` (separate alloc) |
| Array of T | `make_unique<T[]>(n)` or `make_shared<T[]>(n)` (C++20) |

**Core Guideline R.22**: Prefer `make_shared`/`make_unique` over using `new` directly. The only exceptions are custom deleters and the weak_ptr memory retention edge case.

```cpp
#include <memory>
#include <mutex>
#include <fstream>
#include <stdexcept>
#include <iostream>

std::mutex g_mutex;

void process(const std::string& path) {
    // Resource 1: heap buffer via unique_ptr
    auto buffer = std::make_unique<char[]>(8192);
    std::cout << "1. Buffer allocated\n";

    // Resource 2: mutex via lock_guard
    std::lock_guard<std::mutex> lock(g_mutex);
    std::cout << "2. Mutex locked\n";

    // Exception BEFORE resource 3 is acquired
    if (path.empty())
        throw std::invalid_argument("empty path");

    // Resource 3: file via ifstream
    std::ifstream file(path);
    if (!file.is_open())
        throw std::runtime_error("cannot open " + path);
    std::cout << "3. File opened\n";

    // Do work...
    file.read(buffer.get(), 8192);
}

int main() {
    try {
        process("");  // Throws after resource 1+2, before 3
    } catch (const std::exception& e) {
        std::cout << "Exception: " << e.what() << "\n";
    }
}
```

Output:
```
1. Buffer allocated
2. Mutex locked
Exception: empty path
```

What happens during stack unwinding:
1. **File (resource 3)**: Never constructed — no cleanup needed. C++ only destroys fully-constructed objects.
2. **lock_guard (resource 2)**: `~lock_guard()` called — mutex unlocked. Last constructed, first destroyed.
3. **unique_ptr (resource 1)**: `~unique_ptr()` called — buffer freed. First constructed, last destroyed.

The guarantee: only resources that were successfully acquired need cleanup, and RAII handles each one independently. No try/catch needed. No possibility of forgetting to unlock the mutex or free the buffer. Adding a fourth resource means adding one line — no restructuring of cleanup logic.

**No-throw guarantee**: The operation will never throw. Destructors, swap, move operations on primitives.

```cpp
void swap(int& a, int& b) noexcept {
    int tmp = a;  // Can't throw — primitives
    a = b;
    b = tmp;
}
// If marked noexcept and it throws anyway: std::terminate()
```

**Strong guarantee**: If the operation throws, the program state is unchanged — as if the call never happened.

```cpp
class Account {
    std::string name_;
    int balance_;

public:
    // Strong guarantee via copy-and-swap
    void transfer_to(Account& other, int amount) {
        if (amount > balance_)
            throw std::runtime_error("Insufficient funds");

        // Do all the risky work on copies
        Account self_copy = *this;
        Account other_copy = other;

        self_copy.balance_ -= amount;   // Modify copies
        other_copy.balance_ += amount;

        // Commit: noexcept swaps
        swap(*this, self_copy);    // noexcept
        swap(other, other_copy);   // noexcept
        // If any copy/computation threw, originals are untouched
    }
};
```

**Basic guarantee**: If the operation throws, no resources leak and invariants are preserved, but state may have changed.

```cpp
class Logger {
    std::vector<std::string> entries_;
    int total_bytes_ = 0;

public:
    // Basic guarantee: if push_back throws (reallocation fails),
    // entries_ might have been modified but is still valid.
    // total_bytes_ might not match actual entries.
    void log_basic(const std::string& msg) {
        total_bytes_ += msg.size();      // Already updated!
        entries_.push_back(msg);         // If this throws...
        // total_bytes_ is wrong, but no leak, vector is valid
    }

    // Fixed for strong guarantee:
    void log_strong(const std::string& msg) {
        entries_.push_back(msg);         // Do the risky thing first
        total_bytes_ += msg.size();      // Only update if push succeeded
    }
};
```

The hierarchy: no-throw ⊂ strong ⊂ basic. Every operation should provide at least the basic guarantee. RAII gives you basic for free (no leaks). Copy-and-swap gives you strong. noexcept gives you no-throw.

**Standard library guarantees:**
- `vector::push_back`: Strong if T's move is noexcept, basic otherwise
- `map::insert`: Strong (node-based, insertion failure doesn't corrupt)
- `string::operator+`: Strong (temporary + swap)
- All destructors: No-throw (undefined behavior if destructor throws during unwinding)
- All `swap` overloads: No-throw

```cpp
#include <type_traits>
#include <iostream>
#include <string>
#include <vector>

// 1. Conditional noexcept: noexcept if the operation is noexcept
template <typename T>
void swap_values(T& a, T& b)
    noexcept(std::is_nothrow_move_constructible_v<T> &&
             std::is_nothrow_move_assignable_v<T>) {
    T tmp = std::move(a);
    a = std::move(b);
    b = std::move(tmp);
}

// 2. noexcept propagation through wrapper functions
template <typename F, typename... Args>
auto invoke_noexcept(F&& f, Args&&... args)
    noexcept(noexcept(f(std::forward<Args>(args)...)))
    -> decltype(f(std::forward<Args>(args)...)) {
    return f(std::forward<Args>(args)...);
}

// 3. noexcept as part of the type system (C++17)
void regular() { throw 1; }
void safe() noexcept {}

void demo_type_system() {
    // C++17: noexcept is part of the function type
    void (*fp1)() noexcept = safe;     // OK
    // void (*fp2)() noexcept = regular;  // ERROR: can't assign non-noexcept to noexcept
    void (*fp3)() = safe;              // OK: noexcept -> non-noexcept is fine
    void (*fp4)() = regular;           // OK
}

// 4. noexcept in move operations — THE critical use case
struct Widget {
    std::string data;

    // noexcept move: vector uses move during reallocation
    Widget(Widget&& other) noexcept : data(std::move(other.data)) {}

    // NOT noexcept: vector falls back to copy during reallocation
    // Widget(Widget&& other) : data(std::move(other.data)) {}
};

// 5. SFINAE with noexcept (checking if an operation is noexcept)
template <typename T>
void process(T&& val) {
    if constexpr (std::is_nothrow_move_constructible_v<T>) {
        std::cout << "Using optimized move path\n";
        // Can use move_if_noexcept → guaranteed move
    } else {
        std::cout << "Using safe copy path\n";
        // move_if_noexcept → will copy instead
    }
}

// 6. Conditional noexcept on class methods
template <typename T>
class Container {
    T* data_;
    std::size_t size_;

public:
    // Destructor: always noexcept (implicit)
    ~Container() {
        for (std::size_t i = 0; i < size_; ++i)
            data_[i].~T();  // T's destructor must be noexcept
        delete[] reinterpret_cast<char*>(data_);
    }

    // Swap: noexcept unconditionally (only swaps pointers)
    friend void swap(Container& a, Container& b) noexcept {
        std::swap(a.data_, b.data_);
        std::swap(a.size_, b.size_);
    }

    // Move: conditionally noexcept based on T
    Container(Container&& other)
        noexcept(std::is_nothrow_move_constructible_v<T>)
        : data_(std::exchange(other.data_, nullptr)),
          size_(std::exchange(other.size_, 0)) {}
};

int main() {
    static_assert(noexcept(swap_values(std::declval<int&>(), std::declval<int&>())),
                  "int swap should be noexcept");

    std::cout << "string swap noexcept: "
              << noexcept(swap_values(std::declval<std::string&>(),
                                     std::declval<std::string&>()))
              << "\n";  // true: string move is noexcept
}
```

Key rules:
1. **Always mark move constructors/assignment `noexcept`** — containers depend on it
2. **Always mark swap `noexcept`** — it's the foundation of exception safety
3. **Always mark destructors `noexcept`** — throwing destructors during unwinding = `terminate()`
4. **Use `noexcept(expr)` for conditional** — propagate noexcept through templates
5. **C++17**: `noexcept` is part of the function type — `void(*)() noexcept` ≠ `void(*)()`

```cpp
#include <new>
#include <utility>
#include <type_traits>
#include <stdexcept>
#include <iostream>

template <typename T>
class Optional {
    alignas(T) unsigned char storage_[sizeof(T)];
    bool engaged_ = false;

    T* ptr() noexcept { return reinterpret_cast<T*>(storage_); }
    const T* ptr() const noexcept { return reinterpret_cast<const T*>(storage_); }

public:
    // Default: disengaged
    Optional() noexcept = default;

    // Construct from value
    Optional(const T& value) : engaged_(true) {
        new (storage_) T(value);
    }

    Optional(T&& value) noexcept(std::is_nothrow_move_constructible_v<T>)
        : engaged_(true) {
        new (storage_) T(std::move(value));
    }

    // Copy
    Optional(const Optional& other) : engaged_(other.engaged_) {
        if (engaged_) new (storage_) T(*other.ptr());
    }

    // Move
    Optional(Optional&& other) noexcept(std::is_nothrow_move_constructible_v<T>)
        : engaged_(other.engaged_) {
        if (engaged_) {
            new (storage_) T(std::move(*other.ptr()));
            // Note: other remains engaged but in moved-from state
        }
    }

    // Destructor
    ~Optional() { reset(); }

    // Copy assignment
    Optional& operator=(const Optional& other) {
        if (this != &other) {
            if (engaged_ && other.engaged_) {
                *ptr() = *other.ptr();  // Assign existing
            } else if (other.engaged_) {
                new (storage_) T(*other.ptr());  // Construct
                engaged_ = true;
            } else {
                reset();  // Destroy
            }
        }
        return *this;
    }

    // Move assignment
    Optional& operator=(Optional&& other)
        noexcept(std::is_nothrow_move_assignable_v<T> &&
                 std::is_nothrow_move_constructible_v<T>) {
        if (this != &other) {
            if (engaged_ && other.engaged_) {
                *ptr() = std::move(*other.ptr());
            } else if (other.engaged_) {
                new (storage_) T(std::move(*other.ptr()));
                engaged_ = true;
            } else {
                reset();
            }
        }
        return *this;
    }

    // Const-correct accessors
    T& value() & {
        if (!engaged_) throw std::bad_optional_access();
        return *ptr();
    }

    const T& value() const& {
        if (!engaged_) throw std::bad_optional_access();
        return *ptr();
    }

    T&& value() && {
        if (!engaged_) throw std::bad_optional_access();
        return std::move(*ptr());
    }

    // Dereference operators (no bounds check — like std::optional)
    T& operator*() & { return *ptr(); }
    const T& operator*() const& { return *ptr(); }
    T&& operator*() && { return std::move(*ptr()); }

    T* operator->() { return ptr(); }
    const T* operator->() const { return ptr(); }

    // State
    bool has_value() const noexcept { return engaged_; }
    explicit operator bool() const noexcept { return engaged_; }

    void reset() noexcept {
        if (engaged_) {
            ptr()->~T();
            engaged_ = false;
        }
    }

    template <typename... Args>
    T& emplace(Args&&... args) {
        reset();
        new (storage_) T(std::forward<Args>(args)...);
        engaged_ = true;
        return *ptr();
    }

    T value_or(T default_value) const& {
        return engaged_ ? *ptr() : std::move(default_value);
    }

    T value_or(T default_value) && {
        return engaged_ ? std::move(*ptr()) : std::move(default_value);
    }
};

int main() {
    Optional<std::string> a("hello");
    Optional<std::string> b = std::move(a);  // Move construct
    std::cout << *b << "\n";  // "hello"

    const Optional<std::string> c("const");
    std::cout << c.value() << "\n";  // const access
    // c.value() = "modify";  // ERROR: returns const string&

    // Move out of rvalue optional
    std::string s = Optional<std::string>("temp").value();  // Uses value() &&
    std::cout << s << "\n";

    // value_or
    Optional<std::string> empty;
    std::cout << empty.value_or("default") << "\n";
}
```

Key design points:
- **Placement new** in aligned storage — no heap allocation
- **Three overloads of `value()`**: `&` (lvalue), `const&` (const lvalue), `&&` (rvalue) — each returns the appropriate reference type
- **Conditional noexcept** on move operations — propagates T's guarantees
- **`reset()`** explicitly calls destructor — critical for types with cleanup
- **Move assignment** handles all four cases: both engaged, only source, only target, neither
- **`emplace()`** destroys existing value first, then constructs new one in-place

Copy-and-swap is the cleanest way, but sometimes you want to avoid the extra allocation. Here's the direct approach with strong guarantee:

```cpp
#include <memory>
#include <cstring>
#include <utility>
#include <algorithm>

class Buffer {
    char* data_;
    std::size_t size_;

public:
    Buffer(std::size_t n) : data_(new char[n]{}), size_(n) {}
    ~Buffer() { delete[] data_; }

    Buffer(const Buffer& other)
        : data_(new char[other.size_]), size_(other.size_) {
        std::memcpy(data_, other.data_, size_);
    }

    Buffer(Buffer&& other) noexcept
        : data_(std::exchange(other.data_, nullptr)),
          size_(std::exchange(other.size_, 0)) {}

    // Approach 1: Copy-and-swap (simple, always safe)
    Buffer& assign_swap(Buffer other) noexcept {
        swap(*this, other);
        return *this;
        // Pro: dead simple, always strongly exception-safe
        // Con: always allocates a new buffer, even if sizes match
    }

    // Approach 2: Direct with strong guarantee (reuse buffer when possible)
    Buffer& operator=(const Buffer& other) {
        if (this == &other) return *this;

        if (size_ == other.size_) {
            // Same size: reuse existing buffer, no allocation
            std::memcpy(data_, other.data_, size_);
            // Strong guarantee: if memcpy somehow failed (it can't for
            // trivial types), data_ would contain partial copy — but
            // with non-trivial types you'd need element-wise copy.
        } else {
            // Different size: allocate first, swap second
            char* new_data = new char[other.size_];  // May throw
            // If new throws: *this is unchanged (strong guarantee)
            std::memcpy(new_data, other.data_, other.size_);

            // Commit phase: all noexcept from here
            delete[] data_;
            data_ = new_data;
            size_ = other.size_;
        }
        return *this;
    }

    // Move assignment
    Buffer& operator=(Buffer&& other) noexcept {
        if (this != &other) {
            delete[] data_;
            data_ = std::exchange(other.data_, nullptr);
            size_ = std::exchange(other.size_, 0);
        }
        return *this;
    }

    friend void swap(Buffer& a, Buffer& b) noexcept {
        using std::swap;
        swap(a.data_, b.data_);
        swap(a.size_, b.size_);
    }

    std::size_t size() const { return size_; }
};
```

**Comparison:**

| Aspect | Copy-and-swap | Direct assignment |
|--------|--------------|-------------------|
| Lines of code | 3 | 15+ |
| Exception safety | Strong (automatic) | Strong (manual) |
| Self-assignment | Safe (free) | Need explicit check |
| Buffer reuse | Never (always alloc) | Yes (same-size case) |
| Performance | 1 alloc + 1 dealloc always | 0 alloc if same size |
| Move assignment | Handled automatically | Separate implementation |
| Correctness risk | Very low | Medium (easy to mess up ordering) |

**When to use which:**
- **Copy-and-swap**: Default choice. Simple, correct, maintainable.
- **Direct**: Only when profiling shows assignment is a bottleneck AND most assignments are same-size (e.g., fixed-size buffers, matrix operations).

The key to direct approach: do all throwing operations (allocation) BEFORE modifying any state. The commit phase must be entirely noexcept.

When an object needs multiple initialization steps that can each fail, RAII ensures partial state is cleaned up even if a later step throws.

```cpp
#include <memory>
#include <string>
#include <stdexcept>
#include <iostream>
#include <fstream>

// Simulated subsystems
struct NetworkStack {
    NetworkStack() { std::cout << "  Network initialized\n"; }
    ~NetworkStack() { std::cout << "  Network shut down\n"; }
};

struct Database {
    std::string path;
    Database(const std::string& p) : path(p) {
        if (p.empty()) throw std::runtime_error("empty db path");
        std::cout << "  Database opened: " << p << "\n";
    }
    ~Database() { std::cout << "  Database closed: " << path << "\n"; }
};

struct Cache {
    Cache(int size_mb) {
        if (size_mb > 1024) throw std::bad_alloc();
        std::cout << "  Cache allocated: " << size_mb << "MB\n";
    }
    ~Cache() { std::cout << "  Cache freed\n"; }
};

// Multi-phase init: each member is RAII
class Server {
    std::unique_ptr<NetworkStack> network_;
    std::unique_ptr<Database> db_;
    std::unique_ptr<Cache> cache_;

public:
    Server(const std::string& db_path, int cache_mb) {
        // Phase 1: Network
        network_ = std::make_unique<NetworkStack>();

        // Phase 2: Database (may throw)
        db_ = std::make_unique<Database>(db_path);

        // Phase 3: Cache (may throw)
        cache_ = std::make_unique<Cache>(cache_mb);

        // If Phase 3 throws:
        //   cache_ was never assigned (make_unique threw)
        //   ~Server() runs: db_ destroyed, network_ destroyed
        //   Cleanup is automatic and correct

        std::cout << "  Server fully initialized\n";
    }

    // Rule of Zero: unique_ptr members handle everything
    ~Server() { std::cout << "  Server shutting down\n"; }
};

int main() {
    std::cout << "=== Successful init ===\n";
    {
        Server s("prod.db", 512);
    }

    std::cout << "\n=== Failed at Phase 3 (cache too large) ===\n";
    try {
        Server s("prod.db", 2048);  // Cache alloc fails
    } catch (const std::exception& e) {
        std::cout << "Caught: " << e.what() << "\n";
    }

    std::cout << "\n=== Failed at Phase 2 (bad db path) ===\n";
    try {
        Server s("", 512);  // DB open fails
    } catch (const std::exception& e) {
        std::cout << "Caught: " << e.what() << "\n";
    }
}
```

Output:
```
=== Successful init ===
  Network initialized
  Database opened: prod.db
  Cache allocated: 512MB
  Server fully initialized
  Server shutting down
  Cache freed
  Database closed: prod.db
  Network shut down

=== Failed at Phase 3 ===
  Network initialized
  Database opened: prod.db
  Database closed: prod.db
  Network shut down
Caught: std::bad_alloc

=== Failed at Phase 2 ===
  Network initialized
  Network shut down
Caught: empty db path
```

Key principle: when a constructor throws, C++ destroys all fully-constructed members (in reverse order) but does NOT call the class destructor (since the object was never fully constructed). By using RAII members (unique_ptr), each sub-component cleans itself up independently. No try/catch needed in the constructor, no manual cleanup, no possibility of resource leaks regardless of which phase fails.

```cpp
#include <vector>
#include <string>
#include <iostream>
#include <utility>

struct Tracked {
    std::string name;
    Tracked(std::string n) : name(std::move(n)) {}
    Tracked(const Tracked& o) : name(o.name) { std::cout << "  copy: " << name << "\n"; }
    Tracked(Tracked&& o) noexcept : name(std::move(o.name)) { std::cout << "  move: " << name << "\n"; }
};

std::vector<Tracked> get_items() {
    std::vector<Tracked> v;
    v.emplace_back("alpha");
    v.emplace_back("beta");
    return v;
}

int main() {
    // 1. const auto& — read-only, extends temporary lifetime
    std::cout << "--- const auto& ---\n";
    for (const auto& item : get_items()) {
        std::cout << item.name << "\n";
        // item is const Tracked& — can't move from it
        // Tracked copy = std::move(item);  // Would COPY, not move!
    }

    // 2. auto&& — forwarding reference, preserves value category
    std::cout << "\n--- auto&& ---\n";
    for (auto&& item : get_items()) {
        std::cout << item.name << "\n";
        // item is Tracked&& (rvalue ref) — CAN move from it
        // But be careful: once moved, item is in moved-from state
        // for rest of loop body
    }

    // 3. auto (by value) — copies each element
    std::cout << "\n--- auto (copy) ---\n";
    for (auto item : get_items()) {
        std::cout << item.name << "\n";
        // Each element is copied from the vector
    }

    // 4. Practical difference: consuming elements
    std::cout << "\n--- Moving out with auto&& ---\n";
    std::vector<Tracked> destination;
    for (auto&& item : get_items()) {
        destination.push_back(std::move(item));  // Actually moves
    }
    // With const auto&: push_back would copy, not move

    // 5. With existing (lvalue) container
    std::vector<Tracked> existing;
    existing.emplace_back("gamma");

    std::cout << "\n--- auto&& with lvalue container ---\n";
    for (auto&& item : existing) {
        // item is Tracked& (lvalue ref!) — auto&& deduces to T&
        // Safe to read, can modify, but std::move would empty 'existing'
        std::cout << item.name << "\n";
    }
}
```

**Decision table for range-based for:**

| Syntax | Type of `item` | Copies? | Can modify? | Can move from? | Use when |
|--------|---------------|---------|-------------|----------------|----------|
| `auto item` | `T` | Yes (each elem) | Local copy | Yes (your copy) | Need independent copy |
| `auto& item` | `T&` | No | Yes | Yes (empties container!) | Modifying elements |
| `const auto& item` | `const T&` | No | No | No (silent copy) | Reading only (default) |
| `auto&& item` | `T&` or `T&&` | No | Yes | Yes if rvalue | Perfect forwarding / consuming |

**Rule of thumb:**
- `const auto&` — default choice (safe, no copies)
- `auto&` — when you need to modify container elements
- `auto&&` — when consuming from a temporary or need forwarding
- `auto` — rarely (only when you need an independent copy)

C++17 mandates copy elision for prvalue initialization — the compiler MUST construct the object directly at the destination. This is often called "guaranteed copy elision" or "guaranteed RVO".

```cpp
#include <iostream>

struct Heavy {
    Heavy() { std::cout << "construct\n"; }
    Heavy(const Heavy&) { std::cout << "COPY\n"; }
    Heavy(Heavy&&) { std::cout << "MOVE\n"; }
};

// GUARANTEED elision (C++17): returning a prvalue
Heavy make() {
    return Heavy{};  // Prvalue — constructed directly at call site
}
// Pre-C++17: allowed but not required (could copy/move)
// C++17: MUST elide — no copy, no move, no constructor needed

// Works even with DELETED copy/move constructors!
struct Immovable {
    Immovable() = default;
    Immovable(const Immovable&) = delete;
    Immovable(Immovable&&) = delete;
};

Immovable make_immovable() {
    return Immovable{};  // OK in C++17! Copy/move never needed
}

// NRVO: NOT guaranteed, but usually applied
Heavy make_named() {
    Heavy h;       // Named variable
    return h;      // NRVO may or may not apply
    // If NRVO applies: "construct" only
    // If NRVO fails: "construct" + "MOVE" (implicit move of local)
}

// NRVO FAILS in these cases:
Heavy pick(bool flag) {
    Heavy a, b;
    if (flag) return a;  // Two possible return variables
    return b;            // Compiler can't assign both to caller's slot
    // Result: construct + construct + MOVE
}

Heavy identity(Heavy h) {
    return h;  // Parameter — not eligible for NRVO
    // But: implicit move applies (treated as rvalue)
}

// Key distinction:
// Prvalue (guaranteed):  return Heavy{};     — always elided
// Named (NRVO):          Heavy h; return h;  — usually elided
// Parameter:             return param;       — never elided, implicit move
// Multiple paths:        return a or b;      — rarely elided
// std::move(local):      return std::move(h); — PREVENTS NRVO!

int main() {
    std::cout << "--- Guaranteed elision ---\n";
    Heavy h1 = make();  // "construct" — guaranteed one construction

    std::cout << "\n--- NRVO (usually works) ---\n";
    Heavy h2 = make_named();  // Probably just "construct"

    std::cout << "\n--- NRVO fails ---\n";
    Heavy h3 = pick(true);  // "construct" "construct" "MOVE"

    std::cout << "\n--- Immovable type ---\n";
    auto h4 = make_immovable();  // OK! No copy/move needed
}
```

Practical rules:
1. **Return temporaries directly**: `return T{args};` — guaranteed elision
2. **Return named locals without std::move**: `T x; return x;` — enables NRVO + implicit move fallback
3. **Never `return std::move(local)`** — kills NRVO, no better than implicit move
4. **Guaranteed elision enables factory functions for non-movable types** — revolutionary for RAII handles with deleted copy/move
5. **Chaining works**: `T a = make_a(); T b = transform(make_a());` — each step can elide

The type state pattern encodes an object's lifecycle state into the type system, making invalid operations a compile error.

```cpp
#include <memory>
#include <string>
#include <iostream>
#include <utility>

// Forward declarations for state types
struct Open;
struct Closed;

// File handle parameterized by state
template <typename State>
class File;

// Closed state: can only open
template <>
class File<Closed> {
    std::string path_;
    friend class File<Open>;

public:
    explicit File(std::string path) : path_(std::move(path)) {}

    // Transition: Closed -> Open (consumes Closed, returns Open)
    File<Open> open() && {  // rvalue-qualified: must be moved from
        std::cout << "Opening: " << path_ << "\n";
        return File<Open>(std::move(path_));
    }

    // Can't read, write, or close a Closed file:
    // void read() — doesn't exist
    // void write() — doesn't exist
    // void close() — doesn't exist
};

// Open state: can read, write, close
template <>
class File<Open> {
    std::string path_;
    friend class File<Closed>;

    explicit File(std::string path) : path_(std::move(path)) {}

public:
    void read() const {
        std::cout << "Reading: " << path_ << "\n";
    }

    void write(const std::string& data) {
        std::cout << "Writing " << data.size() << " bytes to " << path_ << "\n";
    }

    // Transition: Open -> Closed (consumes Open)
    File<Closed> close() && {
        std::cout << "Closing: " << path_ << "\n";
        return File<Closed>(std::move(path_));
    }

    // Can't open an already-open file:
    // void open() — doesn't exist

    // RAII: if dropped without close(), destructor handles cleanup
    ~File() {
        if (!path_.empty()) {
            std::cout << "Auto-closing: " << path_ << "\n";
        }
    }

    // Move-only
    File(File&& other) noexcept : path_(std::move(other.path_)) {}
    File& operator=(File&&) = delete;  // Prevent reuse
    File(const File&) = delete;
};

int main() {
    // Type-safe lifecycle:
    File<Closed> f("data.txt");

    // f.read();     // COMPILE ERROR: File<Closed> has no read()
    // f.write("");  // COMPILE ERROR: File<Closed> has no write()

    auto opened = std::move(f).open();  // Closed -> Open
    // f is now moved-from — can't use it

    opened.read();                       // OK: File<Open> has read()
    opened.write("hello");               // OK: File<Open> has write()

    auto closed = std::move(opened).close();  // Open -> Closed
    // opened is now moved-from
    // opened.read();  // Would use moved-from object — path_ is empty

    // Can reopen:
    auto reopened = std::move(closed).open();
    reopened.read();
    // Auto-closed by destructor when reopened goes out of scope
}
```

This pattern provides:
1. **Compile-time prevention** of reading a closed file or opening an already-open file
2. **Explicit state transitions** via `std::move(obj).method()` — consumes the old state
3. **RAII fallback** — destructor handles cleanup if close() is forgotten
4. **Zero runtime cost** — all checking happens at compile time via the type system

The `&&` qualifier on `open()` and `close()` means these can only be called on rvalues — you must `std::move()` the object, making it clear that the old state is consumed. This is the closest C++ gets to Rust's ownership-based state machines.

Small buffer optimization stores small objects inline (on the stack) and only heap-allocates for large objects. This is how `std::string` (SSO) and `std::function` work.

```cpp
#include <cstddef>
#include <cstring>
#include <algorithm>
#include <utility>
#include <iostream>

class SBOString {
    static constexpr std::size_t SBO_SIZE = 24;  // Inline buffer size

    union {
        char local_[SBO_SIZE];     // Small string: stored inline
        struct {
            char* ptr;
            std::size_t capacity;
        } heap_;                   // Large string: heap-allocated
    };
    std::size_t size_ = 0;
    bool on_heap_ = false;

    char* data() noexcept {
        return on_heap_ ? heap_.ptr : local_;
    }
    const char* data() const noexcept {
        return on_heap_ ? heap_.ptr : local_;
    }

public:
    SBOString() { local_[0] = '\0'; }

    SBOString(const char* s) {
        size_ = std::strlen(s);
        if (size_ < SBO_SIZE) {
            std::memcpy(local_, s, size_ + 1);
            on_heap_ = false;
        } else {
            heap_.capacity = size_ + 1;
            heap_.ptr = new char[heap_.capacity];
            std::memcpy(heap_.ptr, s, size_ + 1);
            on_heap_ = true;
        }
    }

    ~SBOString() {
        if (on_heap_) delete[] heap_.ptr;
    }

    // Copy constructor
    SBOString(const SBOString& other) : size_(other.size_), on_heap_(other.on_heap_) {
        if (on_heap_) {
            heap_.capacity = other.heap_.capacity;
            heap_.ptr = new char[heap_.capacity];
            std::memcpy(heap_.ptr, other.heap_.ptr, size_ + 1);
        } else {
            std::memcpy(local_, other.local_, size_ + 1);
        }
    }

    // Move constructor: O(1) for heap, memcpy for local
    SBOString(SBOString&& other) noexcept
        : size_(other.size_), on_heap_(other.on_heap_) {
        if (on_heap_) {
            // Steal heap pointer — O(1)
            heap_.ptr = other.heap_.ptr;
            heap_.capacity = other.heap_.capacity;
            other.heap_.ptr = nullptr;
        } else {
            // Can't "steal" stack memory — must copy
            std::memcpy(local_, other.local_, size_ + 1);
        }
        other.size_ = 0;
        other.on_heap_ = false;
        other.local_[0] = '\0';
    }

    // Copy-and-swap assignment
    SBOString& operator=(SBOString other) noexcept {
        swap(*this, other);
        return *this;
    }

    friend void swap(SBOString& a, SBOString& b) noexcept {
        // For SBO types, swap is more complex:
        // Can't just swap pointers if either is using local storage
        SBOString tmp(std::move(a));
        new (&a) SBOString(std::move(b));
        new (&b) SBOString(std::move(tmp));
    }

    const char* c_str() const noexcept { return data(); }
    std::size_t size() const noexcept { return size_; }
    bool is_small() const noexcept { return !on_heap_; }
};

int main() {
    SBOString small("hi");      // Uses local buffer (3 bytes)
    SBOString large("this is a much longer string that exceeds SBO");

    std::cout << "small on heap: " << !small.is_small() << "\n";  // 0
    std::cout << "large on heap: " << !large.is_small() << "\n";  // 1

    SBOString moved_large = std::move(large);  // O(1) pointer steal
    SBOString moved_small = std::move(small);  // memcpy of 24 bytes

    std::cout << moved_large.c_str() << "\n";
    std::cout << moved_small.c_str() << "\n";
}
```

SBO move semantics:
- **Heap path**: O(1) — steal the pointer, null out the source
- **Local path**: O(n) — must copy bytes (can't transfer stack memory)
- **Swap**: Can't just swap pointers — need move-construct through temporary
- **noexcept**: Both paths are noexcept (memcpy and pointer assignment can't throw)

This is why `std::string::move` is technically O(n) for small strings, though n ≤ ~22 bytes so it's effectively instant.

**Slicing** happens when you copy a derived object into a base variable — the derived part is "sliced off" and lost.

```cpp
#include <memory>
#include <iostream>
#include <vector>

// THE PROBLEM: slicing
class Animal {
public:
    virtual std::string speak() const { return "..."; }
    virtual ~Animal() = default;
};

class Dog : public Animal {
    std::string name_;
public:
    Dog(std::string name) : name_(std::move(name)) {}
    std::string speak() const override {
        return name_ + " says woof!";
    }
};

void slicing_demo() {
    Dog rex("Rex");
    Animal a = rex;        // SLICED! Dog part is gone
    std::cout << a.speak() << "\n";  // "..." — not "Rex says woof!"

    // Even worse in containers:
    std::vector<Animal> animals;
    animals.push_back(Dog("Buddy"));  // Sliced on insert!
}

// THE SOLUTION: clone pattern with unique_ptr
class Shape {
public:
    virtual ~Shape() = default;
    virtual std::unique_ptr<Shape> clone() const = 0;
    virtual double area() const = 0;
    virtual void print() const = 0;
};

class Circle : public Shape {
    double radius_;
public:
    explicit Circle(double r) : radius_(r) {}

    std::unique_ptr<Shape> clone() const override {
        return std::make_unique<Circle>(*this);  // Copy via copy-ctor
    }

    double area() const override { return 3.14159 * radius_ * radius_; }
    void print() const override {
        std::cout << "Circle(r=" << radius_ << ")\n";
    }
};

class Rectangle : public Shape {
    double w_, h_;
public:
    Rectangle(double w, double h) : w_(w), h_(h) {}

    std::unique_ptr<Shape> clone() const override {
        return std::make_unique<Rectangle>(*this);
    }

    double area() const override { return w_ * h_; }
    void print() const override {
        std::cout << "Rect(" << w_ << "x" << h_ << ")\n";
    }
};

// Container that deep-copies polymorphic objects
class Canvas {
    std::vector<std::unique_ptr<Shape>> shapes_;

public:
    void add(std::unique_ptr<Shape> s) {
        shapes_.push_back(std::move(s));
    }

    // Deep copy: clone each shape
    Canvas(const Canvas& other) {
        shapes_.reserve(other.shapes_.size());
        for (const auto& s : other.shapes_)
            shapes_.push_back(s->clone());
    }

    Canvas& operator=(const Canvas& other) {
        Canvas tmp(other);  // Copy-and-swap
        shapes_ = std::move(tmp.shapes_);
        return *this;
    }

    Canvas(Canvas&&) = default;
    Canvas& operator=(Canvas&&) = default;

    void draw_all() const {
        for (const auto& s : shapes_)
            s->print();
    }
};

int main() {
    Canvas c1;
    c1.add(std::make_unique<Circle>(5.0));
    c1.add(std::make_unique<Rectangle>(3.0, 4.0));

    Canvas c2 = c1;  // Deep copy — each shape is cloned
    c2.draw_all();   // Circle(r=5), Rect(3x4) — no slicing!
}
```

**CRTP helper to reduce boilerplate:**
```cpp
template <typename Derived, typename Base>
class Clonable : public Base {
public:
    using Base::Base;
    std::unique_ptr<Shape> clone() const override {
        return std::make_unique<Derived>(static_cast<const Derived&>(*this));
    }
};

// Now derived classes don't need to implement clone:
class Triangle : public Clonable<Triangle, Shape> {
    double base_, height_;
public:
    Triangle(double b, double h) : base_(b), height_(h) {}
    double area() const override { return 0.5 * base_ * height_; }
    void print() const override {
        std::cout << "Triangle(" << base_ << "," << height_ << ")\n";
    }
    // clone() is auto-generated by CRTP!
};
```

**Prevention rules:**
1. Store polymorphic objects by `unique_ptr<Base>` — never by value
2. Implement `clone()` for deep copies
3. Consider deleting copy constructor on base class to make slicing a compile error
4. Use CRTP to eliminate clone boilerplate in every derived class
